import { useState, useRef, useCallback, useEffect } from 'react';
import { Paperclip, X, Mic } from 'lucide-react';
import { Icon } from '@iconify/react';
import { Sheet, SheetContent } from '@/components/ui/sheet';
import GiphyPicker from '@/components/create/GiphyPicker';
import { ChatMediaPicker } from './ChatMediaPicker';
import { VoiceRecorderBar } from './VoiceRecorderBar';
import { useVoiceRecorder } from '@/hooks/useVoiceRecorder';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';
import { uploadMedia, uploadToR2 } from '@/lib/r2Upload';
import { MediaUploadProgress } from './MediaUploadProgress';

interface MediaFile {
  file: File;
  preview: string;
  type: 'image' | 'video';
  progress?: number;
}

interface ChatInputProps {
  conversationId: string | null;
  onSendMessage: (
    content: string,
    mediaUrl?: string,
    mediaType?: string,
    waveformData?: number[],
  ) => Promise<void>;
  onTyping: (isTyping: boolean) => void;
}

type RecorderUIState = 'idle' | 'recording' | 'locked' | 'uploading';

export const ChatInput = ({ conversationId, onSendMessage, onTyping }: ChatInputProps) => {
  const { user } = useAuth();
  const [inputValue, setInputValue]       = useState('');
  const [selectedMedia, setSelectedMedia] = useState<MediaFile[]>([]);
  const [isUploading, setIsUploading]     = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);
  const [showGIFPicker, setShowGIFPicker]     = useState(false);
  const [showMediaPicker, setShowMediaPicker] = useState(false);

  const {
    isRecording,
    duration,
    audioBlob,
    waveformData,
    recordedWaveformSnapshot,
    startRecording,
    stopRecording,
    cancelRecording,
    clearAudio,
    formatDuration,
    getDurationMs,
  } = useVoiceRecorder();

  const [recorderState, setRecorderState] = useState<RecorderUIState>('idle');
  const [voiceUploadProgress, setVoiceUploadProgress] = useState<number | undefined>();

  const [dragDelta, setDragDelta] = useState({ x: 0, y: 0 });

  const gestureState = useRef({
    isHolding: false,
    recordingStarted: false,
    locked: false,
    touchStart: null as { x: number; y: number } | null,
    isRecording: false,
  });

  const holdTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    gestureState.current.isRecording = isRecording;
  }, [isRecording]);

  const uploadFile = async (file: File, index: number): Promise<string | null> => {
    if (!user?.id) return null;
    try {
      return await uploadMedia(file, 'messages', user.id, (progress) => {
        setSelectedMedia(prev => {
          const next = [...prev];
          if (next[index]) next[index] = { ...next[index], progress };
          return next;
        });
      });
    } catch {
      toast.error('Fayl yuklashda xatolik');
      return null;
    }
  };

  const handleSend = async (directMedia?: MediaFile[], directCaption?: string) => {
    if (!conversationId) return;
    setIsUploading(true);
    try {
      const mediaList = directMedia || selectedMedia;
      const textVal   = directCaption !== undefined ? directCaption : inputValue;

      if (mediaList.length > 0) {
        for (let i = 0; i < mediaList.length; i++) {
          const media    = mediaList[i];
          const mediaUrl = await uploadFile(media.file, i);
          if (mediaUrl) {
            await onSendMessage(i === 0 ? textVal.trim() : '', mediaUrl, media.type);
            URL.revokeObjectURL(media.preview);
          }
        }
        setSelectedMedia([]);
      } else if (textVal.trim()) {
        await onSendMessage(textVal.trim());
      }
      setInputValue('');
      onTyping(false);
    } catch {
      toast.error('Xabar yuborishda xatolik');
    } finally {
      setIsUploading(false);
    }
  };

  const handleUploadAndSendAudio = useCallback(async (blob: Blob, snapshot: number[]) => {
    if (!blob || blob.size === 0 || !conversationId) {
      toast.error("Ovozli xabar bo'sh");
      setRecorderState('idle');
      return;
    }
    setRecorderState('uploading');
    setIsUploading(true);
    setVoiceUploadProgress(0);
    try {
      const audioFile = new File([blob], `voice_${Date.now()}.webm`, { type: 'audio/webm' });
      const mediaUrl  = await uploadToR2(
        audioFile,
        `messages/${user?.id}`,
        undefined,
        (p) => setVoiceUploadProgress(p),
      );
      if (mediaUrl) {
        await onSendMessage('≡ƒÄñ Ovozli xabar', mediaUrl, 'audio', snapshot);
      }
      clearAudio();
    } catch {
      toast.error('Ovozli xabar yuborishda xatolik');
    } finally {
      setIsUploading(false);
      setVoiceUploadProgress(undefined);
      setRecorderState('idle');
    }
  }, [conversationId, user?.id, onSendMessage, clearAudio]);

  const handleCancelVoice = useCallback(() => {
    cancelRecording();
    gestureState.current.locked = false;
    setDragDelta({ x: 0, y: 0 });
    setRecorderState('idle');
  }, [cancelRecording]);

  const handleLock = useCallback(() => {
    if (gestureState.current.locked) return;
    gestureState.current.locked = true;
    setDragDelta({ x: 0, y: 0 });
    setRecorderState('locked');
  }, []);

  const handleMicPointerDown = useCallback((e: React.PointerEvent) => {
    if (recorderState !== 'idle') return;

    e.currentTarget.setPointerCapture(e.pointerId);

    gestureState.current.isHolding = true;
    gestureState.current.recordingStarted = false;
    gestureState.current.locked = false;
    gestureState.current.touchStart = { x: e.clientX, y: e.clientY };
    setDragDelta({ x: 0, y: 0 });

    holdTimerRef.current = setTimeout(async () => {
      if (gestureState.current.isHolding) {
        gestureState.current.recordingStarted = true;
        setRecorderState('recording');

        await startRecording();

        if (!gestureState.current.isHolding && !gestureState.current.locked) {
          cancelRecording();
          setRecorderState('idle');
        }
      }
    }, 150);
  }, [recorderState, startRecording, cancelRecording]);

  const handleMicPointerMove = useCallback((e: React.PointerEvent) => {
    if (!gestureState.current.isHolding || !gestureState.current.touchStart) return;
    if (gestureState.current.locked) return;

    const deltaX = gestureState.current.touchStart.x - e.clientX;
    const deltaY = gestureState.current.touchStart.y - e.clientY;

    setDragDelta({ x: Math.max(0, deltaX), y: Math.max(0, deltaY) });

    if (deltaX > 80) {
      handleCancelVoice();
      gestureState.current.isHolding = false;
      gestureState.current.recordingStarted = false;
      gestureState.current.touchStart = null;
    } else if (deltaY > 60) {
      handleLock();
    }
  }, [handleCancelVoice, handleLock]);

  const handleMicPointerUp = useCallback(async (e: React.PointerEvent) => {
    if (holdTimerRef.current) {
      clearTimeout(holdTimerRef.current);
      holdTimerRef.current = null;
    }

    try { e.currentTarget.releasePointerCapture(e.pointerId); } catch {}

    const wasRecordingStarted = gestureState.current.recordingStarted;
    const isLocked = gestureState.current.locked;

    gestureState.current.isHolding = false;
    setDragDelta({ x: 0, y: 0 });

    if (!wasRecordingStarted) {
      cancelRecording();
      setRecorderState('idle');
      return;
    }

    if (isLocked) return;

    if (gestureState.current.isRecording) {
      if (getDurationMs() < 300) {
        toast.error('Ovozli xabar juda qisqa');
        handleCancelVoice();
      } else {
        const result = await stopRecording();
        await handleUploadAndSendAudio(result.blob, result.snapshot);
      }
    } else {
      handleCancelVoice();
    }
  }, [cancelRecording, stopRecording, handleUploadAndSendAudio, handleCancelVoice, getDurationMs]);

  const handleMicPointerCancel = useCallback((e: React.PointerEvent) => {
    if (holdTimerRef.current) {
      clearTimeout(holdTimerRef.current);
      holdTimerRef.current = null;
    }

    try { e.currentTarget.releasePointerCapture(e.pointerId); } catch {}

    if (gestureState.current.recordingStarted && !gestureState.current.locked) {
      handleCancelVoice();
    }
    gestureState.current.isHolding = false;
    gestureState.current.recordingStarted = false;
    gestureState.current.touchStart = null;
    setDragDelta({ x: 0, y: 0 });
  }, [handleCancelVoice]);

  const handleStopLocked = useCallback(async () => {
    if (getDurationMs() < 300) {
      toast.error('Ovozli xabar juda qisqa');
      handleCancelVoice();
      return;
    }
    const result = await stopRecording();
    gestureState.current.locked = false;
    await handleUploadAndSendAudio(result.blob, result.snapshot);
  }, [getDurationMs, stopRecording, handleUploadAndSendAudio, handleCancelVoice]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setInputValue(e.target.value);
    onTyping(true);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); }
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (!files.length) return;
    const newItems: MediaFile[] = files.map(file => ({
      file,
      preview: URL.createObjectURL(file),
      type: file.type.startsWith('video/') ? 'video' : 'image',
    }));
    setSelectedMedia(prev => [...prev, ...newItems]);
    e.target.value = '';
  };

  const handleRemoveMedia = (index: number) => {
    const item = selectedMedia[index];
    if (item?.preview) URL.revokeObjectURL(item.preview);
    setSelectedMedia(prev => { const next = [...prev]; next.splice(index, 1); return next; });
  };

  const hasText  = inputValue.trim().length > 0;
  const hasMedia = selectedMedia.length > 0;
  const showSend = hasText || hasMedia;

  return (
    <div
      className="fixed bottom-0 left-0 right-0 z-50 bg-transparent border-none pointer-events-none"
      style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}
    >
      {selectedMedia.length > 0 && (
        <div className="mx-3 mt-1 mb-2 flex flex-wrap gap-2 pointer-events-auto">
          {selectedMedia.map((media, index) => (
            <div key={index} className="relative inline-block">
              <div className="relative w-16 h-16 rounded-xl overflow-hidden border border-border/30 bg-muted">
                {media.type === 'image'
                  ? <img src={media.preview} alt="" className="w-full h-full object-cover" />
                  : <video src={media.preview} className="w-full h-full object-cover" />
                }
                {media.progress !== undefined && media.progress < 100 && (
                  <div className="absolute inset-0 bg-black/40 flex items-center justify-center">
                    <MediaUploadProgress progress={media.progress} size={24} />
                  </div>
                )}
                <button
                  onClick={() => handleRemoveMedia(index)}
                  className="absolute -top-1.5 -right-1.5 w-5 h-5 bg-destructive text-destructive-foreground rounded-full flex items-center justify-center shadow-sm"
                >
                  <X className="h-3 w-3" />
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      <div className="relative pointer-events-auto mx-3 mb-3">
        {/* Input bar */}
        <div 
          className="flex items-center bg-background/90 dark:bg-zinc-900/90 backdrop-blur-xl border border-border/40 rounded-[28px] gap-2 px-3 py-2 shadow-lg shadow-black/5"
          style={{ opacity: recorderState !== 'idle' ? 0 : 1, transition: 'opacity 0.2s' }}
        >
          <button
            type="button"
            onClick={() => setShowMediaPicker(true)}
            className="w-9 h-9 rounded-full flex items-center justify-center hover:bg-muted/50 transition-colors shrink-0"
            style={{ visibility: recorderState !== 'idle' ? 'hidden' : 'visible' }}
          >
            <Paperclip className="h-5 w-5 text-muted-foreground" />
          </button>

          <button
            type="button"
            onClick={() => setShowGIFPicker(true)}
            className="w-9 h-9 rounded-full flex items-center justify-center hover:bg-violet-500/15 transition-all active:scale-90 shrink-0"
            aria-label="GIF qidirish"
            style={{ visibility: recorderState !== 'idle' ? 'hidden' : 'visible' }}
          >
            <Icon icon="mage:gif-fill" className="h-6 w-6 text-violet-500" />
          </button>

          <input
            ref={inputRef}
            value={inputValue}
            onChange={handleInputChange}
            onKeyDown={handleKeyDown}
            placeholder="Xabar yozing..."
            className="flex-1 bg-transparent text-sm text-foreground placeholder:text-muted-foreground outline-none w-full min-w-0"
            disabled={isUploading || recorderState !== 'idle'}
            style={{ visibility: recorderState !== 'idle' ? 'hidden' : 'visible' }}
          />

          {showSend ? (
            <button
              onClick={() => handleSend()}
              disabled={isUploading}
              className="w-9 h-9 rounded-full bg-green-500 flex items-center justify-center shadow-md hover:opacity-90 transition-all active:scale-90 disabled:opacity-50 shrink-0"
              style={{ visibility: recorderState !== 'idle' ? 'hidden' : 'visible' }}
            >
              <Icon icon="heroicons:paper-airplane-16-solid" className="h-5 w-5 text-white" />
            </button>
          ) : (
            <div
              onPointerDown={handleMicPointerDown}
              onPointerMove={handleMicPointerMove}
              onPointerUp={handleMicPointerUp}
              onPointerCancel={handleMicPointerCancel}
              className="w-9 h-9 rounded-full flex items-center justify-center transition-all cursor-pointer select-none touch-none shrink-0"
              style={{ touchAction: 'none' }}
            >
              {/* Keep mic icon visible even when opacity is 0 so pointer events trigger correctly if needed? Actually we don't care about visibility, opacity handles it */}
              <Mic className="h-5 w-5 text-muted-foreground" />
            </div>
          )}
        </div>

        {/* Recorder overlay */}
        {recorderState !== 'idle' && (
          <div className="absolute inset-0 z-10">
            <VoiceRecorderBar
              state={recorderState === 'locked' ? 'locked' : recorderState === 'uploading' ? 'uploading' : 'recording'}
              duration={duration}
              waveformData={waveformData}
              isUploading={isUploading}
              uploadProgress={voiceUploadProgress}
              formatDuration={formatDuration}
              dragDelta={dragDelta}
              onCancel={handleCancelVoice}
              onLock={handleLock}
              onStop={handleStopLocked}
              onMicPointerDown={() => {}}
              onMicPointerMove={() => {}}
              onMicPointerUp={() => {}}
              onMicPointerCancel={() => {}}
            />
          </div>
        )}
      </div>

      {showGIFPicker && (
        <div
          className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex flex-col justify-end pointer-events-auto"
          onClick={() => setShowGIFPicker(false)}
        >
          <div onClick={(e) => e.stopPropagation()} className="relative">
            <GiphyPicker
              onSelect={async (gif) => {
                const url = gif.originalUrl || gif.previewUrl;
                if (!isUploading && url) {
                  setIsUploading(true);
                  try { await onSendMessage('', url, 'image'); }
                  catch { toast.error('Xatolik yuz berdi'); }
                  finally { setIsUploading(false); setShowGIFPicker(false); }
                }
              }}
              onClose={() => setShowGIFPicker(false)}
            />
          </div>
        </div>
      )}

      <Sheet open={showMediaPicker} onOpenChange={setShowMediaPicker}>
        <SheetContent side="bottom" className="p-0 h-[88vh] border-none bg-transparent">
          <ChatMediaPicker
            onSend={(media, caption) => { setShowMediaPicker(false); handleSend(media, caption); }}
            onClose={() => setShowMediaPicker(false)}
          />
        </SheetContent>
      </Sheet>
    </div>
  );
};

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { ScrollArea } from '@/components/ui/scroll-area';
import { toast } from 'sonner';
import { Search, Users, Megaphone, Check } from 'lucide-react';

interface ForwardTarget {
  id: string;
  name: string;
  avatar_url: string | null;
  type: 'user' | 'group' | 'channel';
}

interface ForwardMessageDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  messageContent: string;
  mediaUrl?: string | null;
  mediaType?: string | null;
}

export const ForwardMessageDialog = ({
  open,
  onOpenChange,
  messageContent,
  mediaUrl,
  mediaType,
}: ForwardMessageDialogProps) => {
  const { user } = useAuth();
  const [searchQuery, setSearchQuery] = useState('');
  const [targets, setTargets] = useState<ForwardTarget[]>([]);
  const [selectedTargets, setSelectedTargets] = useState<string[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSending, setIsSending] = useState(false);

  useEffect(() => {
    if (open) {
      fetchTargets();
    }
  }, [open]);

  const fetchTargets = async () => {
    if (!user?.id) return;
    setIsLoading(true);

    try {
      // Fetch conversations (users)
      const { data: conversations } = await supabase
        .from('conversations')
        .select('*')
        .or(`participant1_id.eq.${user.id},participant2_id.eq.${user.id}`);

      const userIds = new Set<string>();
      conversations?.forEach(conv => {
        if (conv.participant1_id !== user.id) userIds.add(conv.participant1_id);
        if (conv.participant2_id !== user.id) userIds.add(conv.participant2_id);
      });

      const { data: profiles } = await supabase
        .from('profiles')
        .select('id, name, avatar_url')
        .in('id', Array.from(userIds));

      // Fetch groups/channels
      const { data: ownedChats } = await supabase
        .from('group_chats')
        .select('id, name, avatar_url, type')
        .eq('owner_id', user.id);

      const { data: memberOf } = await supabase
        .from('group_members')
        .select('group_id')
        .eq('user_id', user.id);

      const memberGroupIds = memberOf?.map(m => m.group_id) || [];
      let memberChats: any[] = [];
      if (memberGroupIds.length > 0) {
        const { data } = await supabase
          .from('group_chats')
          .select('id, name, avatar_url, type')
          .in('id', memberGroupIds);
        memberChats = data || [];
      }

      const allTargets: ForwardTarget[] = [];

      // Add users
      profiles?.forEach(profile => {
        allTargets.push({
          id: profile.id,
          name: profile.name || 'Foydalanuvchi',
          avatar_url: profile.avatar_url,
          type: 'user'
        });
      });

      // Add groups/channels
      [...(ownedChats || []), ...memberChats].forEach(chat => {
        if (!allTargets.find(t => t.id === chat.id)) {
          allTargets.push({
            id: chat.id,
            name: chat.name,
            avatar_url: chat.avatar_url,
            type: chat.type as 'group' | 'channel'
          });
        }
      });

      setTargets(allTargets);
    } catch (error) {
      console.error('Error fetching targets:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const toggleTarget = (targetId: string) => {
    setSelectedTargets(prev => 
      prev.includes(targetId)
        ? prev.filter(id => id !== targetId)
        : [...prev, targetId]
    );
  };

  const handleForward = async () => {
    if (selectedTargets.length === 0) {
      toast.error('Kimgadir tanlang');
      return;
    }

    setIsSending(true);

    try {
      for (const targetId of selectedTargets) {
        const target = targets.find(t => t.id === targetId);
        if (!target) continue;

        if (target.type === 'user') {
          // Get or create conversation
          const { data: existingConv } = await supabase
            .from('conversations')
            .select('id')
            .or(`and(participant1_id.eq.${user?.id},participant2_id.eq.${targetId}),and(participant1_id.eq.${targetId},participant2_id.eq.${user?.id})`)
            .maybeSingle();

          let conversationId = existingConv?.id;

          if (!conversationId) {
            const { data: newConv } = await supabase
              .from('conversations')
              .insert({
                participant1_id: user?.id,
                participant2_id: targetId
              })
              .select('id')
              .single();
            conversationId = newConv?.id;
          }

          if (conversationId) {
            await supabase
              .from('messages')
              .insert({
                conversation_id: conversationId,
                sender_id: user?.id,
                content: `Γå¬∩╕Å Yo'naltirilgan: ${messageContent}`,
                media_url: mediaUrl,
                media_type: mediaType,
                status: 'sent'
              });
          }
        } else {
          // Forward to group/channel
          await supabase
            .from('group_messages')
            .insert({
              group_id: targetId,
              sender_id: user?.id,
              content: `Γå¬∩╕Å Yo'naltirilgan: ${messageContent}`,
              media_url: mediaUrl,
              media_type: mediaType
            });
        }
      }

      toast.success('Xabar yo\'naltirildi');
      onOpenChange(false);
      setSelectedTargets([]);
    } catch (error) {
      console.error('Error forwarding message:', error);
      toast.error('Xatolik yuz berdi');
    } finally {
      setIsSending(false);
    }
  };

  const getInitials = (name: string) => {
    return name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);
  };

  const filteredTargets = targets.filter(target =>
    target.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle>Xabarni yo'naltirish</DialogTitle>
        </DialogHeader>

        <div className="relative mb-4">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Qidirish..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="pl-10"
          />
        </div>

        <ScrollArea className="h-[300px]">
          {isLoading ? (
            <p className="text-center text-muted-foreground py-8">Yuklanmoqda...</p>
          ) : filteredTargets.length === 0 ? (
            <p className="text-center text-muted-foreground py-8">Topilmadi</p>
          ) : (
            <div className="space-y-1">
              {filteredTargets.map((target) => (
                <div
                  key={target.id}
                  className={`flex items-center gap-3 p-3 rounded-lg cursor-pointer transition-colors ${
                    selectedTargets.includes(target.id)
                      ? 'bg-primary/10'
                      : 'hover:bg-muted'
                  }`}
                  onClick={() => toggleTarget(target.id)}
                >
                  <Avatar className="h-10 w-10">
                    <AvatarImage src={target.avatar_url || undefined} />
                    <AvatarFallback className="bg-primary/10">
                      {target.type === 'group' ? (
                        <Users className="h-5 w-5 text-primary" />
                      ) : target.type === 'channel' ? (
                        <Megaphone className="h-5 w-5 text-primary" />
                      ) : (
                        getInitials(target.name)
                      )}
                    </AvatarFallback>
                  </Avatar>
                  <div className="flex-1 min-w-0">
                    <p className="font-medium truncate">{target.name}</p>
                    <p className="text-xs text-muted-foreground">
                      {target.type === 'group' ? 'Guruh' : target.type === 'channel' ? 'Kanal' : 'Foydalanuvchi'}
                    </p>
                  </div>
                  {selectedTargets.includes(target.id) && (
                    <Check className="h-5 w-5 text-primary" />
                  )}
                </div>
              ))}
            </div>
          )}
        </ScrollArea>

        <div className="flex justify-end gap-2 mt-4">
          <Button variant="outline" onClick={() => onOpenChange(false)}>
            Bekor qilish
          </Button>
          <Button 
            onClick={handleForward} 
            disabled={selectedTargets.length === 0 || isSending}
          >
            {isSending ? 'Yuborilmoqda...' : `Yuborish (${selectedTargets.length})`}
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
};

import { useEffect, useRef, useState, useCallback } from 'react';
import { Button } from '@/components/ui/button';
import { Video, VideoOff, Mic, MicOff, PhoneOff, Maximize2, Minimize2, SwitchCamera } from 'lucide-react';
import { DailyCall, DailyParticipant } from '@daily-co/daily-js';
import { cn } from '@/lib/utils';
import { toast } from 'sonner';

type LayoutMode = 'pip' | 'split';

interface VideoCallUIProps {
  callObject: DailyCall;
  remoteParticipant: DailyParticipant | null;
  cameraOn: boolean;
  micOn: boolean;
  onToggleCamera: () => void;
  onToggleMic: () => void;
  onEndCall: () => void;
}

export const VideoCallUI = ({
  callObject,
  remoteParticipant,
  cameraOn,
  micOn,
  onToggleCamera,
  onToggleMic,
  onEndCall,
}: VideoCallUIProps) => {
  const localVideoRef = useRef<HTMLVideoElement>(null);
  const remoteVideoRef = useRef<HTMLVideoElement>(null);
  
  const [layoutMode, setLayoutMode] = useState<LayoutMode>('pip');
  const [showControls, setShowControls] = useState(true);
  const hideTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  
  // PiP drag state
  const [pipPosition, setPipPosition] = useState({ x: 16, y: 16 });
  const [pipSize, setPipSize] = useState({ w: 120, h: 170 });
  const [isDragging, setIsDragging] = useState(false);
  const dragStartRef = useRef({ x: 0, y: 0, px: 0, py: 0 });
  
  // Swapped: false = local in PiP (small), remote fullscreen; true = remote in PiP, local fullscreen
  const [swapped, setSwapped] = useState(false);

  // Auto-hide controls
  const resetHideTimer = useCallback(() => {
    setShowControls(true);
    if (hideTimerRef.current) clearTimeout(hideTimerRef.current);
    hideTimerRef.current = setTimeout(() => setShowControls(false), 3000);
  }, []);

  useEffect(() => {
    resetHideTimer();
    return () => { if (hideTimerRef.current) clearTimeout(hideTimerRef.current); };
  }, [resetHideTimer]);

  // Attach local video track
  useEffect(() => {
    if (!callObject) return;

    const attachLocal = () => {
      const lp = callObject.participants()?.local;
      if (lp?.videoTrack && localVideoRef.current) {
        const stream = new MediaStream([lp.videoTrack]);
        if (localVideoRef.current.srcObject !== stream) {
          localVideoRef.current.srcObject = stream;
        }
      } else if (localVideoRef.current && !lp?.video) {
        localVideoRef.current.srcObject = null;
      }
    };

    attachLocal();
    
    const handler = (evt: unknown) => {
      const p = (evt as { participant?: { local?: boolean } } | null)?.participant;
      if (p?.local) attachLocal();
    };
    
    callObject.on('participant-updated', handler);
    return () => { callObject.off('participant-updated', handler); };
  }, [callObject, layoutMode, swapped]);

  // Attach remote video + audio tracks
  useEffect(() => {
    if (remoteParticipant?.videoTrack && remoteVideoRef.current) {
      remoteVideoRef.current.srcObject = new MediaStream([remoteParticipant.videoTrack]);
    } else if (remoteVideoRef.current && !remoteParticipant?.video) {
      remoteVideoRef.current.srcObject = null;
    }
    
    if (remoteParticipant?.audioTrack) {
      let audioEl = document.getElementById('remote-audio') as HTMLAudioElement;
      if (!audioEl) {
        audioEl = document.createElement('audio');
        audioEl.id = 'remote-audio';
        audioEl.autoplay = true;
        document.body.appendChild(audioEl);
      }
      audioEl.srcObject = new MediaStream([remoteParticipant.audioTrack]);
    }

    return () => {
      const el = document.getElementById('remote-audio');
      if (el) el.remove();
    };
  }, [remoteParticipant?.videoTrack, remoteParticipant?.audioTrack, layoutMode, swapped]);

  // PiP Drag
  const handlePipPointerDown = (e: React.PointerEvent) => {
    if (layoutMode !== 'pip') return;
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(true);
    dragStartRef.current = { x: e.clientX, y: e.clientY, px: pipPosition.x, py: pipPosition.y };
    (e.target as HTMLElement).setPointerCapture(e.pointerId);
  };

  const handlePipPointerMove = (e: React.PointerEvent) => {
    if (!isDragging) return;
    const dx = e.clientX - dragStartRef.current.x;
    const dy = e.clientY - dragStartRef.current.y;
    const maxX = window.innerWidth - pipSize.w - 8;
    const maxY = window.innerHeight - pipSize.h - 8;
    setPipPosition({
      x: Math.max(8, Math.min(maxX, dragStartRef.current.px + dx)),
      y: Math.max(8, Math.min(maxY, dragStartRef.current.py + dy)),
    });
  };

  const handlePipPointerUp = () => setIsDragging(false);

  const handleFlipCamera = useCallback(async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!callObject) return;
    try {
      // Use Daily.co's built-in cycleCamera() which is more reliable for front/back switching
      await callObject.cycleCamera();
    } catch (err) {
      console.error('Camera flip error:', err);
      toast.error("Kamerani almashtirishda xatolik");
    }
  }, [callObject]);

  // Who is fullscreen vs PiP
  const fullscreenIsRemote = !swapped;
  const fullscreenHasVideo = fullscreenIsRemote ? !!remoteParticipant?.video : cameraOn;
  const pipHasVideo = fullscreenIsRemote ? cameraOn : !!remoteParticipant?.video;

  const renderVideoElement = (
    isLocal: boolean,
    hasVideo: boolean,
    className: string,
    label?: string
  ) => {
    const ref = isLocal ? localVideoRef : remoteVideoRef;
    return (
      <div className={cn("bg-muted flex items-center justify-center overflow-hidden", className)}>
        {hasVideo ? (
          <video
            ref={ref}
            autoPlay
            playsInline
            muted={isLocal}
            className={cn("w-full h-full object-cover", isLocal && "scale-x-[-1]")}
          />
        ) : (
          <div className="text-center text-muted-foreground">
            <div className="w-16 h-16 bg-muted-foreground/20 rounded-full flex items-center justify-center mx-auto mb-2">
              <VideoOff className="h-8 w-8" />
            </div>
            {label && <p className="text-xs">{label}</p>}
          </div>
        )}
      </div>
    );
  };

  return (
    <div 
      className="fixed inset-0 z-50 bg-background" 
      onClick={resetHideTimer}
      onTouchStart={resetHideTimer}
    >
      {layoutMode === 'split' ? (
        <div className="flex flex-col h-full">
          {renderVideoElement(!fullscreenIsRemote, fullscreenIsRemote ? !!remoteParticipant?.video : cameraOn, "flex-1", fullscreenIsRemote ? "Kutilmoqda..." : undefined)}
          <div className="h-px bg-border" />
          {renderVideoElement(fullscreenIsRemote, fullscreenIsRemote ? cameraOn : !!remoteParticipant?.video, "flex-1", !fullscreenIsRemote ? "Kutilmoqda..." : undefined)}
        </div>
      ) : (
        <>
          {/* Fullscreen */}
          {renderVideoElement(!fullscreenIsRemote, fullscreenHasVideo, "absolute inset-0", fullscreenIsRemote ? "Kutilmoqda..." : undefined)}

          {/* PiP Window */}
          <div
            className="absolute rounded-2xl overflow-hidden shadow-2xl border-2 border-background/50 cursor-grab active:cursor-grabbing touch-none"
            style={{
              left: pipPosition.x,
              top: pipPosition.y,
              width: pipSize.w,
              height: pipSize.h,
              zIndex: 10,
            }}
            onPointerDown={handlePipPointerDown}
            onPointerMove={handlePipPointerMove}
            onPointerUp={handlePipPointerUp}
          >
            {renderVideoElement(fullscreenIsRemote, pipHasVideo, "w-full h-full")}
          </div>
        </>
      )}

      {/* Controls */}
      <div 
        className={cn(
          "absolute bottom-0 left-0 right-0 transition-all duration-300",
          showControls ? "opacity-100 translate-y-0" : "opacity-0 translate-y-4 pointer-events-none"
        )}
      >
        <div className="bg-gradient-to-t from-black/60 to-transparent pt-16 pb-8 px-4">
          <div className="flex items-center justify-center gap-3">
            <Button
              variant="ghost"
              size="icon"
              className={cn(
                "h-12 w-12 rounded-full backdrop-blur-md",
                cameraOn ? "bg-white/20 text-white" : "bg-red-500/80 text-white"
              )}
              onClick={(e) => { e.stopPropagation(); onToggleCamera(); }}
            >
              {cameraOn ? <Video className="h-5 w-5" /> : <VideoOff className="h-5 w-5" />}
            </Button>

            <Button
              variant="ghost"
              size="icon"
              className={cn(
                "h-12 w-12 rounded-full backdrop-blur-md",
                micOn ? "bg-white/20 text-white" : "bg-red-500/80 text-white"
              )}
              onClick={(e) => { e.stopPropagation(); onToggleMic(); }}
            >
              {micOn ? <Mic className="h-5 w-5" /> : <MicOff className="h-5 w-5" />}
            </Button>

            <Button
              variant="ghost"
              size="icon"
              className="h-14 w-14 rounded-full bg-destructive text-destructive-foreground"
              onClick={(e) => { e.stopPropagation(); onEndCall(); }}
            >
              <PhoneOff className="h-6 w-6" />
            </Button>

            <Button
              variant="ghost"
              size="icon"
              className="h-12 w-12 rounded-full bg-white/20 text-white backdrop-blur-md"
              onClick={(e) => {
                e.stopPropagation();
                setLayoutMode(prev => prev === 'pip' ? 'split' : 'pip');
              }}
            >
              {layoutMode === 'pip' ? <Maximize2 className="h-5 w-5" /> : <Minimize2 className="h-5 w-5" />}
            </Button>

            <Button
              variant="ghost"
              size="icon"
              className="h-12 w-12 rounded-full bg-white/20 text-white backdrop-blur-md"
              onClick={handleFlipCamera}
            >
              <SwitchCamera className="h-5 w-5" />
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
};

import { useState, useRef, useEffect, useCallback } from 'react';
import { Button } from '@/components/ui/button';
import { Slider } from '@/components/ui/slider';
import { Check, RotateCcw, Sun, Contrast, Droplets, Palette } from 'lucide-react';
import { cn } from '@/lib/utils';

interface ImageEditorProps {
  src: string;
  onSave: (blob: Blob) => void;
  onCancel: () => void;
}

interface Filters {
  brightness: number;
  contrast: number;
  saturation: number;
}

const PRESETS: { name: string; filters: Filters }[] = [
  { name: 'Original', filters: { brightness: 100, contrast: 100, saturation: 100 } },
  { name: 'Vivid', filters: { brightness: 105, contrast: 115, saturation: 140 } },
  { name: 'Warm', filters: { brightness: 108, contrast: 105, saturation: 120 } },
  { name: 'Cool', filters: { brightness: 100, contrast: 110, saturation: 80 } },
  { name: 'B&W', filters: { brightness: 105, contrast: 120, saturation: 0 } },
  { name: 'Fade', filters: { brightness: 110, contrast: 85, saturation: 90 } },
];

const ImageEditor = ({ src, onSave, onCancel }: ImageEditorProps) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const imgRef = useRef<HTMLImageElement | null>(null);
  const [filters, setFilters] = useState<Filters>({ brightness: 100, contrast: 100, saturation: 100 });
  const [activePreset, setActivePreset] = useState(0);
  const [showSliders, setShowSliders] = useState(false);

  useEffect(() => {
    const img = new Image();
    img.crossOrigin = 'anonymous';
    img.onload = () => {
      imgRef.current = img;
      drawImage();
    };
    img.src = src;
  }, [src]);

  const drawImage = useCallback(() => {
    const canvas = canvasRef.current;
    const img = imgRef.current;
    if (!canvas || !img) return;

    const maxW = 1080;
    const maxH = 1080;
    let w = img.naturalWidth;
    let h = img.naturalHeight;
    if (w > maxW || h > maxH) {
      const ratio = Math.min(maxW / w, maxH / h);
      w = Math.round(w * ratio);
      h = Math.round(h * ratio);
    }
    canvas.width = w;
    canvas.height = h;

    const ctx = canvas.getContext('2d')!;
    ctx.filter = `brightness(${filters.brightness}%) contrast(${filters.contrast}%) saturate(${filters.saturation}%)`;
    ctx.drawImage(img, 0, 0, w, h);
  }, [filters]);

  useEffect(() => {
    drawImage();
  }, [drawImage]);

  const applyPreset = (idx: number) => {
    setActivePreset(idx);
    setFilters(PRESETS[idx].filters);
  };

  const resetFilters = () => {
    setFilters({ brightness: 100, contrast: 100, saturation: 100 });
    setActivePreset(0);
  };

  const handleSave = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    canvas.toBlob(
      (blob) => {
        if (blob) onSave(blob);
      },
      'image/webp',
      0.9
    );
  };

  const sliders = [
    { key: 'brightness' as const, icon: Sun, label: 'Yorqinlik' },
    { key: 'contrast' as const, icon: Contrast, label: 'Kontrast' },
    { key: 'saturation' as const, icon: Droplets, label: 'To\'yinganlik' },
  ];

  return (
    <div className="space-y-4">
      {/* Canvas preview */}
      <div className="relative rounded-xl overflow-hidden bg-muted flex items-center justify-center max-h-[50vh]">
        <canvas
          ref={canvasRef}
          className="max-w-full max-h-[50vh] object-contain"
        />
      </div>

      {/* Filter presets */}
      <div className="flex gap-2 overflow-x-auto pb-1 px-1">
        {PRESETS.map((preset, i) => (
          <button
            key={preset.name}
            onClick={() => applyPreset(i)}
            className={cn(
              'flex-shrink-0 text-center space-y-1',
              activePreset === i && 'ring-2 ring-primary rounded-xl'
            )}
          >
            <div className="w-16 h-16 rounded-lg overflow-hidden bg-muted">
              <img
                src={src}
                alt={preset.name}
                className="w-full h-full object-cover"
                style={{
                  filter: `brightness(${preset.filters.brightness}%) contrast(${preset.filters.contrast}%) saturate(${preset.filters.saturation}%)`,
                }}
              />
            </div>
            <p className="text-[10px] text-muted-foreground font-medium">{preset.name}</p>
          </button>
        ))}
      </div>

      {/* Toggle sliders */}
      <Button
        variant="ghost"
        size="sm"
        className="w-full gap-2"
        onClick={() => setShowSliders(!showSliders)}
      >
        <Palette className="h-4 w-4" />
        {showSliders ? 'Yashirish' : 'Qo\'lda sozlash'}
      </Button>

      {/* Manual sliders */}
      {showSliders && (
        <div className="space-y-3 p-3 rounded-xl border border-border bg-muted/30">
          {sliders.map(({ key, icon: Icon, label }) => (
            <div key={key} className="space-y-1">
              <div className="flex items-center justify-between text-xs">
                <span className="flex items-center gap-1.5 text-muted-foreground">
                  <Icon className="h-3.5 w-3.5" />
                  {label}
                </span>
                <span className="font-mono text-muted-foreground">{filters[key]}%</span>
              </div>
              <Slider
                min={0}
                max={200}
                step={1}
                value={[filters[key]]}
                onValueChange={([v]) => {
                  setFilters((f) => ({ ...f, [key]: v }));
                  setActivePreset(-1);
                }}
              />
            </div>
          ))}
          <Button variant="ghost" size="sm" className="w-full gap-1" onClick={resetFilters}>
            <RotateCcw className="h-3.5 w-3.5" />
            Asliga qaytarish
          </Button>
        </div>
      )}

      {/* Actions */}
      <div className="flex gap-3">
        <Button variant="outline" className="flex-1 rounded-xl" onClick={onCancel}>
          Bekor qilish
        </Button>
        <Button className="flex-1 rounded-xl" onClick={handleSave}>
          <Check className="h-4 w-4 mr-1" />
          Saqlash
        </Button>
      </div>
    </div>
  );
};

export default ImageEditor;

import { useState, useRef, useEffect, useCallback } from 'react';
import { X, SwitchCamera, ChevronRight, Image as ImageIcon, Video } from 'lucide-react';
import { cn } from '@/lib/utils';

export interface CapturedMedia {
  id: string;
  type: 'photo' | 'video';
  file: File;
  url: string;
  thumbnail?: string;
}

interface MediaCaptureProps {
  onNext: (media: CapturedMedia[]) => void;
  onClose: () => void;
}

export default function MediaCapture({ onNext, onClose }: MediaCaptureProps) {
  const [selectedMedia, setSelectedMedia] = useState<CapturedMedia[]>([]);
  const [isCapturing, setIsCapturing] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [zoom, setZoom] = useState(1);
  const [facingMode, setFacingMode] = useState<'environment' | 'user'>('environment');
  const [cameraReady, setCameraReady] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);
  const [dragStartY, setDragStartY] = useState<number | null>(null);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const recordedChunksRef = useRef<Blob[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const recordTimerRef = useRef<number>();
  const captureTimerRef = useRef<number>();
  const isTakingPhotoRef = useRef<boolean>(false);

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, [facingMode]);

  const startCamera = async () => {
    stopCamera();
    try {
      let stream: MediaStream | null = null;
      try {
        // Preferred: 1280x720 (720p HD) - Gold Standard for mobile WebRTC (picks primary sensor with focus)
        stream = await navigator.mediaDevices.getUserMedia({
          video: { 
            facingMode: { ideal: facingMode }, 
            width: { ideal: 1280 }, 
            height: { ideal: 720 } 
          },
          audio: true,
        });
      } catch (e1) {
        try {
          // Fallback: 1080p full resolution
          stream = await navigator.mediaDevices.getUserMedia({
            video: { facingMode: { ideal: facingMode }, width: { ideal: 1920 }, height: { ideal: 1080 } },
            audio: true,
          });
        } catch (e2) {
          try {
            // Fallback: raw ideal facingMode without resolution
            stream = await navigator.mediaDevices.getUserMedia({ 
              video: { facingMode: { ideal: facingMode } }, 
              audio: true 
            });
          } catch (e3) {
            try {
              // Fallback: legacy facingMode direct string
              stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode }, audio: true });
            } catch (e4) {
              try {
                // Fallback: generic camera with audio
                stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
              } catch (e5) {
                // Fallback: generic camera without audio
                stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: false });
              }
            }
          }
        }
      }

      if (videoRef.current && stream) {
        videoRef.current.srcObject = stream;
        streamRef.current = stream;
        setCameraReady(true);
      }
    } catch (err) {
      console.error('Camera error:', err);
    }
  };

  const stopCamera = () => {
    streamRef.current?.getTracks().forEach(t => t.stop());
    streamRef.current = null;
    if (videoRef.current) videoRef.current.srcObject = null;
    setCameraReady(false);
  };

  const takePhoto = useCallback(() => {
    if (!videoRef.current || !canvasRef.current || selectedMedia.length >= 5 || isTakingPhotoRef.current) return;
    isTakingPhotoRef.current = true;
    const video = videoRef.current;
    const canvas = canvasRef.current;
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d')!;
    if (zoom > 1) {
      const sw = video.videoWidth / zoom;
      const sh = video.videoHeight / zoom;
      const sx = (video.videoWidth - sw) / 2;
      const sy = (video.videoHeight - sh) / 2;
      ctx.drawImage(video, sx, sy, sw, sh, 0, 0, canvas.width, canvas.height);
    } else {
      ctx.drawImage(video, 0, 0);
    }
    canvas.toBlob((blob) => {
      if (!blob) return;
      const file = new File([blob], `photo-${Date.now()}.jpg`, { type: 'image/jpeg' });
      const url = URL.createObjectURL(blob);
      setSelectedMedia(prev => [...prev, { id: Date.now().toString(), type: 'photo', file, url }]);
      isTakingPhotoRef.current = false;
    }, 'image/jpeg', 0.92);
  }, [zoom, selectedMedia.length]);

  const startRecording = useCallback(() => {
    if (!streamRef.current || selectedMedia.length >= 5) return;
    recordedChunksRef.current = [];
    const mimeType = MediaRecorder.isTypeSupported('video/webm;codecs=vp9') ? 'video/webm;codecs=vp9' : 'video/webm';
    const recorder = new MediaRecorder(streamRef.current, { mimeType });
    recorder.ondataavailable = (e) => { if (e.data.size > 0) recordedChunksRef.current.push(e.data); };
    recorder.onstop = () => {
      const blob = new Blob(recordedChunksRef.current, { type: 'video/webm' });
      const file = new File([blob], `video-${Date.now()}.webm`, { type: 'video/webm' });
      const url = URL.createObjectURL(blob);
      const tempVideo = document.createElement('video');
      tempVideo.src = url;
      tempVideo.currentTime = 0.5;
      tempVideo.onloadeddata = () => {
        const c = document.createElement('canvas');
        c.width = tempVideo.videoWidth;
        c.height = tempVideo.videoHeight;
        c.getContext('2d')?.drawImage(tempVideo, 0, 0);
        const thumb = c.toDataURL('image/jpeg', 0.7);
        setSelectedMedia(prev => [...prev, { id: Date.now().toString(), type: 'video', file, url, thumbnail: thumb }]);
      };
    };
    recorder.start();
    mediaRecorderRef.current = recorder;
    setIsRecording(true);
    setRecordingTime(0);
    recordTimerRef.current = window.setInterval(() => setRecordingTime(t => t + 1), 1000);
  }, [selectedMedia.length]);

  const stopRecording = useCallback(() => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      clearInterval(recordTimerRef.current);
    }
  }, [isRecording]);

  const handleCaptureStart = useCallback(() => {
    setIsCapturing(true);
    captureTimerRef.current = window.setTimeout(() => startRecording(), 500);
  }, [startRecording]);

  const handleCaptureEnd = useCallback(() => {
    clearTimeout(captureTimerRef.current);
    if (isTakingPhotoRef.current) return;
    if (isRecording) stopRecording();
    else takePhoto();
    setIsCapturing(false);
  }, [isRecording, stopRecording, takePhoto]);

  const handleTouchStart = useCallback((e: React.TouchEvent) => {
    if (isRecording) setDragStartY(e.touches[0].clientY);
  }, [isRecording]);

  const handleTouchMove = useCallback((e: React.TouchEvent) => {
    if (isRecording && dragStartY !== null) {
      const delta = (dragStartY - e.touches[0].clientY) / 100;
      setZoom(z => Math.max(1, Math.min(5, z + delta)));
      setDragStartY(e.touches[0].clientY);
    }
  }, [isRecording, dragStartY]);

  const handleTouchEnd = useCallback(() => setDragStartY(null), []);

  const handleFileSelect = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;
    const remaining = 5 - selectedMedia.length;
    Array.from(files).slice(0, remaining).forEach((file, i) => {
      const isVideo = file.type.startsWith('video/');
      const url = URL.createObjectURL(file);
      setSelectedMedia(prev => [...prev, { id: `${Date.now()}-${i}`, type: isVideo ? 'video' : 'photo', file, url }]);
    });
    e.target.value = '';
  }, [selectedMedia.length]);

  const removeMedia = useCallback((id: string) => {
    setSelectedMedia(prev => {
      const item = prev.find(m => m.id === id);
      if (item) URL.revokeObjectURL(item.url);
      return prev.filter(m => m.id !== id);
    });
  }, []);

  const moveMedia = useCallback((from: number, to: number) => {
    setSelectedMedia(prev => {
      const arr = [...prev];
      const [item] = arr.splice(from, 1);
      arr.splice(to, 0, item);
      return arr;
    });
  }, []);

  const handleNext = useCallback(() => {
    if (selectedMedia.length === 0) return;
    onNext(selectedMedia);
  }, [selectedMedia, onNext]);

  const fmtTime = (s: number) => `${Math.floor(s / 60)}:${(s % 60).toString().padStart(2, '0')}`;

  return (
    <div className="fixed inset-0 z-[60] bg-black flex flex-col">
      {/* Camera view - takes remaining space */}
      <div className="relative flex-1 min-h-0">
        <video
          ref={videoRef}
          autoPlay
          playsInline
          muted
          className="absolute inset-0 w-full h-full object-cover"
          style={{ transform: `scale(${zoom})`, transformOrigin: 'center' }}
        />
        <canvas ref={canvasRef} className="hidden" />

        {/* Top bar - safe area */}
        <div className="absolute top-0 left-0 right-0 z-20 flex items-center justify-between p-3 pt-[max(0.75rem,env(safe-area-inset-top))]">
          <div className="flex items-center gap-2">
            <button
              onClick={onClose}
              className="w-9 h-9 rounded-full bg-black/50 backdrop-blur-md flex items-center justify-center active:scale-90 transition-transform"
            >
              <X className="w-4.5 h-4.5 text-white" />
            </button>
            <button
              onClick={() => setFacingMode(f => f === 'environment' ? 'user' : 'environment')}
              className="w-9 h-9 rounded-full bg-black/50 backdrop-blur-md flex items-center justify-center active:scale-90 transition-transform"
            >
              <SwitchCamera className="w-4.5 h-4.5 text-white" />
            </button>
          </div>

          {selectedMedia.length > 0 && (
            <button
              onClick={handleNext}
              className="px-5 py-2 rounded-full bg-primary text-primary-foreground text-sm font-semibold flex items-center gap-1 active:scale-95 transition-transform shadow-lg"
            >
              Keyingisi
              <ChevronRight className="w-4 h-4" />
            </button>
          )}
        </div>

        {/* Selected media strip - only here, no bottom duplicate */}
        {selectedMedia.length > 0 && (
          <div className="absolute top-14 left-2 right-2 z-20 mt-[env(safe-area-inset-top)]">
            <div
              className="flex gap-1.5 p-1.5 rounded-2xl bg-black/50 backdrop-blur-xl overflow-x-auto"
              style={{ scrollbarWidth: 'none' }}
            >
              {selectedMedia.map((item, idx) => (
                <div
                  key={item.id}
                  draggable
                  onDragStart={(e) => e.dataTransfer.setData('idx', idx.toString())}
                  onDragOver={(e) => e.preventDefault()}
                  onDrop={(e) => { e.preventDefault(); moveMedia(parseInt(e.dataTransfer.getData('idx')), idx); }}
                  className="relative flex-shrink-0"
                >
                  <div className="w-14 h-14 rounded-lg overflow-hidden border border-white/15">
                    {item.type === 'photo' ? (
                      <img src={item.url} alt="" className="w-full h-full object-cover" />
                    ) : (
                      <div className="relative w-full h-full">
                        <img src={item.thumbnail || item.url} alt="" className="w-full h-full object-cover" />
                        <Video className="absolute inset-0 m-auto w-4 h-4 text-white drop-shadow" />
                      </div>
                    )}
                  </div>
                  <button
                    onClick={() => removeMedia(item.id)}
                    className="absolute -top-1 -right-1 w-4.5 h-4.5 rounded-full bg-destructive flex items-center justify-center shadow"
                  >
                    <X className="w-2.5 h-2.5 text-destructive-foreground" />
                  </button>
                  <span className="absolute bottom-0.5 right-0.5 text-[8px] font-bold text-white bg-black/60 rounded-full w-3.5 h-3.5 flex items-center justify-center">{idx + 1}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Zoom indicator */}
        {zoom > 1 && (
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-10 pointer-events-none">
            <div className="px-3 py-1 rounded-full bg-black/50 backdrop-blur-md text-white text-xs font-medium">
              {zoom.toFixed(1)}x
            </div>
          </div>
        )}

        {/* Recording indicator */}
        {isRecording && (
          <div className="absolute top-3 left-1/2 -translate-x-1/2 z-30 flex items-center gap-1.5 px-3 py-1 rounded-full bg-red-500/90 backdrop-blur-sm">
            <div className="w-2 h-2 rounded-full bg-white animate-pulse" />
            <span className="text-white text-[11px] font-medium">{fmtTime(recordingTime)}</span>
          </div>
        )}
      </div>

      {/* Bottom controls - compact, no gallery duplicates */}
      <div className="flex-shrink-0 bg-black/90 backdrop-blur-md px-4 py-3 pb-[max(0.75rem,env(safe-area-inset-bottom))]">
        <input ref={fileInputRef} type="file" accept="image/*,video/*" multiple onChange={handleFileSelect} className="hidden" />

        <div className="flex items-center justify-between">
          {/* Gallery button */}
          <button
            onClick={() => fileInputRef.current?.click()}
            disabled={selectedMedia.length >= 5}
            className="w-12 h-12 rounded-xl bg-white/10 backdrop-blur-sm flex items-center justify-center disabled:opacity-30 active:scale-90 transition-transform"
          >
            <ImageIcon className="w-5 h-5 text-white" />
          </button>

          {/* Capture button */}
          <button
            onMouseDown={handleCaptureStart}
            onMouseLeave={() => { if (isCapturing) handleCaptureEnd(); }}
            onTouchStart={(e) => { handleCaptureStart(); handleTouchStart(e); }}
            onTouchMove={handleTouchMove}
            onTouchEnd={() => { handleCaptureEnd(); handleTouchEnd(); }}
            disabled={selectedMedia.length >= 5}
            className="relative w-[72px] h-[72px] rounded-full flex items-center justify-center disabled:opacity-30"
          >
            <div className="absolute inset-0 rounded-full border-[3px] border-white/40" />
            <div className={cn(
              'relative transition-all duration-200',
              isCapturing ? 'scale-[0.85]' : 'scale-100',
              isRecording ? 'w-8 h-8 rounded-lg bg-red-500' : 'w-[58px] h-[58px] rounded-full bg-white'
            )}>
              {isRecording && <div className="absolute inset-0 rounded-lg animate-pulse bg-red-400" />}
            </div>
            {isRecording && <div className="absolute inset-0 rounded-full border-[3px] border-red-400 animate-ping" />}
          </button>

          {/* Zoom + counter */}
          <div className="flex flex-col items-center gap-1">
            <div className="flex gap-0.5 p-0.5 rounded-full bg-white/10 backdrop-blur-sm">
              {[1, 2, 5].map((zl) => (
                <button
                  key={zl}
                  onClick={() => setZoom(zl)}
                  className={cn(
                    'px-2.5 py-1 rounded-full text-[10px] font-bold transition-all',
                    Math.abs(zoom - zl) < 0.5 ? 'bg-white/25 text-white' : 'text-white/40'
                  )}
                >
                  {zl}x
                </button>
              ))}
            </div>
            <span className="text-white/50 text-[10px] font-medium">{selectedMedia.length}/5</span>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Search, Send, User, Users, UserPlus, Phone, Link as LinkIcon, CheckCircle2, X } from 'lucide-react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Badge } from '@/components/ui/badge';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';
import { useAuth } from '@/contexts/AuthContext';
import { FamilyMember } from '@/types/family';
import { cn } from '@/lib/utils';
import { StarUsername } from '@/components/user/StarUsername';
import { Contacts } from '@capacitor-community/contacts';
import { Capacitor } from '@capacitor/core';

interface SendInvitationModalProps {
  isOpen: boolean;
  onClose: () => void;
  member: FamilyMember | null;
}

interface UserProfile {
  id: string;
  name: string | null;
  username: string | null;
  avatar_url: string | null;
  gender: string | null;
}

export const SendInvitationModal = ({
  isOpen,
  onClose,
  member,
}: SendInvitationModalProps) => {
  const { user, profile } = useAuth();
  const { toast } = useToast();
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<UserProfile[]>([]);
  const [followers, setFollowers] = useState<UserProfile[]>([]);
  const [following, setFollowing] = useState<UserProfile[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [isSending, setIsSending] = useState(false);
  const [isLoadingFollows, setIsLoadingFollows] = useState(false);
  const [isGeneratingLink, setIsGeneratingLink] = useState(false);
  const [copiedLink, setCopiedLink] = useState(false);

  // The gender that the invited person should be (matches the placeholder member's gender)
  const requiredGender = member?.gender;

  // Fetch followers and following when modal opens
  useEffect(() => {
    if (isOpen && user?.id) {
      fetchFollowData();
      setCopiedLink(false);
    }
  }, [isOpen, user?.id]);

  const fetchFollowData = async () => {
    if (!user?.id) return;

    setIsLoadingFollows(true);
    try {
      // Fetch followers
      const { data: followersData } = await supabase
        .from('follows')
        .select('follower_id')
        .eq('following_id', user.id);

      if (followersData && followersData.length > 0) {
        const followerIds = followersData.map(f => f.follower_id);
        const { data: profiles } = await supabase
          .from('profiles')
          .select('id, name, username, avatar_url, gender')
          .in('id', followerIds);
        setFollowers(profiles || []);
      } else {
        setFollowers([]);
      }

      // Fetch following
      const { data: followingData } = await supabase
        .from('follows')
        .select('following_id')
        .eq('follower_id', user.id);

      if (followingData && followingData.length > 0) {
        const followingIds = followingData.map(f => f.following_id);
        const { data: profiles } = await supabase
          .from('profiles')
          .select('id, name, username, avatar_url, gender')
          .in('id', followingIds);
        setFollowing(profiles || []);
      } else {
        setFollowing([]);
      }
    } catch (error) {
      console.error('Error fetching follow data:', error);
    } finally {
      setIsLoadingFollows(false);
    }
  };

  const createInviteToken = async () => {
    if (!member || !user?.id) return null;
    
    setIsGeneratingLink(true);
    try {
      const { data, error } = await (supabase as any)
        .from('family_invites')
        .insert({
          invited_by: user.id,
          tree_node_id: member.id,
          relation_type: 'family_member', 
        })
        .select('token')
        .single();
        
      if (error) throw error;
      return data?.token;
    } catch (error) {
      console.error('Error creating invite token:', error);
      toast({
        title: "Xato",
        description: "Havola yaratishda xatolik ro'y berdi",
        variant: "destructive",
      });
      return null;
    } finally {
      setIsGeneratingLink(false);
    }
  };

  const handleCopyLink = async () => {
    const token = await createInviteToken();
    if (!token) return;
    
    // Base URL dynamically based on environment or fixed
    const baseUrl = window.location.origin;
    const inviteLink = `${baseUrl}/invite/${token}`;
    
    try {
      await navigator.clipboard.writeText(inviteLink);
      setCopiedLink(true);
      toast({
        title: "Nusxalandi!",
        description: "Taklif havolasi xotiraga nusxalandi",
      });
      setTimeout(() => setCopiedLink(false), 3000);
    } catch (err) {
      console.error('Failed to copy text: ', err);
      toast({
        title: "Xato",
        description: "Havolani nusxalash imkonsiz",
        variant: "destructive",
      });
    }
  };

  const handlePickContactAndSend = async () => {
    if (!Capacitor.isNativePlatform()) {
      toast({
        title: "Platforma qo'llab-quvvatlanmaydi",
        description: "Kontaktlardan tanlash faqat mobil ilovada mavjud.",
        variant: "destructive",
      });
      return;
    }
    
    try {
      const permission = await Contacts.requestPermissions();
      if (permission.contacts !== 'granted') {
        toast({
          title: "Ruxsat yo'q",
          description: "Kontaktlarga kirishga ruxsat berilmadi",
          variant: "destructive",
        });
        return;
      }

      const result = await Contacts.pickContact({ projection: { name: true, phones: true } });
      const contact = result.contact;
      
      if (!contact || !contact.phones || contact.phones.length === 0) {
        toast({
          title: "Raqam yo'q",
          description: "Tanlangan kontaktda telefon raqami mavjud emas",
          variant: "destructive",
        });
        return;
      }
      
      const phoneNumber = contact.phones[0].number;
      const token = await createInviteToken();
      if (!token) return;
      
      const baseUrl = window.location.origin;
      const inviteLink = `${baseUrl}/invite/${token}`;
      const senderName = profile?.name || "foydalanuvchi";
      const message = `Siz ${senderName} oila daraxtiga qo'shilishga taklif qilindingiz!\n${inviteLink}`;
      
      // Open native SMS composer
      window.open(`sms:${phoneNumber}?body=${encodeURIComponent(message)}`, '_system');
      
      handleClose();
      
    } catch (err) {
      console.log('Error or cancellation during contact picking:', err);
    }
  };

  const handleSearch = async (query: string) => {
    setSearchQuery(query);
    if (query.length < 2) {
      setSearchResults([]);
      return;
    }

    setIsSearching(true);
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('id, name, username, avatar_url, gender')
        .or(`name.ilike.%${query}%,username.ilike.%${query}%`)
        .neq('id', user?.id)
        .limit(20);

      if (error) throw error;
      setSearchResults(data || []);
    } catch (error) {
      console.error('Search error:', error);
      toast({
        title: "Xato",
        description: "Qidirishda xatolik yuz berdi",
        variant: "destructive",
      });
    } finally {
      setIsSearching(false);
    }
  };

  const handleSendInvitation = async (userId: string) => {
    if (!member || !user?.id) return;

    setIsSending(true);
    try {
      // Check if invitation already exists
      const { data: existing } = await supabase
        .from('family_invitations')
        .select('id')
        .eq('sender_id', user.id)
        .eq('receiver_id', userId)
        .eq('member_id', member.supabaseId || member.id)
        .eq('status', 'pending')
        .maybeSingle();

      if (existing) {
        toast({
          title: "Mavjud",
          description: "Bu foydalanuvchiga allaqachon taklifnoma yuborilgan",
          variant: "destructive",
        });
        setIsSending(false);
        return;
      }

      const { error } = await supabase
        .from('family_invitations')
        .insert({
          sender_id: user.id,
          receiver_id: userId,
          member_id: member.supabaseId || member.id,
          relation_type: 'family_member',
        });

      if (error) throw error;

      // Create notification for receiver
      await supabase.from('notifications').insert({
        user_id: userId,
        actor_id: user.id,
        type: 'family_invitation',
      });

      toast({
        title: "Yuborildi!",
        description: "Taklifnoma muvaffaqiyatli yuborildi",
      });
      handleClose();
    } catch (error) {
      console.error('Send invitation error:', error);
      toast({
        title: "Xato",
        description: error instanceof Error ? error.message : "Taklifnoma yuborishda xatolik",
        variant: "destructive",
      });
    } finally {
      setIsSending(false);
    }
  };

  const handleClose = () => {
    setSearchQuery('');
    setSearchResults([]);
    onClose();
  };

  // Filter users by gender if required
  const filterByGender = (users: UserProfile[]) => {
    if (!requiredGender) return users;
    return users.filter(u => u.gender === requiredGender || !u.gender);
  };

  const renderUserList = (users: UserProfile[], emptyMessage: string) => {
    const filteredUsers = filterByGender(users);
    
    if (filteredUsers.length === 0) {
      return (
        <div className="text-center py-8 text-muted-foreground">
          {emptyMessage}
        </div>
      );
    }

    return (
      <div className="space-y-2">
        {filteredUsers.map((profileListMember) => {
          const isGenderMatch = !requiredGender || profileListMember.gender === requiredGender;
          const genderMismatch = requiredGender && profileListMember.gender && profileListMember.gender !== requiredGender;
          
          return (
            <div
              key={profileListMember.id}
              className={cn(
                "flex items-center justify-between p-3 rounded-2xl border transition-colors bg-background/40 backdrop-blur-sm",
                genderMismatch 
                  ? "border-border/50 opacity-50" 
                  : "border-border/50 hover:bg-muted/30"
              )}
            >
              <div className="flex items-center gap-3">
                <Avatar className="h-10 w-10">
                  <AvatarImage src={profileListMember.avatar_url || undefined} />
                  <AvatarFallback className={cn(
                    profileListMember.gender === 'male' ? "bg-sky-500" : "bg-pink-500",
                    "text-primary-foreground"
                  )}>
                    {profileListMember.name?.[0]?.toUpperCase() || <User className="w-4 h-4" />}
                  </AvatarFallback>
                </Avatar>
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2">
                    <p className="font-medium truncate">{profileListMember.name || "Noma'lum"}</p>
                    {profileListMember.gender && (
                      <Badge 
                        variant="outline" 
                        className={cn(
                          "text-xs",
                          profileListMember.gender === 'male' 
                            ? "border-sky-500/50 text-sky-600 dark:text-sky-400" 
                            : "border-pink-500/50 text-pink-600 dark:text-pink-400"
                        )}
                      >
                        {profileListMember.gender === 'male' ? 'Erkak' : 'Ayol'}
                      </Badge>
                    )}
                  </div>
                  {profileListMember.username && (
                    <div className="truncate">
                      <StarUsername username={profileListMember.username} textClassName="text-sm" />
                    </div>
                  )}
                </div>
              </div>
              <Button
                size="sm"
                onClick={() => handleSendInvitation(profileListMember.id)}
                disabled={isSending || genderMismatch}
                className={cn(
                  genderMismatch 
                    ? "bg-muted text-muted-foreground" 
                    : "text-white bg-gradient-to-b from-emerald-400 to-emerald-600 shadow-md shadow-emerald-500/20 hover:from-emerald-300 hover:to-emerald-600"
                )}
              >
                <Send className="w-4 h-4 mr-1" />
                Yuborish
              </Button>
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <Dialog open={isOpen} onOpenChange={handleClose}>
      <DialogContent className="sm:max-w-md max-h-[85vh] overflow-hidden flex flex-col p-0 rounded-[28px] border border-white/10 bg-background/80 backdrop-blur-2xl shadow-2xl">
        <DialogHeader className="px-5 pt-4 pb-3 border-b border-border/40">
          <div className="flex items-center justify-between">
            <DialogTitle className="text-[15px] font-semibold tracking-tight">Taklifnoma yuborish</DialogTitle>
            <Button
              type="button"
              variant="ghost"
              size="icon"
              onClick={handleClose}
              className="h-9 w-9 rounded-2xl bg-muted/30 hover:bg-muted/50"
              aria-label="Yopish"
            >
              <X className="h-4 w-4" />
            </Button>
          </div>
        </DialogHeader>

        <div className="flex-1 overflow-hidden flex flex-col gap-4 px-5 py-4">
          {member && (
            <div className="text-center">
              <p className="text-sm text-muted-foreground">
                <span className="font-semibold text-foreground">{member.name || "Noma'lum"}</span> uchun foydalanuvchi taklif qiling
              </p>
              {requiredGender && (
                <Badge 
                  variant="outline" 
                  className={cn(
                    "mt-2 mb-0 rounded-full px-3 py-1 text-[11px] font-semibold",
                    requiredGender === 'male' 
                      ? "border-sky-500/50 text-sky-600 dark:text-sky-400" 
                      : "border-pink-500/50 text-pink-600 dark:text-pink-400"
                  )}
                >
                  Faqat {requiredGender === 'male' ? 'erkak' : 'ayol'} foydalanuvchilar
                </Badge>
              )}
            </div>
          )}

          {/* New prominent action buttons */}
          <div className="grid grid-cols-2 gap-3">
            <Button 
              variant="outline" 
              onClick={handlePickContactAndSend}
              disabled={isGeneratingLink}
              className="h-[92px] flex flex-col gap-2 rounded-[22px] border-white/10 bg-white/5 hover:bg-white/10 dark:bg-white/5 dark:hover:bg-white/10 shadow-sm"
            >
              <div className="w-9 h-9 rounded-2xl bg-emerald-500/10 flex items-center justify-center border border-emerald-500/20">
                <Phone className="h-4 w-4 text-emerald-500" />
              </div>
              <div className="text-center leading-tight">
                <div className="text-[13px] font-semibold">Kontaktlar</div>
                <div className="text-[11px] text-muted-foreground">SMS orqali yuborish</div>
              </div>
            </Button>
            <Button
              variant="outline"
              onClick={handleCopyLink}
              disabled={isGeneratingLink}
              className="h-[92px] flex flex-col gap-2 rounded-[22px] border-white/10 bg-white/5 hover:bg-white/10 dark:bg-white/5 dark:hover:bg-white/10 shadow-sm"
            >
              <div className={cn(
                "w-9 h-9 rounded-2xl flex items-center justify-center transition-colors border",
                copiedLink ? "bg-emerald-500/10 border-emerald-500/20" : "bg-primary/10 border-primary/20"
              )}>
                {copiedLink ? (
                  <CheckCircle2 className="h-4 w-4 text-emerald-500" />
                ) : (
                  <LinkIcon className="h-4 w-4 text-primary" />
                )}
              </div>
              <div className="text-center leading-tight">
                <div className="text-[13px] font-semibold">Havola</div>
                <div className="text-[11px] text-muted-foreground">Nusxalash</div>
              </div>
            </Button>
          </div>

          <div className="relative flex items-center py-1">
            <div className="flex-grow border-t border-border"></div>
            <span className="flex-shrink-0 mx-4 text-[10px] text-muted-foreground uppercase tracking-widest font-semibold flex items-center gap-1.5 opacity-80">
              <UserPlus className="w-3 h-3" /> Yoki tizim ichidan
            </span>
            <div className="flex-grow border-t border-border"></div>
          </div>

          {/* Search Input */}
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              type="text"
              value={searchQuery}
              onChange={(e) => handleSearch(e.target.value)}
              placeholder="Ism yoki username bo'yicha qidirish..."
              className="pl-10 h-11 rounded-2xl bg-muted/30 border-border/50 focus-visible:ring-1 focus-visible:border-primary/40"
            />
          </div>

          {/* Search Results or Tabs */}
          <div className="flex-1 overflow-hidden">
            {searchQuery.length >= 2 ? (
              <ScrollArea className="h-[250px] sm:h-[300px]">
                <div className="pr-4">
                  <p className="text-sm text-muted-foreground mb-2">Qidiruv natijalari</p>
                  {isSearching ? (
                    <div className="text-center py-8 text-muted-foreground">
                      Qidirilmoqda...
                    </div>
                  ) : (
                    renderUserList(searchResults, "Foydalanuvchi topilmadi")
                  )}
                </div>
              </ScrollArea>
            ) : (
              <Tabs defaultValue="followers" className="flex-1 flex flex-col h-[250px] sm:h-[300px]">
