interface FullScreenViewerProps {
  posts: Post[];
  initialIndex: number;
  onClose: () => void;
}

export const FullScreenViewer = ({ posts, initialIndex, onClose }: FullScreenViewerProps) => {
  const [currentPostIndex, setCurrentPostIndex] = useState(initialIndex);
  const [currentMediaIndex, setCurrentMediaIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(true);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [slideDirection, setSlideDirection] = useState<'up' | 'down' | null>(null);
  const [showDoubleTapHeart, setShowDoubleTapHeart] = useState(false);
  const [heartAnimClass, setHeartAnimClass] = useState('animate-heartBurst');
  const [showVideoPlayer, setShowVideoPlayer] = useState(false);
  const [videoPlayerSrc, setVideoPlayerSrc] = useState('');
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const [isAudioPlaying, setIsAudioPlaying] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);

  const touchStartY = useRef(0);
  const touchStartX = useRef(0);
  const lastTapRef = useRef(0);
  const singleTapTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const currentPost = posts[currentPostIndex];

  const mediaUrls = currentPost?.media_urls || (currentPost?.image_url ? [currentPost.image_url] : []);
  const currentMediaUrl = mediaUrls[currentMediaIndex];

  const rawContent = currentPost?.content || '';
  const locationMatch = rawContent.match(/(?:^|\n)≡ƒôì\s*(.+?)\s*$/m);
  const locationLine = locationMatch ? locationMatch[1].trim() : '';
  const locationParts = locationLine.split('||').map((p) => p.trim()).filter(Boolean);
  const locationText = locationParts[0] || '';
  const coordsPart = locationParts[1] || '';
  const coordsMatch = coordsPart.match(/^(-?\d+(?:\.\d+)?),\s*(-?\d+(?:\.\d+)?)$/);
  const lat = coordsMatch?.[1] || '';
  const lon = coordsMatch?.[2] || '';
  const mapUrl = locationText
    ? lat && lon
      ? 'https://www.google.com/maps?q=' + encodeURIComponent(lat + ',' + lon)
      : 'https://www.google.com/maps/search/?api=1&query=' + encodeURIComponent(locationText)
    : '';

  const formatLocationShort = (text: string) => {
    const normalized = (text || '').trim();
    if (!normalized) return '';

    const parts = normalized
      .split(',')
      .map((p) => p.trim())
      .filter(Boolean);

    const drop = new Set(["o'zbekiston", 'ozbekiston', 'uzbekistan', 'republic of uzbekistan']);
    let cleaned = parts;
    if (cleaned.length > 1) {
      const last = cleaned[cleaned.length - 1].toLowerCase();
      if (drop.has(last)) cleaned = cleaned.slice(0, -1);
    }

    const mostSpecific = cleaned[0] || cleaned[cleaned.length - 1] || '';
    const oneWord = mostSpecific.split(/\s+/).filter(Boolean)[0] || '';
    return oneWord;
  };

  const locationTextShort = formatLocationShort(locationText);
  const contentWithoutLocation = rawContent.replace(/(?:\n|^)≡ƒôì\s*.+\s*$/m, '').trim();

  // Hook for double-tap like
  const { isLiked, toggleLike } = usePostLikes(currentPost?.id || '');

  const { isSaved, save, unsave } = useSavedMusic();

  const audioKey = currentPost?.id ? `post:${currentPost.id}:fullscreen` : null;

  const stopAudio = useCallback(() => {
    const el = audioRef.current;
    if (!el) return;
    try {
      el.pause();
    } catch {
      // ignore
    }
    setIsAudioPlaying(false);
  }, []);

  const playAudio = useCallback(async () => {
    if (!currentPost?.audio_url) return;
    if (!audioKey) return;
    const el = audioRef.current;
    if (!el) return;

    try {
      el.src = currentPost.audio_url;
      el.loop = true;
      el.preload = 'auto';
      el.crossOrigin = 'anonymous';
      try { el.load(); } catch (_e) { /* ignore load errors */ }
    } catch {
      // ignore
    }

    const ok = await playExclusiveAudio(audioKey, el);
    if (!ok) {
      setIsAudioPlaying(false);
      return;
    }
    setIsAudioPlaying(!el.paused);
  }, [audioKey, currentPost?.audio_url]);

  const toggleAudio = useCallback(() => {
    const el = audioRef.current;
    if (!el) return;
    if (isAudioPlaying) {
      stopActiveAudio(audioKey || undefined);
      stopAudio();
    } else {
      void playAudio();
    }
  }, [audioKey, isAudioPlaying, playAudio, stopAudio]);

  const isVideo = (url: string) => {
    return url?.includes('.mp4') || url?.includes('.mov') || url?.includes('.webm');
  };

  // Extract dominant colors from current media
  const { dominantColor, secondaryColor } = useColorExtractor(
    currentMediaUrl,
    isVideo(currentMediaUrl || '')
  );

  const isLowPowerDevice = useMemo(() => {
    if (typeof window === 'undefined') return false;
    try {
      const isSmallScreen = window.matchMedia?.('(max-width: 768px)')?.matches ?? false;
      const cores = typeof navigator !== 'undefined' ? (navigator as Navigator & { hardwareConcurrency?: number }).hardwareConcurrency : undefined;
      const lowCpu = typeof cores === 'number' ? cores <= 6 : false;
      return isSmallScreen || lowCpu;
    } catch {
      return false;
    }
  }, []);

  useEffect(() => {
    setCurrentMediaIndex(0);
    setIsPlaying(true);
    stopActiveAudio(audioKey || undefined);
    stopAudio();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentPostIndex]);

  useEffect(() => {
    return () => {
      stopActiveAudio(audioKey || undefined);
      stopAudio();
    };
  }, [audioKey, stopAudio]);

  useEffect(() => {
    if (videoRef.current) {
      if (isPlaying) {
        videoRef.current.play().catch(() => {});
      } else {
        videoRef.current.pause();
      }
    }
  }, [isPlaying, currentMediaIndex, currentPostIndex]);

  // Smooth transition to next/prev post
  const smoothNavigate = (direction: 'up' | 'down') => {
    if (isTransitioning) return;

    const canGoNext = direction === 'down' && currentPostIndex < posts.length - 1;
    const canGoPrev = direction === 'up' && currentPostIndex > 0;

    if (!canGoNext && !canGoPrev) return;

    setIsTransitioning(true);
    setSlideDirection(direction);

    // Wait for exit animation
    setTimeout(() => {
      if (direction === 'down') {
        setCurrentPostIndex((prev) => prev + 1);
      } else {
        setCurrentPostIndex((prev) => prev - 1);
      }

      // Reset for enter animation
      setTimeout(() => {
        setSlideDirection(null);
        setIsTransitioning(false);
      }, 300);
    }, 200);
  };

  const handleClose = useCallback(() => {
    stopActiveAudio(audioKey || undefined);
    stopAudio();
    onClose();
  }, [audioKey, onClose, stopAudio]);

  // Mouse wheel scroll for post navigation with debounce
  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    let isScrolling = false;
    let scrollTimeout: ReturnType<typeof setTimeout>;

    const handleWheel = (e: WheelEvent) => {
      e.preventDefault();

      if (isScrolling || isTransitioning) return;

      if (Math.abs(e.deltaY) > 30) {
        isScrolling = true;

        if (e.deltaY > 0) {
          smoothNavigate('down');
        } else {
          smoothNavigate('up');
        }

        // Block scrolling for 600ms (animation duration + buffer)
        scrollTimeout = setTimeout(() => {
          isScrolling = false;
        }, 600);
      }
    };

    container.addEventListener('wheel', handleWheel, { passive: false });
    return () => {
      container.removeEventListener('wheel', handleWheel);
      clearTimeout(scrollTimeout);
    };
  }, [posts.length, isTransitioning, currentPostIndex]);

  // Handle keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') handleClose();
      if (e.key === 'ArrowUp') smoothNavigate('up');
      if (e.key === 'ArrowDown') smoothNavigate('down');
      if (e.key === 'ArrowLeft') goToPrevMedia();
      if (e.key === 'ArrowRight') goToNextMedia();
      if (e.key === ' ') togglePlay();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [currentPostIndex, currentMediaIndex, handleClose]);

  // Prevent body scroll
  useEffect(() => {
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = '';
    };
  }, []);

  const goToNextPost = () => {
    smoothNavigate('down');
  };

  const goToPrevPost = () => {
    smoothNavigate('up');
  };

  const goToNextMedia = () => {
    if (currentMediaIndex < mediaUrls.length - 1) {
      setCurrentMediaIndex((prev) => prev + 1);
    }
  };

  const goToPrevMedia = () => {
    if (currentMediaIndex > 0) {
      setCurrentMediaIndex((prev) => prev - 1);
    }
  };

  const togglePlay = () => {
    setIsPlaying((prev) => !prev);
  };

  // Touch handlers for swipe
  const handleTouchStart = (e: React.TouchEvent) => {
    touchStartY.current = e.touches[0].clientY;
    touchStartX.current = e.touches[0].clientX;
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    const touchEndY = e.changedTouches[0].clientY;
    const touchEndX = e.changedTouches[0].clientX;
    const diffY = touchStartY.current - touchEndY;
    const diffX = touchStartX.current - touchEndX;

    // Prioritize vertical swipe for post navigation
    if (Math.abs(diffY) > Math.abs(diffX) && Math.abs(diffY) > 50) {
      if (diffY > 0) {
        goToNextPost();
      } else {
        goToPrevPost();
      }
    }
    // Horizontal swipe
    else if (Math.abs(diffX) > 50) {
      if (diffX > 0) {
        goToNextPost();
      } else {
        goToPrevPost();
      }
    }
  };

  const handleMediaClick = (e: React.MouseEvent) => {
    const now = Date.now();
    const DOUBLE_TAP_DELAY = 300;

    // Check for double tap
    if (now - lastTapRef.current < DOUBLE_TAP_DELAY) {
      if (singleTapTimerRef.current) {
        clearTimeout(singleTapTimerRef.current);
        singleTapTimerRef.current = null;
      }
      // Double tap detected - show heart and like
      const anims = ['animate-heartBurst', 'animate-likePop', 'animate-likeSwing', 'animate-likeFloat', 'animate-likePulse'];
      setHeartAnimClass(anims[Math.floor(Math.random() * anims.length)]);
      setShowDoubleTapHeart(true);
      if (!isLiked) {
        toggleLike();
      }
      setTimeout(() => setShowDoubleTapHeart(false), 1000);
      lastTapRef.current = 0;
      return;
    }

    lastTapRef.current = now;

    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const width = rect.width;

    // Single tap logic - delayed to check for double tap
    if (singleTapTimerRef.current) clearTimeout(singleTapTimerRef.current);
    singleTapTimerRef.current = setTimeout(() => {
      if (lastTapRef.current === 0) return;
      lastTapRef.current = 0;
      singleTapTimerRef.current = null;

      // Click on left side - previous media, right side - next media, center - toggle play
      if (x < width * 0.3 && mediaUrls.length > 1) {
        goToPrevMedia();
      } else if (x > width * 0.7 && mediaUrls.length > 1) {
        goToNextMedia();
      } else if (isVideo(currentMediaUrl)) {
        togglePlay();
      }
    }, DOUBLE_TAP_DELAY + 50);
  };

  useEffect(() => {
    return () => {
      if (singleTapTimerRef.current) {
        clearTimeout(singleTapTimerRef.current);
        singleTapTimerRef.current = null;
      }
    };
  }, []);

  if (!currentPost) return null;

  return (
    <>
      <div
        ref={containerRef}
        className="fixed inset-0 z-[60] flex flex-col overflow-hidden"
        style={{
          backgroundColor: '#000',
          backgroundImage: `linear-gradient(135deg, ${dominantColor} 0%, ${secondaryColor} 50%, ${dominantColor} 100%)`
        }}
        onTouchStart={handleTouchStart}
        onTouchEnd={handleTouchEnd}>

        {/* Blurred background overlay for extra depth */}
        {!isLowPowerDevice && (
          <div
            className="absolute inset-0 z-0"
            style={{
              background: `radial-gradient(ellipse at center, transparent 0%, ${dominantColor} 70%)`,
              backdropFilter: 'blur(20px)'
            }}
          />
        )}

        {/* Header */}
        <div className="absolute top-0 left-0 right-0 z-10 flex items-center justify-between p-4 bg-transparent">
          <button
            onClick={handleClose}
            className="p-3.5 rounded-full bg-white/10 backdrop-blur-md border border-white/10 opacity-100 mx-px text-center px-[4px] py-[4px]"
            aria-label="Close"
            type="button">

            <X className="text-white w-[20px] h-[20px]" />
          </button>

          {/* Post counter */}
        </div>

        {/* Media area */}
        <div
          className={cn(
            "flex-1 flex items-center justify-center relative overflow-hidden z-[1] transition-all duration-300 ease-out",
            slideDirection === 'down' && "animate-slide-out-up",
            slideDirection === 'up' && "animate-slide-out-down",
            !slideDirection && "animate-slide-in"
          )}
          onClick={handleMediaClick}>

          {isVideo(currentMediaUrl) ?
            <>
              <video
                ref={videoRef}
                src={currentMediaUrl}
                className="max-w-full max-h-full object-contain"
                loop
                playsInline
                autoPlay />

              {/* Play/Pause overlay */}
              <button
                onClick={(e) => { e.stopPropagation(); togglePlay(); }}
                className="absolute inset-0 flex items-center justify-center">

                <div className={cn(
                  "p-4 rounded-full bg-black/30 backdrop-blur-sm transition-opacity",
                  isPlaying ? "opacity-0" : "opacity-100"
                )}>
                  {isPlaying ?
                    <Pause className="h-8 w-8 text-white" /> :
                    <Play className="h-8 w-8 text-white" />
                  }
                </div>
              </button>
            </> :

            <img
              src={currentMediaUrl}
              alt="Post media"
              className="max-w-full max-h-full object-contain" />

          }

          {/* Double-tap heart animation overlay */}
          {showDoubleTapHeart &&
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-20">
              <Heart className={cn("h-24 w-24 text-white fill-white drop-shadow-lg", heartAnimClass)} />
            </div>
          }

          {/* Media indicators */}
          {mediaUrls.length > 1 &&
            <>
              {/* Dots */}
              <div className="absolute bottom-24 left-1/2 -translate-x-1/2 flex gap-1.5">
                {mediaUrls.map((_, index) =>
                  <button
                    key={index}
                    onClick={(e) => { e.stopPropagation(); setCurrentMediaIndex(index); }}
                    className={cn(
                      "w-2 h-2 rounded-full transition-colors",
                      currentMediaIndex === index ? "bg-white" : "bg-white/40"
                    )} />

                )}
              </div>

              {/* Navigation arrows */}
              {currentMediaIndex > 0 &&
                <button
                  onClick={(e) => { e.stopPropagation(); goToPrevMedia(); }}
                  className="absolute left-2 top-1/2 -translate-y-1/2 p-2 bg-black/30 backdrop-blur-sm px-px py-[5px] border-0 rounded-2xl opacity-85 text-left text-sm mx-0 my-0">

                  <ChevronLeft className="h-5 text-white w-[9px]" />
                </button>
              }
              {currentMediaIndex < mediaUrls.length - 1 &&
                <button
                  onClick={(e) => { e.stopPropagation(); goToNextMedia(); }}
                  className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-black/30 backdrop-blur-sm opacity-85 px-px py-[5px] rounded-sm">

                  <ChevronRight className="h-5 text-white w-[10px] shadow-2xs opacity-100 px-px py-[5px]" />
                </button>
              }
            </>
          }
        </div>

        {currentPost.audio_url && (
          <div className="absolute bottom-6 right-4 z-30" onClick={(e) => e.stopPropagation()}>
            <MusicOverlay
              audioTitle={currentPost.audio_title}
              audioArtist={currentPost.audio_artist}
              isPlaying={isAudioPlaying}
              isSaved={isSaved(currentPost.audio_url)}
              onTogglePlay={toggleAudio}
              onToggleSave={() => {
                if (!currentPost.audio_url) return;
                if (isSaved(currentPost.audio_url)) {
                  void unsave(currentPost.audio_url);
                } else {
                  void save({
                    audio_url: currentPost.audio_url,
                    audio_title: currentPost.audio_title,
                    audio_artist: currentPost.audio_artist,
                  });
                }
              }}
            />

            <audio
              ref={audioRef}
              preload="none"
              onPlay={() => setIsAudioPlaying(true)}
              onPause={() => setIsAudioPlaying(false)}
              onEnded={() => setIsAudioPlaying(false)}
              className="absolute left-0 top-0 h-px w-px opacity-0 pointer-events-none"
            />
          </div>
        )}

        {/* Right side actions - vertical layout like reference */}
        <div className="absolute right-4 bottom-32 z-[2]">
          {currentPost.is_memorial ? (
            <MemorialFullscreenActions
              memorialPostId={currentPost.id}
              initialLikesCount={currentPost.likes_count}
              initialCommentsCount={currentPost.comments_count}
              initialViewsCount={currentPost.views_count ?? 0}
            />
          ) : (
            <FullscreenActions
              postId={currentPost.id}
              initialLikesCount={currentPost.likes_count}
              initialCommentsCount={currentPost.comments_count}
              initialViewsCount={currentPost.views_count ?? 0}
              videoUrl={isVideo(currentMediaUrl) ? currentMediaUrl : undefined}
              onOpenVideoPlayer={(url) => {
                setVideoPlayerSrc(url);
                setShowVideoPlayer(true);
                if (videoRef.current) videoRef.current.pause();
                setIsPlaying(false);
                stopActiveAudio(audioKey || undefined);
                stopAudio();
              }} 
            />
          )}
        </div>

        {/* Author info */}
        <div className="absolute bottom-14 left-0 right-14 bg-transparent p-4 pt-14 z-[1]">
          {!currentPost.is_memorial && (
            <div className="flex items-center mb-2 gap-2">
              <UserAvatar userId={currentPost.user_id} avatarUrl={currentPost.author?.avatar_url} name={currentPost.author?.full_name} size="lg" className="border-2 border-white/20 ring-0" />
              <UserInfo userId={currentPost.user_id} name={currentPost.author?.full_name} username={currentPost.author?.username} variant="fullscreen" />
              <FollowButton targetUserId={currentPost.user_id} size="sm" />
            </div>
          )}
          {locationTextShort && mapUrl && !currentPost.is_memorial && (
            <a
              href={mapUrl}
              target="_blank"
              rel="noreferrer"
              className="inline-flex items-center gap-1 text-xs text-white/70 font-medium uppercase max-w-[80%] hover:text-white transition-colors"
              title={locationText}
            >
              <Icon icon="gis:location-poi" className="h-3.5 w-3.5 flex-shrink-0" />
              <span className="truncate">{locationTextShort}</span>
            </a>
          )}

          {contentWithoutLocation && <PostCaption content={contentWithoutLocation} variant="fullscreen" />}
        </div>
      </div>

      {typeof document !== 'undefined' && showVideoPlayer && createPortal(
        <div
          className="fixed inset-0 z-[80] w-full h-full min-h-[100dvh] overflow-hidden bg-black"
          style={{ height: '100dvh', maxHeight: '100dvh' }}>

          <SamsungUltraVideoPlayer
            src={videoPlayerSrc}
            title={currentPost?.content?.slice(0, 50) || 'Video'}
            onClose={() => {
              setShowVideoPlayer(false);
            }}
            startInFullscreen={true}
          />
        </div>,
        document.body
      )}
    </>
  );
};

import { useState, useRef, useEffect, useCallback, useMemo } from 'react';

import { createPortal } from 'react-dom';

import { Play, Pause, ChevronLeft, ChevronRight, Heart, X, Send, Loader2 } from 'lucide-react';

import { Post } from '@/types';

import { cn } from '@/lib/utils';



import { useColorExtractor } from '@/hooks/useColorExtractor';

import { FullscreenActions } from '@/components/post/FullscreenActions';

import { PostCaption } from '@/components/post/PostCaption';

import { usePostLikes } from '@/hooks/usePostLikes';

import { UserAvatar } from '@/components/user/UserAvatar';

import { UserInfo } from '@/components/user/UserInfo';

import { FollowButton } from '@/components/user/FollowButton';

import { SamsungUltraVideoPlayer } from '@/components/video/SamsungUltraVideoPlayer';

import type { Short } from '@/components/shorts/YouTubeShortsSection';

import { useActiveStories } from '@/hooks/useActiveStories';

import { useAuth } from '@/contexts/AuthContext';

import { supabase } from '@/integrations/supabase/client';

import { StoryViewer } from '@/components/stories/StoryViewer';

import type { StoryGroup, Story } from '@/hooks/useStories';

import { ShareDialog } from '@/components/post/ShareDialog';

import { Icon } from '@iconify/react';

import { MusicOverlay } from '@/components/music/MusicOverlay';

import { playExclusiveAudio, stopActiveAudio } from '@/lib/audioController';

import { useSavedMusic } from '@/hooks/useSavedMusic';



type TabType = 'shorts' | 'posts';



interface UnifiedFullScreenViewerProps {

  posts: Post[];

  shorts: Short[];

  initialTab: TabType;

  initialIndex: number;

  onClose: () => void;

}



export const UnifiedFullScreenViewer = ({

  posts,

  shorts,

  initialTab,

  initialIndex,

  onClose

}: UnifiedFullScreenViewerProps) => {

  const { user } = useAuth();

  const { getStoryInfo } = useActiveStories();

  const [activeTab, setActiveTab] = useState<TabType>(initialTab);

  const [postIndex, setPostIndex] = useState(initialTab === 'posts' ? initialIndex : 0);

  const [shortIndex, setShortIndex] = useState(initialTab === 'shorts' ? initialIndex : 0);

  const [currentMediaIndex, setCurrentMediaIndex] = useState(0);

  const [isPlaying, setIsPlaying] = useState(true);

  const [isTransitioning, setIsTransitioning] = useState(false);

  const [slideDirection, setSlideDirection] = useState<'up' | 'down' | null>(null);

  const [showDoubleTapHeart, setShowDoubleTapHeart] = useState(false);

  const [heartAnimClass, setHeartAnimClass] = useState('animate-heartBurst');

  const [showVideoPlayer, setShowVideoPlayer] = useState(false);

  const [videoPlayerSrc, setVideoPlayerSrc] = useState('');



  const [shortsPlaying, setShortsPlaying] = useState(true);

  const [showPlayIndicator, setShowPlayIndicator] = useState(false);



  const [showShortShare, setShowShortShare] = useState(false);



  const [storyViewerOpen, setStoryViewerOpen] = useState(false);

  const [storyViewerGroups, setStoryViewerGroups] = useState<StoryGroup[]>([]);

  const [isShortIframeReady, setIsShortIframeReady] = useState(false);



  const containerRef = useRef<HTMLDivElement>(null);

  const videoRef = useRef<HTMLVideoElement>(null);

  const ambientVideoRef = useRef<HTMLVideoElement>(null);

  const shortsIframeRef = useRef<HTMLIFrameElement>(null);

  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [isAudioPlaying, setIsAudioPlaying] = useState(false);



  const mutedMediaRef = useRef(new Map<HTMLMediaElement, {muted: boolean;volume: number;}>());

  const touchStartY = useRef(0);

  const touchStartX = useRef(0);

  const touchStartTime = useRef(0);

  const touchMoved = useRef(false);



  const lastTapRef = useRef(0);

  const singleTapTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);



  const lastShortsTouchTapTs = useRef(0);



  const mouseDownRef = useRef(false);

  const mouseStartY = useRef(0);

  const mouseStartX = useRef(0);

  const playIndicatorTimeout = useRef<ReturnType<typeof setTimeout>>();



  const currentPost = activeTab === 'posts' ? posts[postIndex] : null;

  const currentShort = activeTab === 'shorts' ? shorts[shortIndex] : null;



  const { isSaved, save, unsave } = useSavedMusic();



  const audioKey = currentPost?.id ? `post:${currentPost.id}:unified_fullscreen` : null;



  const stopAudio = useCallback(() => {

    const el = audioRef.current;

    if (!el) return;

    try {

      el.pause();

    } catch {

      // ignore

    }

    setIsAudioPlaying(false);

  }, []);



  const playAudio = useCallback(async () => {

    if (!currentPost?.audio_url) return;

    if (!audioKey) return;

    const el = audioRef.current;

    if (!el) return;



    try {

      el.src = currentPost.audio_url;

      el.loop = true;

      el.preload = 'auto';

      el.crossOrigin = 'anonymous';

      try { el.load(); } catch (e) {

        console.error("Audio load error:", e);

      }

    } catch {

      // ignore

    }



    const ok = await playExclusiveAudio(audioKey, el);

    if (!ok) {

      setIsAudioPlaying(false);

      return;

    }

    setIsAudioPlaying(!el.paused);

  }, [audioKey, currentPost?.audio_url]);



  const toggleAudio = useCallback(() => {

    const el = audioRef.current;

    if (!el) return;

    if (isAudioPlaying) {

      stopActiveAudio(audioKey || undefined);

      stopAudio();

    } else {

      void playAudio();

    }

  }, [audioKey, isAudioPlaying, playAudio, stopAudio]);



  const handleClose = useCallback(() => {

    stopActiveAudio(audioKey || undefined);

    stopAudio();

    onClose();

  }, [audioKey, onClose, stopAudio]);



  const rawPostContent = currentPost?.content || '';

  const locationMatch = rawPostContent.match(/(?:^|\n)≡ƒôì\s*(.+?)\s*$/m);

  const locationLine = locationMatch ? locationMatch[1].trim() : '';

  const locationParts = locationLine.split('||').map((p) => p.trim()).filter(Boolean);

  const locationText = locationParts[0] || '';

  const coordsPart = locationParts[1] || '';

  const coordsMatch = coordsPart.match(/^(-?\d+(?:\.\d+)?),\s*(-?\d+(?:\.\d+)?)$/);

  const lat = coordsMatch?.[1] || '';

  const lon = coordsMatch?.[2] || '';

  const mapUrl = locationText

    ? lat && lon

      ? 'https://www.google.com/maps?q=' + encodeURIComponent(lat + ',' + lon)

      : 'https://www.google.com/maps/search/?api=1&query=' + encodeURIComponent(locationText)

    : '';



  const formatLocationShort = (text: string) => {

    const normalized = (text || '').trim();

    if (!normalized) return '';



    const parts = normalized

      .split(',')

      .map((p) => p.trim())

      .filter(Boolean);



    const drop = new Set(["o'zbekiston", 'ozbekiston', 'uzbekistan', 'republic of uzbekistan']);

    let cleaned = parts;

    if (cleaned.length > 1) {

      const last = cleaned[cleaned.length - 1].toLowerCase();

      if (drop.has(last)) cleaned = cleaned.slice(0, -1);

    }



    const mostSpecific = cleaned[0] || cleaned[cleaned.length - 1] || '';

    const oneWord = mostSpecific.split(/\s+/).filter(Boolean)[0] || '';

    return oneWord;

  };



  const locationTextShort = formatLocationShort(locationText);

  const postContentWithoutLocation = rawPostContent.replace(/(?:\n|^)≡ƒôì\s*.+\s*$/m, '').trim();



  const mediaUrls = currentPost?.media_urls || (currentPost?.image_url ? [currentPost.image_url] : []);

  const currentMediaUrl = mediaUrls[currentMediaIndex];



  const isLowPowerDevice = useMemo(() => {

    if (typeof window === 'undefined') return false;

    try {

      const isSmallScreen = window.matchMedia?.('(max-width: 768px)')?.matches ?? false;

      const cores = typeof navigator !== 'undefined' ? (navigator as unknown as { hardwareConcurrency?: number }).hardwareConcurrency : undefined;

      const lowCpu = typeof cores === 'number' ? cores <= 6 : false;

      return isSmallScreen || lowCpu;

    } catch {

      return false;

    }

  }, []);



  const ambientUrl = activeTab === 'posts' ?

  currentMediaUrl :

  currentShort ?

  `https://img.youtube.com/vi/${currentShort.id}/hqdefault.jpg` :

  undefined;



  const { isLiked, toggleLike } = usePostLikes(currentPost?.id || '');



  const isVideo = (url?: string) => url?.includes('.mp4') || url?.includes('.mov') || url?.includes('.webm');



  const { dominantColor, secondaryColor } = useColorExtractor(

    activeTab === 'posts' ? currentMediaUrl : undefined,

    isVideo(currentMediaUrl)

  );



  const bgStyle = activeTab === 'posts' && dominantColor ?

  { background: `linear-gradient(135deg, ${dominantColor} 0%, ${secondaryColor} 50%, ${dominantColor} 100%)` } :

  { background: '#000' };



  const ytOrigin = typeof window !== 'undefined' ? window.location.origin : '';



  const sendYouTubeCommand = useCallback((func: 'playVideo' | 'pauseVideo') => {

    const w = shortsIframeRef.current?.contentWindow;

    if (!w) return;

    w.postMessage(

      JSON.stringify({ event: 'command', func, args: [] }),

      '*'

    );

  }, []);



  const ensureAmbientPlayback = useCallback(() => {

    const ambient = ambientVideoRef.current;

    if (ambient && ambient.paused) {

      const p = ambient.play();

      if (p && typeof p.catch === 'function') p.catch(() => {});

    }



    const main = videoRef.current;

    if (main && !main.paused && main.readyState >= 2) return;

    if (main && isPlaying && main.paused) {

      const p = main.play();

      if (p && typeof p.catch === 'function') p.catch(() => {});

    }

  }, [isPlaying]);



  useEffect(() => {

    setCurrentMediaIndex(0);

    setIsPlaying(true);

    setShortsPlaying(true);

    stopActiveAudio(audioKey || undefined);

    stopAudio();



    // Auto-play audio for posts with music

    if (activeTab === 'posts' && currentPost?.audio_url && audioRef.current) {

      const t = setTimeout(() => void playAudio(), 400);

      return () => clearTimeout(t);

    }

     

  }, [postIndex, shortIndex, activeTab]);



  useEffect(() => {

    if (videoRef.current) {

      if (isPlaying) {

        videoRef.current.play().catch(() => {});

      } else {

        videoRef.current.pause();

      }

    }

  }, [isPlaying, currentMediaIndex, postIndex]);



  useEffect(() => {

    if (activeTab !== 'posts') return;

    if (!currentMediaUrl) return;

    if (!isVideo(currentMediaUrl)) return;



    const main = videoRef.current;

    const ambient = ambientVideoRef.current;

    if (!main || !ambient) return;



    let lastSyncTs = 0;



    const sync = (force = false) => {

      if (!main || !ambient) return;



      const now = performance.now();

      if (!force && isLowPowerDevice && now - lastSyncTs < 220) return;

      lastSyncTs = now;



      if (ambient.playbackRate !== main.playbackRate) {

        ambient.playbackRate = main.playbackRate;

      }



      const diff = Math.abs((ambient.currentTime || 0) - (main.currentTime || 0));

      const threshold = isLowPowerDevice ? 0.32 : 0.18;

      if (diff > threshold) {

        try {

          ambient.currentTime = main.currentTime;

        } catch {

          return;

        }

      }



      if (main.paused) {

        if (!ambient.paused) ambient.pause();

      } else {

        if (ambient.paused) {

          const p = ambient.play();

          if (p && typeof p.catch === 'function') p.catch(() => {});

        }

      }

    };



    const handleLoaded = () => {

      try {

        ambient.currentTime = main.currentTime || 0;

      } catch {

        // ignore

      }

      sync(true);

    };



    const handleTimeUpdate = () => sync(false);

    const handleRateChange = () => sync(true);

    const handlePlay = () => sync(true);

    const handlePause = () => sync(true);

    const handleSeeking = () => sync(true);



    ambient.muted = true;

    ambient.volume = 0;



    ambient.addEventListener('loadedmetadata', handleLoaded);

    main.addEventListener('loadedmetadata', handleLoaded);

    main.addEventListener('timeupdate', handleTimeUpdate);

    main.addEventListener('ratechange', handleRateChange);

    main.addEventListener('play', handlePlay);

    main.addEventListener('pause', handlePause);

    main.addEventListener('seeking', handleSeeking);



    sync(true);



    return () => {

      ambient.removeEventListener('loadedmetadata', handleLoaded);

      main.removeEventListener('loadedmetadata', handleLoaded);

      main.removeEventListener('timeupdate', handleTimeUpdate);

      main.removeEventListener('ratechange', handleRateChange);

      main.removeEventListener('play', handlePlay);

      main.removeEventListener('pause', handlePause);

      main.removeEventListener('seeking', handleSeeking);

    };

  }, [activeTab, currentMediaUrl, isLowPowerDevice]);



  useEffect(() => {

    if (activeTab === 'shorts') {

      if (videoRef.current) videoRef.current.pause();

      setIsPlaying(false);

    }

  }, [activeTab]);



  useEffect(() => {

    if (activeTab !== 'shorts') {

      mutedMediaRef.current.forEach((prev, el) => {

        el.muted = prev.muted;

        el.volume = prev.volume;

      });

      mutedMediaRef.current.clear();

      return;

    }



    const container = containerRef.current;

    const media = Array.from(document.querySelectorAll('video, audio')) as HTMLMediaElement[];



    for (const el of media) {

      if (container && container.contains(el)) continue;

      if (!mutedMediaRef.current.has(el)) {

        mutedMediaRef.current.set(el, { muted: el.muted, volume: el.volume });

      }

      try {el.pause();} catch (e) { console.error(e); }

      el.muted = true;

      el.volume = 0;

    }



    const previousMutedMedia = new Map(mutedMediaRef.current);

    return () => {

      previousMutedMedia.forEach((prev, el) => {

        el.muted = prev.muted;

        el.volume = prev.volume;

      });

       

      mutedMediaRef.current.clear();

    };

  }, [activeTab]);



  useEffect(() => {

    const prevOverflow = document.body.style.overflow;

    document.body.style.overflow = 'hidden';

    return () => {document.body.style.overflow = prevOverflow;};

  }, []);



  // ΓöÇΓöÇΓöÇ Status bar: black bg + white icons while viewer is open ΓöÇΓöÇΓöÇ

  useEffect(() => {

    const setStatusBar = async (isDark: boolean) => {

      const color = isDark ? '#000000' : '#ffffff';

      const meta = document.querySelector<HTMLMetaElement>('meta[name="theme-color"]');

      if (meta) meta.content = '#000000';

      try {

        const { StatusBar, Style } = await import('@capacitor/status-bar');

        await StatusBar.setStyle({ style: Style.Dark });

        await StatusBar.setBackgroundColor({ color: '#000000' });

      } catch { /* web / plugin not available */ }

      return color;

    };



    let prevMetaColor = '';

    const meta = document.querySelector<HTMLMetaElement>('meta[name="theme-color"]');

    if (meta) prevMetaColor = meta.content;



    void setStatusBar(true);



    return () => {

      // Restore previous status bar based on current theme

      const isDark = document.documentElement.classList.contains('dark');

      const restoreColor = isDark ? '#000000' : '#ffffff';

      const metaEl = document.querySelector<HTMLMetaElement>('meta[name="theme-color"]');

      if (metaEl) metaEl.content = prevMetaColor || restoreColor;

      import('@capacitor/status-bar').then(({ StatusBar, Style }) => {

        void StatusBar.setStyle({ style: isDark ? Style.Dark : Style.Light });

        void StatusBar.setBackgroundColor({ color: restoreColor });

      }).catch(() => { /* ignore */ });

    };

  }, []);



  const smoothNavigate = useCallback((direction: 'up' | 'down') => {

    if (isTransitioning) return;

    const idx = activeTab === 'posts' ? postIndex : shortIndex;

    const count = activeTab === 'posts' ? posts.length : shorts.length;

    const canGo = direction === 'down' ? idx < count - 1 : idx > 0;

    if (!canGo) return;



    setIsTransitioning(true);

    setSlideDirection(direction);



    // Wait for exit animation (Exactly 200ms as per legacy FullScreenViewer)

    setTimeout(() => {

      requestAnimationFrame(() => {

        if (activeTab === 'posts') {

          setPostIndex((prev) => direction === 'down' ? prev + 1 : prev - 1);

        } else {

          setShortIndex((prev) => direction === 'down' ? prev + 1 : prev - 1);

        }

        

        // Wait for enter animation (Exactly 300ms as per legacy FullScreenViewer)

        setTimeout(() => {

          setSlideDirection(null);

          setIsTransitioning(false);

        }, 300);

      });

    }, 200);

  }, [isTransitioning, activeTab, postIndex, shortIndex, posts.length, shorts.length]);



  useEffect(() => {

    const container = containerRef.current;

    if (!container) return;

    let isScrolling = false;

    let timeout: ReturnType<typeof setTimeout> | undefined;



    const handleWheel = (e: WheelEvent) => {

      e.preventDefault();

      if (isScrolling || isTransitioning) return;

      if (Math.abs(e.deltaY) > 20) {

        isScrolling = true;

        smoothNavigate(e.deltaY > 0 ? 'down' : 'up');

        timeout = setTimeout(() => {isScrolling = false;}, 400);

      }

    };



    container.addEventListener('wheel', handleWheel, { passive: false });

    return () => {

      container.removeEventListener('wheel', handleWheel);

      if (timeout) clearTimeout(timeout);

    };

  }, [smoothNavigate, isTransitioning]);



  const handleShortsTap = useCallback(() => {

    setShortsPlaying((p) => {

      const next = !p;

      sendYouTubeCommand(next ? 'playVideo' : 'pauseVideo');

      setShowPlayIndicator(true);

      if (playIndicatorTimeout.current) clearTimeout(playIndicatorTimeout.current);

      playIndicatorTimeout.current = setTimeout(() => setShowPlayIndicator(false), 800);

      return next;

    });

  }, [sendYouTubeCommand]);



  const handleMouseDown = (e: React.MouseEvent) => {

    ensureAmbientPlayback();

    mouseDownRef.current = true;

    mouseStartY.current = e.clientY;

    mouseStartX.current = e.clientX;

  };



  const handleMouseUp = (e: React.MouseEvent) => {

    if (!mouseDownRef.current) return;

    mouseDownRef.current = false;



    const diffY = mouseStartY.current - e.clientY;

    const diffX = mouseStartX.current - e.clientX;



    // Tap detection for mouse

    if (Math.abs(diffY) < 5 && Math.abs(diffX) < 5) {

      if (activeTab === 'shorts') {

        handleShortsTap();

        return;

      }

    }



    const threshold = 60;

    if (Math.abs(diffY) > Math.abs(diffX) && Math.abs(diffY) > threshold) {

      smoothNavigate(diffY > 0 ? 'down' : 'up');

    } else if (Math.abs(diffX) > Math.abs(diffY) && Math.abs(diffX) > threshold) {

      smoothNavigate(diffX > 0 ? 'down' : 'up');

    }

  };



  const handleMediaClick = (e: React.MouseEvent) => {

    if (activeTab === 'shorts') return;

    if (touchMoved.current) return;



    const t = e.target as HTMLElement | null;

    if (t?.closest('button')) return;



    const now = Date.now();

    const DOUBLE_TAP_DELAY = 300;



    // Double tap => like + heart burst

    if (now - lastTapRef.current < DOUBLE_TAP_DELAY) {

      if (singleTapTimerRef.current) {

        clearTimeout(singleTapTimerRef.current);

        singleTapTimerRef.current = null;

      }

      lastTapRef.current = 0;



      const anims = ['animate-heartBurst', 'animate-likePop', 'animate-likeSwing', 'animate-likeFloat', 'animate-likePulse'];

      setHeartAnimClass(anims[Math.floor(Math.random() * anims.length)]);

      setShowDoubleTapHeart(true);

      if (!isLiked) toggleLike();

      setTimeout(() => setShowDoubleTapHeart(false), 900);

      return;

    }



    // Single tap (delayed) => toggle play for video

    lastTapRef.current = now;

    if (singleTapTimerRef.current) clearTimeout(singleTapTimerRef.current);

    singleTapTimerRef.current = setTimeout(() => {

      if (lastTapRef.current === 0) return;

      lastTapRef.current = 0;

      if (isVideo(currentMediaUrl)) setIsPlaying((p) => !p);

    }, DOUBLE_TAP_DELAY + 40);

  };



  const handleTabSwitch = (tab: TabType) => {

    if (tab === activeTab) return;

    stopActiveAudio(audioKey || undefined);

    stopAudio();

    setActiveTab(tab);

    setCurrentMediaIndex(0);



    // Reset to first item when switching to shorts

    if (tab === 'shorts') {

      let nextIndex = 0;

      try {

        const lastId = localStorage.getItem('yt_shorts_last_id');

        if (lastId) {

        const idx = shorts.findIndex((s) => s.id === lastId);

        if (idx >= 0) nextIndex = idx;

      }

    } catch (e) { console.error(e); }

      setShortIndex(nextIndex);

    }

  };



  // Preload next short thumbnails

  useEffect(() => {

    if (activeTab !== 'shorts') return;

    const preloadCount = 3;

    for (let i = shortIndex + 1; i <= shortIndex + preloadCount && i < shorts.length; i++) {

      const img = new Image();

      img.src = shorts[i].thumbnail;

    }

  }, [shortIndex, activeTab, shorts]);



  // Preload upcoming shorts iframes by keeping adjacent ones in DOM

  const PRELOAD_COUNT = 2;

  const preloadRange = Array.from(

    { length: PRELOAD_COUNT * 2 + 1 },

    (_, i) => shortIndex - PRELOAD_COUNT + i

  ).filter((i) => i >= 0 && i < shorts.length);



  const renderShort = () => {

    if (!currentShort) {

      return (

        <div className="flex-1 flex items-center justify-center text-white/50 text-sm">

          Shorts topilmadi

        </div>);

    }

    return (

      <div className={cn(

        "flex-1 flex flex-col relative overflow-visible z-[1] w-full",

        "pt-[calc(env(safe-area-inset-top,10px)+44px)] bg-black"

      )}

      key={currentShort.id}

      onClick={(e) => {

        if (Date.now() - lastShortsTouchTapTs.current < 450) return;

        const t = e.target as HTMLElement | null;

        if (t?.closest('button') || t?.closest('a') || t?.tagName.toLowerCase() === 'iframe') return;

        handleShortsTap();

      }}>

        <div className="relative w-full flex-1 min-h-0 z-[9999]" style={{ maxHeight: 'calc(100% - 120px)' }}>

          {!isShortIframeReady &&

          <div className="absolute inset-0 flex items-center justify-center bg-black">

            <Loader2 className="h-7 w-7 text-white animate-spin" />

          </div>

          }

          {/* Render current + adjacent iframes for instant switching */}

          {preloadRange.map((idx) => {

            const s = shorts[idx];

            if (!s) return null;

            const isCurrent = idx === shortIndex;

            return (

              <iframe

                key={s.id}

                ref={isCurrent ? shortsIframeRef : undefined}

                src={`https://www.youtube.com/embed/${s.id}?rel=0&autoplay=${isCurrent ? '1' : '0'}&controls=1&modestbranding=1&playsinline=1&loop=1&playlist=${s.id}&iv_load_policy=3&fs=0&enablejsapi=1&origin=${encodeURIComponent(ytOrigin)}`}

                className={cn(

                  "absolute inset-0 w-full h-full transition-opacity duration-150",

                  isCurrent ? "opacity-100 z-[2]" : "opacity-0 z-[1]"

                )}

                onLoad={isCurrent ? () => setIsShortIframeReady(true) : undefined}

                allow="autoplay; encrypted-media"

                allowFullScreen

                title={s.title} />);

          })}

        </div>

        <div className="w-full shrink-0 flex flex-col gap-3 px-4 pt-3 pb-[env(safe-area-inset-bottom,16px)] z-10">

          <div className="flex items-start justify-between gap-3">

            <div className="flex-1 min-w-0">

              <p className="text-[13px] font-medium text-white leading-snug line-clamp-2">

                {currentShort.title}

              </p>

              <p className="text-[11px] text-white/50 mt-1">{currentShort.channelTitle}</p>

            </div>

            <div className="shrink-0 flex items-center gap-2">

              <a

                href={`https://www.youtube.com/shorts/${currentShort.id}`}

                target="_blank"

                rel="noreferrer"

                onClick={(e) => e.stopPropagation()}

                className="p-2.5 rounded-full bg-white/10 hover:bg-white/15 transition-colors flex items-center justify-center"

                title="YouTube da ochish">

                <svg viewBox="0 0 24 24" className="w-5 h-5 text-red-500 fill-current">

                  <path d="M23.498 6.186a3.016 3.016 0 0 0-2.122-2.136C19.505 3.545 12 3.545 12 3.545s-7.505 0-9.377.505A3.017 3.017 0 0 0 .502 6.186C0 8.07 0 12 0 12s0 3.93.502 5.814a3.016 3.016 0 0 0 2.122 2.136c1.871.505 9.376.505 9.376.505s7.505 0 9.377-.505a3.015 3.015 0 0 0 2.122-2.136C24 15.93 24 12 24 12s0-3.93-.502-5.814z" />

                  <path d="M9.545 15.568V8.432L15.818 12l-6.273 3.568z" className="fill-white" />

                </svg>

              </a>

              <button

                type="button"

                onClick={(e) => {

                  e.stopPropagation();

                  setShowShortShare(true);

                }}

                className="p-2.5 rounded-full bg-white/10 hover:bg-white/15 transition-colors">

                <Send className="h-5 w-5 text-white" />

              </button>

            </div>

          </div>

        </div>

        <ShareDialog

          open={showShortShare}

          onOpenChange={setShowShortShare}

          shortId={currentShort.id} />

      </div>);



  };



  // ΓöÇΓöÇΓöÇ RENDER: Posts tab ΓöÇΓöÇΓöÇ

  const renderPost = () => {

    if (!currentPost) return null;

    return (

      <>

        <div

          className={cn(

            "flex-1 flex items-center justify-center relative overflow-hidden z-[1] transition-all duration-300 ease-out",

            slideDirection === 'down' && "animate-slide-out-up",

            slideDirection === 'up' && "animate-slide-out-down",

            !slideDirection && "animate-slide-in"

          )}

          key={currentPost.id}

          style={{ touchAction: 'none' }}

          onClick={handleMediaClick}>



          {/* Touch-intercepting overlay for posts to match shorts behavior */}

          <div

            className="absolute inset-0 z-[3]"

            style={{ touchAction: 'pan-y', background: 'transparent' }}

            onTouchStart={(e) => {

              ensureAmbientPlayback();

              touchMoved.current = false;

              touchStartY.current = e.touches[0].clientY;

              touchStartX.current = e.touches[0].clientX;

              touchStartTime.current = Date.now();

            }}

            onTouchMove={(e) => {

              const diffY = Math.abs(touchStartY.current - e.touches[0].clientY);

              const diffX = Math.abs(touchStartX.current - e.touches[0].clientX);

              if (diffY > 8 || diffX > 8) touchMoved.current = true;

            }}

            onTouchEnd={(e) => {

              const diffY = touchStartY.current - e.changedTouches[0].clientY;

              const diffX = touchStartX.current - e.changedTouches[0].clientX;

              const elapsed = Date.now() - touchStartTime.current;

              const velocityY = Math.abs(diffY) / Math.max(elapsed, 1);

              const threshold = velocityY > 0.25 ? 16 : 34;



              if (Math.abs(diffY) > Math.abs(diffX) && Math.abs(diffY) > threshold) {

                smoothNavigate(diffY > 0 ? 'down' : 'up');

              } else if (Math.abs(diffX) > 50) {

                smoothNavigate(diffX > 0 ? 'down' : 'up');

              }

            }}

          />



          {isVideo(currentMediaUrl) ?

          <>

              <video ref={videoRef} src={currentMediaUrl} className="max-w-full max-h-full object-contain" loop playsInline autoPlay />

              <div className="absolute inset-0 flex items-center justify-center pointer-events-none">

                <div className={cn("p-4 rounded-full bg-black/30 backdrop-blur-sm transition-opacity", isPlaying ? "opacity-0" : "opacity-100")}>

                  {isPlaying ? <Pause className="h-8 w-8 text-white" /> : <Play className="h-8 w-8 text-white" />}

                </div>

              </div>

            </> :

          <img src={currentMediaUrl} alt="Post media" className="max-w-full max-h-full object-contain" />

          }

          {/* Live animated GIF overlays ΓÇö displayed on top of media (Instagram-style) */}
          {currentPost.media_metadata?.[currentMediaIndex]?.gifOverlays?.map(gif => (
            <img
              key={gif.id}
              src={(gif as any).originalUrl || gif.url}
              alt="gif sticker"
              loading="lazy"
              className="absolute pointer-events-none select-none"
              style={{
                left: `${gif.x}%`,
                top: `${gif.y}%`,
                transform: `translate(-50%, -50%) scale(${gif.scale}) rotate(${gif.rotation}deg)`,
                width: '28%',
                maxWidth: '160px',
                zIndex: 20,
              }}
            />
          ))}

          {showDoubleTapHeart &&

          <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-20">

              <Heart className={cn("h-28 w-28 text-[#ff2d55] fill-[#ff2d55] drop-shadow-2xl", heartAnimClass)} />

            </div>

          }



          {currentPost.audio_url && (

            <div className="absolute bottom-6 right-4 z-30" onClick={(e) => e.stopPropagation()}>

              <MusicOverlay

                audioTitle={currentPost.audio_title}

                audioArtist={currentPost.audio_artist}

                isPlaying={isAudioPlaying}

                isSaved={isSaved(currentPost.audio_url)}

                onTogglePlay={toggleAudio}

                onToggleSave={() => {

                  if (!currentPost.audio_url) return;

                  if (isSaved(currentPost.audio_url)) {

                    void unsave(currentPost.audio_url);

                  } else {

                    void save({

                      audio_url: currentPost.audio_url,

                      audio_title: currentPost.audio_title,

                      audio_artist: currentPost.audio_artist,

                    });

                  }

                }}

              />



              <audio

                ref={audioRef}

                preload="none"

                onPlay={() => setIsAudioPlaying(true)}

                onPause={() => setIsAudioPlaying(false)}

                onEnded={() => setIsAudioPlaying(false)}

                className="absolute left-0 top-0 h-px w-px opacity-0 pointer-events-none"

              />

            </div>

          )}

          {mediaUrls.length > 1 &&

          <>

              <div className="absolute bottom-20 left-1/2 -translate-x-1/2 flex gap-1.5">

                {mediaUrls.map((_, i) =>

              <button key={i} onClick={(e) => {e.stopPropagation();setCurrentMediaIndex(i);}}

              className={cn("w-1.5 h-1.5 rounded-full transition-colors", currentMediaIndex === i ? "bg-white" : "bg-white/30")} />

              )}

              </div>

              {currentMediaIndex > 0 &&

            <button onClick={(e) => {e.stopPropagation();setCurrentMediaIndex((p) => p - 1);}}

            className="absolute left-2 top-1/2 -translate-y-1/2 p-1.5 bg-black/20 backdrop-blur-sm rounded-full">

                  <ChevronLeft className="h-4 w-4 text-white" />

                </button>

            }

              {currentMediaIndex < mediaUrls.length - 1 &&

            <button onClick={(e) => {e.stopPropagation();setCurrentMediaIndex((p) => p + 1);}}

            className="absolute right-2 top-1/2 -translate-y-1/2 p-1.5 bg-black/20 backdrop-blur-sm rounded-full">

                  <ChevronRight className="h-4 w-4 text-white" />

                </button>

            }

            </>

          }

        </div>



        {/* Actions */}

        <div className="absolute right-3 bottom-24 z-[2]">

          <FullscreenActions

            postId={currentPost.id}

            initialLikesCount={currentPost.likes_count}

            initialCommentsCount={currentPost.comments_count}

            initialViewsCount={currentPost.views_count ?? 0}

            videoUrl={isVideo(currentMediaUrl) ? currentMediaUrl : undefined}

            onOpenVideoPlayer={(url) => {

              setVideoPlayerSrc(url);

              setShowVideoPlayer(true);

              if (videoRef.current) videoRef.current.pause();

              setIsPlaying(false);

              stopActiveAudio(audioKey || undefined);

              stopAudio();

            }} />



        </div>



        {/* Author info */}

        <div className="absolute bottom-14 left-0 right-14 p-4 z-[1]" style={{ background: 'linear-gradient(to top, rgba(0,0,0,0.75) 0%, rgba(0,0,0,0.4) 60%, transparent 100%)', paddingTop: '3rem' }}>

          <div className="flex items-center mb-2 gap-2">

            <UserAvatar

              userId={currentPost.user_id}

              avatarUrl={currentPost.author?.avatar_url}

              name={currentPost.author?.full_name}

              size="lg"

              className="border-2 border-white/20 ring-0"

              hasStory={!!getStoryInfo(currentPost.user_id)}

              storyRingId={getStoryInfo(currentPost.user_id)?.ring_id}

              hasUnviewedStory={getStoryInfo(currentPost.user_id)?.has_unviewed}

              onStoryClick={() => openStoriesForUser(currentPost.user_id)} />



            <UserInfo userId={currentPost.user_id} name={currentPost.author?.full_name} username={currentPost.author?.username} variant="fullscreen" />

            <FollowButton targetUserId={currentPost.user_id} size="sm" variant="fullscreen" />

          </div>

          {activeTab === 'posts' && locationTextShort && mapUrl && (

            <a

              href={mapUrl}

              target="_blank"

              rel="noreferrer"

              className="inline-flex items-center gap-1 text-xs text-white/70 font-medium uppercase max-w-[80%] hover:text-white transition-colors"

              title={locationText}

            >

              <Icon icon="gis:location-poi" className="h-3.5 w-3.5 flex-shrink-0" />

              <span className="truncate">{locationTextShort}</span>

            </a>

          )}



          {postContentWithoutLocation && <PostCaption content={postContentWithoutLocation} variant="fullscreen" />}

        </div>

      </>);

  };



  const fetchStoryGroupForUser = useCallback(async (targetUserId: string): Promise<StoryGroup | null> => {

    try {

      const { data: stories, error } = await supabase.

      from('stories').

      select('*').

      eq('user_id', targetUserId).

      gt('expires_at', new Date().toISOString()).

      order('created_at', { ascending: true });



      if (error) throw error;

      if (!stories || stories.length === 0) return null;



      const { data: profiles } = await supabase.

      from('profiles').

      select('id, name, username, avatar_url').

      in('id', [targetUserId]);



      const authorProfile = profiles?.find((p) => p.id === targetUserId);

      const viewerId = user?.id;



      const [viewsRes, likesRes] = await Promise.all([

      viewerId ?

      supabase.from('story_views').select('story_id').eq('viewer_id', viewerId).in('story_id', stories.map((s) => s.id)) :

      Promise.resolve({ data: [] as Record<string, unknown>[] }),

      viewerId ?

      supabase.from('story_likes').select('story_id').eq('user_id', viewerId).in('story_id', stories.map((s) => s.id)) :

      Promise.resolve({ data: [] as Record<string, unknown>[] })]

      );



      const viewsResData = viewsRes && 'data' in viewsRes ? (viewsRes.data as { story_id: string }[]) : [];

      const likesResData = likesRes && 'data' in likesRes ? (likesRes.data as { story_id: string }[]) : [];



      const viewedStoryIds = new Set(viewsResData?.map(v => v.story_id) || []);

      const likedStoryIds = new Set(likesResData?.map(l => l.story_id) || []);



      const normalizedStories = stories.map((s: Record<string, unknown>) => ({

        ...s,

        media_type: s.media_type as 'image' | 'video',

        ring_id: (s.ring_id as string) || 'default',

        author: authorProfile ? {

          id: authorProfile.id,

          name: authorProfile.name || '',

          username: authorProfile.username || '',

          avatar_url: authorProfile.avatar_url || ''

        } : undefined,

        has_viewed: viewerId ? viewedStoryIds.has(s.id as string) : false,

        has_liked: viewerId ? likedStoryIds.has(s.id as string) : false

      } as unknown as Story));



      return {

        user_id: targetUserId,

        user: authorProfile || { id: targetUserId, name: null, username: null, avatar_url: null },

        stories: normalizedStories,

        has_unviewed: normalizedStories.some((s) => !s.has_viewed)

      };

    } catch (err) {

      console.error('Error fetching user stories:', err);

      return null;

    }

  }, [user?.id]);



  const openStoriesForUser = useCallback(async (targetUserId: string) => {

    const g = await fetchStoryGroupForUser(targetUserId);

    if (!g) return;

    setStoryViewerGroups([g]);

    setStoryViewerOpen(true);

  }, [fetchStoryGroupForUser]);



  useEffect(() => {

    return () => {

      stopActiveAudio(audioKey || undefined);

      stopAudio();

    };

  }, [audioKey, stopAudio]);



  return (

    <>

      <div

        ref={containerRef}

        className="fixed inset-0 z-[60] flex flex-col overflow-hidden touch-none"

        style={{

          backgroundColor: '#000',

          ...bgStyle

        }}

        onMouseDown={handleMouseDown}

        onMouseUp={handleMouseUp}

        onTouchStart={(e) => {

          ensureAmbientPlayback();

          touchMoved.current = false;

          touchStartY.current = e.touches[0].clientY;

          touchStartX.current = e.touches[0].clientX;

          touchStartTime.current = Date.now();

        }}

        onTouchMove={(e) => {

          const diffY = Math.abs(touchStartY.current - e.touches[0].clientY);

          const diffX = Math.abs(touchStartX.current - e.touches[0].clientX);

          if (diffY > 8 || diffX > 8) touchMoved.current = true;

        }}

        onTouchEnd={(e) => {

          const diffY = touchStartY.current - e.changedTouches[0].clientY;

          const diffX = touchStartX.current - e.changedTouches[0].clientX;

          const elapsed = Date.now() - touchStartTime.current;

          const velocityY = Math.abs(diffY) / Math.max(elapsed, 1);

          // If swiping on shorts, we prefer the internal YT overlay's own logic?

          // No, actually, the global handler is fine too.

          // Just make sure it doesn't duplicate if shorts internal overlay is still there.

          // Lower threshold for faster swipes ΓÇö feels more responsive

          const threshold = velocityY > 0.25 ? 16 : 34;



          if (Math.abs(diffY) > Math.abs(diffX) && Math.abs(diffY) > threshold) {

            smoothNavigate(diffY > 0 ? 'down' : 'up');

          } else if (Math.abs(diffX) > 50) {

            // Horizontal swipe mapping as per legacy FullScreenViewer

            smoothNavigate(diffX > 0 ? 'down' : 'up');

          }

        }}>



        {ambientUrl &&

        <div className="absolute inset-0 z-0 overflow-hidden pointer-events-none">

            <div className="absolute inset-0">

              {activeTab === 'posts' && isVideo(ambientUrl) ?

            <video

              key={ambientUrl}

              ref={ambientVideoRef}

              src={ambientUrl}

              className="absolute inset-0 w-full h-full object-cover"

              style={{

                filter: 'blur(16px) saturate(145%) brightness(0.92) contrast(1.05)',

                transform: 'scale(1.08)',

                opacity: 0.72

              }}

              muted

              playsInline

              autoPlay

              loop

              preload="metadata"

              controls={false}

              disablePictureInPicture /> :





            <img

              key={ambientUrl}

              src={ambientUrl}

              alt=""

              className="absolute inset-0 w-full h-full object-cover"

              style={{

                filter: 'blur(16px) saturate(145%) brightness(0.92) contrast(1.05)',

                transform: 'scale(1.08)',

                opacity: 0.72

              }} />



            }



              <div className="absolute inset-0 bg-black/28" />

              <div className="absolute inset-0 bg-gradient-to-b from-black/45 via-transparent to-black/55" />

              <div

              className="absolute inset-[-10%]"

              style={{

                background:

                'radial-gradient(ellipse at center, rgba(0,0,0,0.06) 0%, rgba(0,0,0,0.38) 58%, rgba(0,0,0,0.72) 100%)'

              }} />

            

            </div>

          </div>

        }



        {activeTab === 'posts' && dominantColor &&

        <div className="absolute inset-0 z-0" style={{

          background: `radial-gradient(ellipse at center, transparent 0%, ${dominantColor} 70%)`,

          backdropFilter: 'blur(20px)'

        }} />

        }



        {/* Top bar with tabs */}

        <div className="absolute top-0 left-0 right-0 z-10 flex items-center justify-between px-3 pt-[env(safe-area-inset-top,10px)] pb-2 bg-black/60 backdrop-blur-sm">

          <button onClick={handleClose} className="p-1.5 rounded-full bg-white/10 backdrop-blur-md border border-white/10 my-0">

            <X className="w-4 h-4 text-white" />

          </button>



          <div className="flex gap-0.5 bg-white/10 backdrop-blur-md rounded-full p-0.5 border border-white/10 py-[2px] my-0">

            <button

              onClick={() => handleTabSwitch('shorts')}

              className={cn(

                "px-3.5 py-1 rounded-full text-[11px] font-medium transition-all",

                activeTab === 'shorts' ? "bg-white/20 text-white shadow-sm" : "text-white/50 hover:text-white/70"

              )}>

              yt shorts

            </button>

            <button

              onClick={() => handleTabSwitch('posts')}

              className={cn(

                "px-3.5 py-1 rounded-full text-[11px] font-medium transition-all",

                activeTab === 'posts' ? "bg-white/20 text-white shadow-sm" : "text-white/50 hover:text-white/70"

              )}>

              postlar

            </button>

          </div>



          <div className="w-7" />

        </div>



        {/* Content */}

        {activeTab === 'shorts' ? renderShort() : renderPost()}

      </div>



      {typeof document !== 'undefined' && showVideoPlayer && createPortal(

        <div className="fixed inset-0 z-[80] w-full h-full min-h-[100dvh] overflow-hidden bg-black" style={{ height: '100dvh' }}>

          <SamsungUltraVideoPlayer

            src={videoPlayerSrc}

            title={currentPost?.content?.slice(0, 50) || 'Video'}

            onClose={() => setShowVideoPlayer(false)}

            startInFullscreen={true}

          />



        </div>,

        document.body

      )}



      {storyViewerOpen && storyViewerGroups.length > 0 &&

      <StoryViewer

        storyGroups={storyViewerGroups}

        initialGroupIndex={0}

        onClose={() => setStoryViewerOpen(false)} />



      }

    </>);



};

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { Sheet, SheetContent, SheetHeader, SheetTitle } from "@/components/ui/sheet";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Input } from "@/components/ui/input";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { StarUsername } from '@/components/user/StarUsername';
import { toast } from 'sonner';
import { Camera, Users, Megaphone, Crown, UserMinus, UserPlus, Link, Copy, Check, Trash2, Search, RefreshCw } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';

interface GroupMember {
  id: string;
  user_id: string;
  role: string;
  profile?: {
    id: string;
    name: string | null;
    username: string | null;
    avatar_url: string | null;
  };
}

interface GroupInfo {
  id: string;
  name: string;
  description: string | null;
  avatar_url: string | null;
  type: 'group' | 'channel';
  visibility: 'public' | 'private';
  owner_id: string;
  invite_link: string | null;
}

interface GroupSettingsSheetProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  groupInfo: GroupInfo;
  onGroupUpdated: () => void;
}

export const GroupSettingsSheet = ({ open, onOpenChange, groupInfo, onGroupUpdated }: GroupSettingsSheetProps) => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [name, setName] = useState(groupInfo.name);
  const [description, setDescription] = useState(groupInfo.description || '');
  const [avatarUrl, setAvatarUrl] = useState(groupInfo.avatar_url || '');
  const [isUpdating, setIsUpdating] = useState(false);
  const [members, setMembers] = useState<GroupMember[]>([]);
  const [isLoadingMembers, setIsLoadingMembers] = useState(false);
  const [linkCopied, setLinkCopied] = useState(false);
  const [isGeneratingLink, setIsGeneratingLink] = useState(false);
  const [addMemberOpen, setAddMemberOpen] = useState(false);

  const isOwner = groupInfo.owner_id === user?.id;

  useEffect(() => {
    if (open) {
      setName(groupInfo.name);
      setDescription(groupInfo.description || '');
      setAvatarUrl(groupInfo.avatar_url || '');
      fetchMembers();
    }
  }, [open, groupInfo]);

  const fetchMembers = async () => {
    setIsLoadingMembers(true);
    try {
      const { data: membersData } = await supabase
        .from('group_members').select('*').eq('group_id', groupInfo.id);
      if (membersData) {
        const userIds = membersData.map(m => m.user_id);
        const { data: profiles } = await supabase
          .from('profiles').select('id, name, username, avatar_url').in('id', userIds);
        const profileMap = new Map(profiles?.map(p => [p.id, p]) || []);
        setMembers(membersData.map(m => ({ ...m, profile: profileMap.get(m.user_id) })));
      }
    } catch (error) {
      console.error('Error fetching members:', error);
    } finally {
      setIsLoadingMembers(false);
    }
  };

  const handleAvatarUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    try {
      const fileExt = file.name.split('.').pop();
      const filePath = `${groupInfo.id}.${fileExt}`;
      const { error: uploadError } = await supabase.storage.from('group-avatars').upload(filePath, file, { upsert: true });
      if (uploadError) throw uploadError;
      const { data: { publicUrl } } = supabase.storage.from('group-avatars').getPublicUrl(filePath);
      setAvatarUrl(publicUrl);
    } catch (error) {
      toast.error('Rasm yuklanmadi');
    }
  };

  const handleUpdate = async () => {
    if (!name.trim()) { toast.error('Nomni kiriting'); return; }
    setIsUpdating(true);
    try {
      const { error } = await supabase.from('group_chats')
        .update({ name: name.trim(), description: description.trim() || null, avatar_url: avatarUrl || null })
        .eq('id', groupInfo.id);
      if (error) throw error;
      toast.success('Ma\'lumotlar yangilandi');
      onGroupUpdated();
      onOpenChange(false);
    } catch (error) {
      toast.error('Xatolik yuz berdi');
    } finally {
      setIsUpdating(false);
    }
  };

  const handleRemoveMember = async (memberId: string) => {
    try {
      const { error } = await supabase.from('group_members').delete().eq('id', memberId);
      if (error) throw error;
      toast.success('A\'zo o\'chirildi');
      fetchMembers();
      onGroupUpdated();
    } catch { toast.error('Xatolik yuz berdi'); }
  };

  const handleDeleteGroup = async () => {
    if (!confirm(`${groupInfo.type === 'group' ? 'Guruh' : 'Kanal'}ni o'chirishni xohlaysizmi?`)) return;
    try {
      await supabase.from('group_messages').delete().eq('group_id', groupInfo.id);
      await supabase.from('group_members').delete().eq('group_id', groupInfo.id);
      const { error } = await supabase.from('group_chats').delete().eq('id', groupInfo.id);
      if (error) throw error;
      toast.success(`${groupInfo.type === 'group' ? 'Guruh' : 'Kanal'} o'chirildi`);
      navigate('/messages');
    } catch { toast.error('Xatolik yuz berdi'); }
  };

  const handleMembersAdded = async (userIds: string[]) => {
    if (userIds.length === 0) return;
    try {
      const existingIds = members.map(m => m.user_id);
      const newIds = userIds.filter(id => !existingIds.includes(id) && id !== groupInfo.owner_id);
      if (newIds.length === 0) { toast.info('Bu foydalanuvchilar allaqachon a\'zo'); return; }
      const inserts = newIds.map(uid => ({ group_id: groupInfo.id, user_id: uid, role: 'member' }));
      const { error } = await supabase.from('group_members').upsert(inserts as any, { onConflict: 'group_id,user_id' });
      if (error) throw error;
      toast.success(`${newIds.length} ta a'zo qo'shildi`);
      fetchMembers();
      onGroupUpdated();
    } catch (e: any) {
      toast.error(e?.message || 'Xatolik yuz berdi');
    }
    setAddMemberOpen(false);
  };

  const copyInviteLink = async () => {
    if (!groupInfo.invite_link) return;
    const baseUrl = (import.meta as any).env?.VITE_PUBLIC_APP_URL || window.location.origin;
    const fullLink = `${String(baseUrl).replace(/\/$/, '')}/join/${groupInfo.invite_link}`;
    await navigator.clipboard.writeText(fullLink);
    setLinkCopied(true);
    toast.success('Havola nusxalandi');
    setTimeout(() => setLinkCopied(false), 2000);
  };

  const generateInviteLink = async () => {
    if (!isOwner) return;
    if (groupInfo.invite_link) return;
    setIsGeneratingLink(true);
    try {
      const newLink = `${groupInfo.type}_${Date.now().toString(36)}`;
      const { error } = await supabase.from('group_chats').update({ invite_link: newLink }).eq('id', groupInfo.id);
      if (error) throw error;
      toast.success('Havola yaratildi');
      onGroupUpdated();
    } catch (e: any) {
      toast.error(e?.message || 'Xatolik yuz berdi');
    } finally {
      setIsGeneratingLink(false);
    }
  };

  const revokeInviteLink = async () => {
    if (!isOwner) return;
    if (!confirm("Rostdan ham havolani bekor qilmoqchimisiz? Eski havola endi ishlamaydi.")) return;
    setIsGeneratingLink(true);
    try {
      const { error } = await supabase.from('group_chats').update({ invite_link: null }).eq('id', groupInfo.id);
      if (error) throw error;
      toast.success('Havola bekor qilindi');
      onGroupUpdated();
    } catch (e: any) {
      toast.error(e?.message || 'Xatolik yuz berdi');
    } finally {
      setIsGeneratingLink(false);
    }
  };

  const getInitials = (name: string | null | undefined) => {
    if (!name) return 'U';
    return name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);
  };

  // Owner profile
  const [ownerProfile, setOwnerProfile] = useState<{ name: string | null; username: string | null; avatar_url: string | null } | null>(null);
  useEffect(() => {
    if (open && groupInfo.owner_id) {
      supabase.from('profiles').select('name, username, avatar_url').eq('id', groupInfo.owner_id).single()
        .then(({ data }) => { if (data) setOwnerProfile(data); });
    }
  }, [open, groupInfo.owner_id]);

  return (
    <>
      <Sheet open={open} onOpenChange={onOpenChange}>
        <SheetContent side="right" className="w-full sm:max-w-md p-0">
          <SheetHeader className="p-4 border-b border-border/50">
            <SheetTitle className="text-lg">
              {groupInfo.type === 'group' ? 'Guruh sozlamalari' : 'Kanal sozlamalari'}
            </SheetTitle>
          </SheetHeader>

          <ScrollArea className="h-[calc(100vh-80px)]">
            <div className="p-5 space-y-6">
              {/* Avatar */}
              <div className="flex flex-col items-center gap-3">
                <div className="relative">
                  <Avatar className="h-24 w-24 ring-2 ring-primary/20">
                    <AvatarImage src={avatarUrl} />
                    <AvatarFallback className="text-2xl bg-gradient-to-br from-primary/30 to-primary/10">
                      {groupInfo.type === 'group' ? <Users className="h-10 w-10 text-primary" /> : <Megaphone className="h-10 w-10 text-primary" />}
                    </AvatarFallback>
                  </Avatar>
                  {isOwner && (
                    <label className="absolute bottom-0 right-0 p-2 bg-primary text-primary-foreground rounded-full cursor-pointer hover:bg-primary/90 shadow-lg">
                      <Camera className="h-4 w-4" />
                      <input type="file" accept="image/*" className="hidden" onChange={handleAvatarUpload} />
                    </label>
                  )}
                </div>
              </div>

              {/* Editable fields */}
              {isOwner ? (
                <div className="space-y-4">
                  <div>
                    <Label className="text-xs text-muted-foreground mb-1.5 block">Nomi</Label>
                    <Input value={name} onChange={(e) => setName(e.target.value)}
                      placeholder={groupInfo.type === 'group' ? 'Guruh nomi' : 'Kanal nomi'}
                      className="rounded-xl bg-card/50 border-border/50" />
                  </div>
                  <div>
                    <Label className="text-xs text-muted-foreground mb-1.5 block">Tavsif</Label>
                    <Textarea value={description} onChange={(e) => setDescription(e.target.value)}
                      placeholder="Qisqacha tavsif..." rows={3}
                      className="rounded-xl bg-card/50 border-border/50 resize-none" />
                  </div>
                  <Button onClick={handleUpdate} disabled={isUpdating}
                    className="w-full rounded-xl bg-gradient-to-r from-[hsl(217,91%,60%)] to-[hsl(263,70%,50%)] text-white hover:opacity-90">
                    {isUpdating ? 'Saqlanmoqda...' : 'Saqlash'}
                  </Button>
                </div>
              ) : (
                <div className="space-y-1 text-center">
                  <h3 className="font-semibold text-lg">{groupInfo.name}</h3>
                  {groupInfo.description && <p className="text-sm text-muted-foreground">{groupInfo.description}</p>}
                </div>
              )}

              {/* Invite Link */}
              {(groupInfo.invite_link || isOwner) && (
                <div className="p-3 bg-card/50 border border-border/30 rounded-xl">
                  <div className="flex items-center gap-2 mb-2">
                    <Link className="h-4 w-4 text-muted-foreground" />
                    <span className="text-sm font-medium">Taklif havolasi</span>
                  </div>
                  {groupInfo.invite_link ? (
                    <div className="flex items-center gap-2 min-w-0">
                      <code className="text-xs bg-muted/50 p-2 rounded-lg truncate block whitespace-nowrap min-w-0" style={{ maxWidth: 'calc(100vw - 100px)' }}>{window.location.origin}/join/{groupInfo.invite_link}</code>
                      <Button variant="ghost" size="icon" onClick={copyInviteLink} className="h-8 w-8 rounded-lg shrink-0">
                        {linkCopied ? <Check className="h-4 w-4 text-green-500" /> : <Copy className="h-4 w-4" />}
                      </Button>
                      {isOwner && (
                        <Button variant="ghost" size="icon" onClick={revokeInviteLink} disabled={isGeneratingLink} className="h-8 w-8 rounded-lg shrink-0 text-destructive hover:bg-destructive/10 hover:text-destructive">
                          <RefreshCw className="h-4 w-4" />
                        </Button>
                      )}
                    </div>
                  ) : (
                    <Button
                      onClick={generateInviteLink}
                      disabled={isGeneratingLink}
                      className="w-full h-10 rounded-xl bg-primary/10 text-primary hover:bg-primary/15"
                      variant="ghost"
                    >
                      {isGeneratingLink ? 'Yaratilmoqda...' : 'Taklif havolasi yaratish'}
                    </Button>
                  )}
                </div>
              )}

              {/* Members */}
              <div>
                <div className="flex items-center justify-between mb-3">
                  <h3 className="font-semibold">A'zolar</h3>
                  {isOwner && (
                    <Button variant="outline" size="sm" onClick={() => setAddMemberOpen(true)}
                      className="rounded-xl gap-1.5 text-xs h-8 border-primary/30 text-primary hover:bg-primary/10">
                      <UserPlus className="h-3.5 w-3.5" />
                      Qo'shish
                    </Button>
                  )}
                </div>
                <div className="space-y-1">
                  {/* Owner */}
                  <div className="flex items-center gap-3 p-2.5 rounded-xl bg-primary/5 border border-primary/10">
                    <Avatar className="h-10 w-10">
                      <AvatarImage src={ownerProfile?.avatar_url || undefined} />
                      <AvatarFallback className="bg-gradient-to-br from-yellow-400/30 to-yellow-600/20">
                        <Crown className="h-4 w-4 text-yellow-500" />
                      </AvatarFallback>
                    </Avatar>
                    <div className="flex-1">
                      <p className="font-medium text-sm">{ownerProfile?.name || 'Egasi'}</p>
                      <p className="text-xs text-muted-foreground">
                        {user?.id === groupInfo.owner_id ? 'Siz ┬╖ Egasi' : 'Egasi'}
                      </p>
                    </div>
                  </div>

                  {isLoadingMembers ? (
                    <p className="text-sm text-muted-foreground text-center py-4">Yuklanmoqda...</p>
                  ) : members.length === 0 ? (
                    <p className="text-sm text-muted-foreground text-center py-4">Boshqa a'zolar yo'q</p>
                  ) : (
                    members.map((member) => (
                      <div key={member.id} className="flex items-center gap-3 p-2.5 rounded-xl hover:bg-muted/50 transition-colors">
                        <Avatar className="h-10 w-10">
                          <AvatarImage src={member.profile?.avatar_url || undefined} />
                          <AvatarFallback className="text-xs">{getInitials(member.profile?.name)}</AvatarFallback>
                        </Avatar>
                        <div className="flex-1 min-w-0">
                          <p className="font-medium text-sm truncate">{member.profile?.name || 'Foydalanuvchi'}</p>
                          <div className="truncate">
                            <StarUsername username={member.profile?.username || 'username'} />
                          </div>
                        </div>
                        {isOwner && (
                          <Button variant="ghost" size="icon" className="text-destructive h-8 w-8 rounded-lg"
                            onClick={() => handleRemoveMember(member.id)}>
                            <UserMinus className="h-4 w-4" />
                          </Button>
                        )}
                      </div>
                    ))
                  )}
                </div>
              </div>

              {/* Delete Group */}
              {isOwner && (
                <div className="pt-4 border-t border-border/50">
                  <Button variant="destructive" className="w-full rounded-xl" onClick={handleDeleteGroup}>
                    <Trash2 className="h-4 w-4 mr-2" />
                    {groupInfo.type === 'group' ? 'Guruhni o\'chirish' : 'Kanalni o\'chirish'}
                  </Button>
                </div>
              )}
            </div>
          </ScrollArea>
        </SheetContent>
      </Sheet>

      <AddMemberInlineDialog
        open={addMemberOpen}
        onOpenChange={setAddMemberOpen}
        onComplete={handleMembersAdded}
        existingMemberIds={[groupInfo.owner_id, ...members.map(m => m.user_id)]}
      />
    </>
  );
};

// Inline Add Member Dialog
interface AddMemberInlineDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onComplete: (userIds: string[]) => void;
  existingMemberIds: string[];
}

const AddMemberInlineDialog = ({ open, onOpenChange, onComplete, existingMemberIds }: AddMemberInlineDialogProps) => {
  const { user } = useAuth();
  const [searchQuery, setSearchQuery] = useState('');
  const [allUsers, setAllUsers] = useState<{ id: string; name: string | null; username: string | null; avatar_url: string | null }[]>([]);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    if (!user?.id || !open) return;
    setIsLoading(true);
    const fetchUsers = async () => {
      try {
        // Get followers + following
        const [{ data: frs }, { data: fng }] = await Promise.all([
          supabase.from('follows').select('follower_id').eq('following_id', user.id),
          supabase.from('follows').select('following_id').eq('follower_id', user.id),
        ]);
        const ids = [...new Set([...(frs || []).map(f => f.follower_id), ...(fng || []).map(f => f.following_id)])];
        const availableIds = ids.filter(id => !existingMemberIds.includes(id));
        if (availableIds.length > 0) {
          const { data: profiles } = await supabase.from('profiles').select('id, name, username, avatar_url').in('id', availableIds);
          setAllUsers(profiles || []);
        } else {
          setAllUsers([]);
        }
      } catch { setAllUsers([]); }
      setIsLoading(false);
    };
    fetchUsers();
  }, [user?.id, open, existingMemberIds]);

  const filteredUsers = allUsers.filter(u => {
    if (!searchQuery) return true;
    const q = searchQuery.toLowerCase();
    return (u.name?.toLowerCase().includes(q)) || (u.username?.toLowerCase().includes(q));
  });

  const toggleUser = (uid: string) => {
    const s = new Set(selectedIds);
    if (s.has(uid)) s.delete(uid); else s.add(uid);
    setSelectedIds(s);
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="w-[calc(100vw-2rem)] max-w-md max-h-[90vh] flex flex-col p-0 overflow-hidden">
        <DialogHeader>
          <DialogTitle className="flex items-center justify-between">
            <span>A'zo qo'shish</span>
            {selectedIds.size > 0 && <span className="text-sm font-normal text-primary">{selectedIds.size} tanlandi</span>}
          </DialogTitle>
        </DialogHeader>
        <div className="relative px-6">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input placeholder="Qidirish..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="pl-10 rounded-xl" />
        </div>
        <ScrollArea className="flex-1 -mx-6 px-6">
          <div className="space-y-1">
            {isLoading ? (
              <p className="text-center py-8 text-muted-foreground text-sm">Yuklanmoqda...</p>
            ) : filteredUsers.length === 0 ? (
              <p className="text-center py-8 text-muted-foreground text-sm">
                {searchQuery ? 'Hech kim topilmadi' : 'Qo\'shish uchun foydalanuvchi yo\'q'}
              </p>
            ) : (
              filteredUsers.map(u => (
                <div key={u.id} onClick={() => toggleUser(u.id)}
                  className="flex items-center gap-3 p-2.5 rounded-xl hover:bg-muted/50 cursor-pointer transition-colors">
                  <Avatar className="h-10 w-10">
                    <AvatarImage src={u.avatar_url || undefined} />
                    <AvatarFallback className="text-xs">{(u.name || 'U')[0]}</AvatarFallback>
                  </Avatar>
                  <div className="flex-1 min-w-0">
                    <p className="font-medium text-sm truncate">{u.name || 'Foydalanuvchi'}</p>
                    <div className="truncate">
                      <StarUsername username={u.username || 'username'} />
                    </div>
                  </div>
                  <Checkbox checked={selectedIds.has(u.id)} onCheckedChange={() => toggleUser(u.id)} />
                </div>
              ))
            )}
          </div>
        </ScrollArea>
        <div className="flex justify-end gap-2 px-6 pb-4 pt-3 border-t border-border/50">
          <Button variant="ghost" onClick={() => { onOpenChange(false); setSelectedIds(new Set()); }} className="rounded-xl">
            Bekor
          </Button>
          <Button onClick={() => { onComplete(Array.from(selectedIds)); setSelectedIds(new Set()); }}
            disabled={selectedIds.size === 0}
            className="rounded-xl bg-gradient-to-r from-[hsl(217,91%,60%)] to-[hsl(263,70%,50%)] text-white">
            Qo'shish ({selectedIds.size})
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
};

