const MSG_GRADIENT = 'from-emerald-500 to-teal-500';

// ΓöÇΓöÇΓöÇ Quick Reply ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const QuickReply = ({
  conversationId,
  onSent,
  onCancel,
}: {
  conversationId: string;
  onSent: () => void;
  onCancel: () => void;
}) => {
  const { user } = useAuth();
  const [text, setText] = useState('');
  const [sending, setSending] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const handleSend = async () => {
    if (!text.trim() || !user?.id || sending) return;
    setSending(true);
    try {
      await supabase.from('messages').insert({
        conversation_id: conversationId,
        sender_id: user.id,
        content: text.trim(),
        status: 'sent',
      });
      onSent();
    } catch (e) {
      console.error(e);
    } finally {
      setSending(false);
    }
  };

  return (
    <motion.div
      initial={{ height: 0, opacity: 0 }}
      animate={{ height: 'auto', opacity: 1 }}
      exit={{ height: 0, opacity: 0 }}
      transition={{ duration: 0.2 }}
      className="overflow-hidden"
    >
      <div className="flex items-center gap-2 px-3.5 pb-3 pt-1">
        <input
          ref={inputRef}
          value={text}
          onChange={(e) => setText(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === 'Enter') handleSend();
            if (e.key === 'Escape') onCancel();
          }}
          placeholder="Javob yozing..."
          className={cn(
            'flex-1 h-9 rounded-full px-3.5 text-sm',
            'bg-white/10 border border-white/15 text-white placeholder:text-white/40',
            'focus:outline-none focus:border-emerald-400/60 transition-colors'
          )}
        />
        <button
          onClick={handleSend}
          disabled={!text.trim() || sending}
          className={cn(
            'h-9 w-9 rounded-full flex items-center justify-center transition-all',
            text.trim()
              ? 'bg-emerald-500 hover:bg-emerald-400 active:scale-95 shadow-md shadow-emerald-500/30'
              : 'bg-white/10 opacity-50'
          )}
        >
          <Send className="h-4 w-4 text-white" />
        </button>
      </div>
    </motion.div>
  );
};

// ΓöÇΓöÇΓöÇ Banner Card ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const BannerCard = ({
  alert,
  onDismiss,
}: {
  alert: AlertData;
  onDismiss: () => void;
}) => {
  const navigate = useNavigate();
  const [showReply, setShowReply] = useState(false);
  const [sent, setSent] = useState(false);

  const y = useMotionValue(0);
  const opacity = useTransform(y, [-60, 0], [0, 1]);

  const isMsg = alert.kind === 'message';
  const config = !isMsg ? (NOTIF_CONFIG[alert.type] ?? NOTIF_CONFIG['message']) : null;
  const gradient = isMsg ? MSG_GRADIENT : (config?.gradient ?? MSG_GRADIENT);

  const actorName = alert.actor.name || alert.actor.username || 'Foydalanuvchi';
  const displayText = isMsg ? alert.text : (config?.label(actorName) ?? alert.text);
  const initials = actorName.split(' ').map(w => w[0]).join('').toUpperCase().slice(0, 2);

  const handleOpen = () => {
    onDismiss();
    if (isMsg && alert.actor.id) {
      navigate(`/chat/${alert.actor.id}`);
    } else {
      switch (alert.type) {
        case 'follow':
        case 'follow_request': navigate(`/user/${alert.actor.id}`); break;
        case 'message':        navigate(`/chat/${alert.actor.id}`); break;
        default:               navigate('/notifications');
      }
    }
  };

  return (
    <motion.div
      drag="y"
      dragConstraints={{ top: -200, bottom: 0 }}
      dragElastic={{ top: 0.5, bottom: 0 }}
      style={{ y, opacity }}
      onDragEnd={(_, info) => {
        if (info.offset.y < -40 || info.velocity.y < -300) onDismiss();
      }}
      className="w-full cursor-grab active:cursor-grabbing select-none"
    >
      <div
        className={cn(
          'rounded-[20px] overflow-hidden',
          'bg-[rgba(20,20,25,0.82)] backdrop-blur-3xl',
          'border border-white/[0.08]',
          'shadow-[0_16px_48px_rgba(0,0,0,0.55)]',
        )}
      >
        {/* Gradient accent line */}
        <div className={cn('h-[2.5px] w-full bg-gradient-to-r', gradient)} />

        {/* Main row */}
        <div className="flex items-center gap-3 px-3.5 pt-3 pb-2.5">
          {/* Avatar + badge */}
          <div className="relative shrink-0">
            <Avatar className="h-11 w-11 border-2 border-white/[0.07] shadow-md">
              <AvatarImage src={alert.actor.avatar_url || undefined} />
              <AvatarFallback className="text-sm font-bold bg-gradient-to-br from-muted/70 to-muted/40 text-white">
                {initials}
              </AvatarFallback>
            </Avatar>
            <div className={cn(
              'absolute -bottom-1 -right-1 h-[20px] w-[20px] rounded-full flex items-center justify-center',
              'shadow-md ring-2 ring-[rgba(20,20,25,0.82)] bg-gradient-to-br', gradient
            )}>
              {isMsg
                ? <MessageSquare className="h-2.5 w-2.5 text-white" />
                : config?.icon
              }
            </div>
          </div>

          {/* Text */}
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-1.5 mb-[2px]">
              <span className="text-[10px] font-bold uppercase tracking-[0.08em] text-white/40">Avlodona</span>
              <span className="text-[10px] text-white/25">ΓÇó</span>
              <span className="text-[10px] text-white/35">hozir</span>
            </div>

            {isMsg ? (
              <>
                <p className="text-[13px] font-semibold text-white/95 leading-tight truncate">{actorName}</p>
                <p className="text-[12px] text-white/55 leading-snug line-clamp-2 mt-[1px]">{displayText}</p>
              </>
            ) : (
              <p className="text-[13px] font-medium text-white/90 leading-snug line-clamp-2">{displayText}</p>
            )}
          </div>

          {/* Right side: thumbnail or type icon */}
          <div className="shrink-0 flex flex-col items-end gap-1.5">
            {alert.mediaThumb ? (
              <div className="h-[44px] w-[44px] rounded-[10px] overflow-hidden border border-white/10">
                <img src={alert.mediaThumb} alt="" className="h-full w-full object-cover" />
              </div>
            ) : (
              <div className={cn(
                'h-[44px] w-[44px] rounded-[10px] flex items-center justify-center',
                'bg-gradient-to-br', gradient, 'opacity-80'
              )}>
                {isMsg
                  ? <MessageSquare className="h-5 w-5 text-white" />
                  : config?.icon && <span className="scale-[1.6]">{config.icon}</span>
                }
              </div>
            )}
          </div>

          {/* Dismiss */}
          <button
            onClick={(e) => { e.stopPropagation(); onDismiss(); }}
            className="shrink-0 h-6 w-6 rounded-full flex items-center justify-center hover:bg-white/10 transition-colors"
          >
            <X className="h-3 w-3 text-white/40" />
          </button>
        </div>

        {/* Action buttons */}
        <div className="flex items-center gap-0 border-t border-white/[0.06]">
          {isMsg && alert.conversationId && !sent && (
            <button
              onClick={() => setShowReply(r => !r)}
              className={cn(
                'flex-1 flex items-center justify-center gap-1.5 py-2.5 text-[12px] font-semibold transition-colors',
                showReply ? 'text-emerald-400' : 'text-white/50 hover:text-white/80'
              )}
            >
              <MessageSquare className="h-3.5 w-3.5" />
              Javob berish
            </button>
          )}
          {sent && (
            <div className="flex-1 flex items-center justify-center gap-1.5 py-2.5 text-[12px] font-semibold text-emerald-400">
              <Check className="h-3.5 w-3.5" />
              Yuborildi
            </div>
          )}
          <div className="w-px h-5 bg-white/[0.06]" />
          <button
            onClick={handleOpen}
            className="flex-1 flex items-center justify-center gap-1.5 py-2.5 text-[12px] font-semibold text-white/50 hover:text-white/80 transition-colors"
          >
            Ochish
            <ArrowRight className="h-3.5 w-3.5" />
          </button>
        </div>

        {/* Quick Reply Input */}
        <AnimatePresence>
          {showReply && alert.conversationId && (
            <QuickReply
              conversationId={alert.conversationId}
              onSent={() => { setSent(true); setShowReply(false); setTimeout(onDismiss, 1200); }}
              onCancel={() => setShowReply(false)}
            />
          )}
        </AnimatePresence>
      </div>
    </motion.div>
  );
};

// ΓöÇΓöÇΓöÇ Main Component ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export const PushNotification = () => {
  const { user } = useAuth();
  const location = useLocation();
  const locationRef = useRef(location.pathname);
  useEffect(() => { locationRef.current = location.pathname; }, [location.pathname]);

  const [alerts, setAlerts] = useState<AlertData[]>([]);
  const timers = useRef<Map<string, ReturnType<typeof setTimeout>>>(new Map());

  const dismiss = useCallback((id: string) => {
    clearTimeout(timers.current.get(id));
    timers.current.delete(id);
    setAlerts(prev => prev.filter(a => a.id !== id));
  }, []);

  const addAlert = useCallback((alert: AlertData) => {
    setAlerts(prev => {
      // Replace same-id or same-sender message (de-dup)
      const filtered = prev.filter(a => a.id !== alert.id && !(a.kind === 'message' && a.actor.id === alert.actor.id));
      return [alert, ...filtered].slice(0, 3); // max 3 stacked
    });
    // Auto-dismiss after 6s
    const t = setTimeout(() => dismiss(alert.id), 6000);
    timers.current.set(alert.id, t);
  }, [dismiss]);

  // Listen to incoming-message custom events
  useEffect(() => {
    const handler = (e: Event) => {
      const ce = e as CustomEvent<{
        id: string;
        conversationId: string;
        sender: ActorProfile;
        preview: string;
        mediaThumb: string | null;
        mediaType: string | null;
      }>;
      const d = ce.detail;

      // Don't show if user is already in this chat
      if (locationRef.current === `/chat/${d.sender.id}`) return;

      addAlert({
        id: d.id,
        kind: 'message',
        type: d.mediaType || 'text',
        actor: d.sender,
        text: d.preview,
        mediaThumb: d.mediaThumb,
        conversationId: d.conversationId,
        created_at: new Date().toISOString(),
      });
    };
    window.addEventListener('avlodona:incoming-message', handler as EventListener);
    return () => window.removeEventListener('avlodona:incoming-message', handler as EventListener);
  }, [addAlert]);

  // Listen to Supabase notifications table
  useEffect(() => {
    if (!user?.id) return;

    const channel = supabase
      .channel('push-notifications-v2')
      .on('postgres_changes', {
        event: 'INSERT',
        schema: 'public',
        table: 'notifications',
        filter: `user_id=eq.${user.id}`,
      }, async (payload) => {
        const raw = payload.new as Record<string, unknown>;

        const { data: actor } = await supabase
          .from('profiles')
          .select('id, name, username, avatar_url')
          .eq('id', raw.actor_id as string)
          .single();

        if (!actor) return;

        let mediaThumb: string | null = null;
        if (raw.post_id) {
          const { data: post } = await supabase.from('posts').select('media_urls').eq('id', raw.post_id as string).single();
          if (post?.media_urls?.[0]) mediaThumb = post.media_urls[0];
        }

        addAlert({
          id: raw.id as string,
          kind: 'notification',
          type: raw.type as string,
          actor: actor as ActorProfile,
          text: '',
          mediaThumb,
          created_at: raw.created_at as string,
        });
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [user?.id, addAlert]);

  useEffect(() => {
    return () => { timers.current.forEach(t => clearTimeout(t)); };
  }, []);

  if (alerts.length === 0) return null;

  return (
    <div className="fixed top-3 left-0 right-0 z-[200] flex justify-center px-4 pointer-events-none">
      <div className="w-full max-w-[390px] flex flex-col gap-2 pointer-events-auto">
        <AnimatePresence mode="popLayout">
          {alerts.map((alert) => (
            <motion.div
              key={alert.id}
              layout
              initial={{ y: -90, opacity: 0, scale: 0.88 }}
              animate={{ y: 0, opacity: 1, scale: 1 }}
              exit={{ y: -90, opacity: 0, scale: 0.88 }}
              transition={{ type: 'spring', damping: 22, stiffness: 320, mass: 0.8 }}
            >
              <BannerCard alert={alert} onDismiss={() => dismiss(alert.id)} />
            </motion.div>
          ))}
        </AnimatePresence>
      </div>
    </div>
  );
};

import { useState, useEffect, useCallback, useRef } from 'react';
import Cropper from 'react-easy-crop';
import { Dialog, DialogContent } from '@/components/ui/dialog';
import { Loader2, X, Image as ImageIcon, Search } from 'lucide-react';
import getCroppedImg from '@/lib/cropImage';
import { Capacitor } from '@capacitor/core';
import { Media } from '@capacitor-community/media';
import { cn } from '@/lib/utils';
import { useLanguage } from '@/contexts/LanguageContext';
import { Icon } from '@iconify/react';
import { useGallery } from '@/hooks/useGallery';

interface InstagramPhotoPickerProps {
  isOpen: boolean;
  onClose: () => void;
  onCropComplete: (croppedImageUrl: string) => Promise<void>;
  type: 'avatar' | 'cover';
  initialImage?: string;
}

export const InstagramPhotoPicker = ({ isOpen, onClose, onCropComplete, type, initialImage }: InstagramPhotoPickerProps) => {
  const { t } = useLanguage();

  // Use unified useGallery hook for reliable Android & iOS gallery media fetching
  const {
    assets,
    permission,
    requestPermission
  } = useGallery({ pageSize: 120 });

  const [localPhotos, setLocalPhotos] = useState<{ id: string; url: string; isVideo?: boolean }[]>([]);
  const [selectedPhoto, setSelectedPhoto] = useState<{ id: string; url: string; isVideo?: boolean } | null>(null);

  const [crop, setCrop] = useState({ x: 0, y: 0 });
  const [zoom, setZoom] = useState(1);
  const [croppedAreaPixels, setCroppedAreaPixels] = useState<{ x: number, y: number, width: number, height: number } | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const [mode, setMode] = useState<'gallery' | 'gif'>('gallery');
  const [gifs, setGifs] = useState<{ id: string; url: string; preview: string }[]>([]);
  const [gifSearchQuery, setGifSearchQuery] = useState('');
  const [isSearchingGif, setIsSearchingGif] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Map hook assets to photopicker items
  const photos = assets.map(asset => ({
    id: asset.identifier,
    url: asset.thumbnail || asset.webUrl
  }));

  const displayPhotos = [...localPhotos, ...photos];

  // Auto clean up and manage state reset on close
  useEffect(() => {
    if (!isOpen) {
      setLocalPhotos([]);
      setSelectedPhoto(null);
      setCrop({ x: 0, y: 0 });
      setZoom(1);
      setGifSearchQuery('');
      setMode('gallery');
    }
  }, [isOpen]);

  // Handle selected photo based on gallery fetch & initialImage
  useEffect(() => {
    if (isOpen) {
      if (initialImage) {
        setSelectedPhoto({ id: 'initial', url: initialImage });
      } else if (displayPhotos.length > 0 && !selectedPhoto) {
        setSelectedPhoto(displayPhotos[0]);
      }
    }
  }, [displayPhotos, initialImage, isOpen]);

  const fetchGifs = async (query = '') => {
    setIsSearchingGif(true);
    try {
      const apiKey = import.meta.env.VITE_GIPHY_API_KEY;
      if (!apiKey) return;
      const endpoint = query 
        ? `https://api.giphy.com/v1/gifs/search?api_key=${apiKey}&q=${encodeURIComponent(query)}&limit=30`
        : `https://api.giphy.com/v1/gifs/trending?api_key=${apiKey}&limit=30`;

      const res = await fetch(endpoint);
      const data = await res.json();

      if (data.data) {
        setGifs(data.data.map((gif: any) => ({
          id: gif.id,
          url: gif.images.original.url,
          preview: gif.images.fixed_width.url
        })));
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsSearchingGif(false);
    }
  };

  useEffect(() => {
    if (mode === 'gif' && gifs.length === 0) {
      fetchGifs();
    }
  }, [mode]);

  useEffect(() => {
    const timeoutId = setTimeout(() => {
      if (mode === 'gif') {
        fetchGifs(gifSearchQuery);
      }
    }, 500);
    return () => clearTimeout(timeoutId);
  }, [gifSearchQuery, mode]);

  const handleFallbackUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;
    const newPhotos = Array.from(e.target.files).map(file => ({
      id: Math.random().toString(),
      url: URL.createObjectURL(file),
      isVideo: file.type.startsWith('video/')
    }));
    setLocalPhotos(prev => [...newPhotos, ...prev]);
    if (newPhotos.length > 0) {
      setSelectedPhoto(newPhotos[0]);
      setCrop({ x: 0, y: 0 });
      setZoom(1);
    }
  };

  const handleConfirm = async () => {
    if (!selectedPhoto) return;

    if (mode === 'gif' || selectedPhoto.isVideo) {
      try {
        setIsLoading(true);
        await onCropComplete(selectedPhoto.url);
        onClose();
      } catch (error) {
        console.error('Bypass error:', error);
      } finally {
        setIsLoading(false);
      }
      return;
    }

    if (!croppedAreaPixels) return;
    try {
      setIsLoading(true);
      const croppedUrl = await getCroppedImg(selectedPhoto.url, croppedAreaPixels, 0);
      await onCropComplete(croppedUrl);
      onClose();
    } catch (error) {
      console.error('Crop error:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const onCropCompleteHandler = useCallback((_croppedArea: any, croppedAreaPixels: any) => {
    setCroppedAreaPixels(croppedAreaPixels);
  }, []);

  return (
    <Dialog open={isOpen} onOpenChange={(open) => !open && onClose()}>
      <DialogContent 
        aria-describedby={undefined}
        className="w-full h-[100dvh] max-w-none flex flex-col p-0 overflow-hidden bg-zinc-950 border-none rounded-none !m-0 !mt-0 !mb-0 !z-[200] sm:max-w-xl sm:h-[92vh] sm:rounded-3xl mx-auto sm:my-auto [&>button]:hidden"
      >
        {/* Modern Instagram-Style Header */}
        <div 
          className="flex items-center justify-between min-h-16 px-4 bg-zinc-950/80 backdrop-blur-xl border-b border-white/[0.04] shrink-0"
          style={{ paddingTop: 'env(safe-area-inset-top, 0px)' }}
        >
          {/* Cancel button */}
          <button 
            type="button"
            onClick={onClose} 
            className="w-10 h-10 rounded-full flex items-center justify-center bg-white/[0.04] hover:bg-white/[0.08] active:scale-90 border border-white/[0.08] transition-all duration-300 shadow-inner"
            aria-label="Yopish"
          >
            <X className="h-4.5 w-4.5 text-white/80" />
          </button>

          {/* Custom Capsule Tab Switcher */}
          <div className="flex bg-black/60 p-0.5 rounded-full items-center border border-white/[0.06] shadow-inner relative">
            <button 
              type="button"
              onClick={() => { 
                setMode('gallery'); 
                if (displayPhotos.length > 0) {
                  setSelectedPhoto(displayPhotos[0]);
                } else if (initialImage) {
                  setSelectedPhoto({ id: 'initial', url: initialImage });
                }
              }}
              className={cn(
                "px-5 py-1.5 rounded-full text-[11px] font-bold transition-all duration-300 relative z-10",
                mode === 'gallery' 
                  ? "bg-white text-zinc-950 shadow-[0_2px_8px_rgba(255,255,255,0.18)]" 
                  : "text-white/45 hover:text-white/80"
              )}
            >
              {t('gallery')}
            </button>
            <button 
              type="button"
              onClick={() => { setMode('gif'); setSelectedPhoto(null); }}
              className={cn(
                "px-5 py-1.5 rounded-full text-[11px] font-bold transition-all duration-300 relative z-10",
                mode === 'gif' 
                  ? "bg-white text-zinc-950 shadow-[0_2px_8px_rgba(255,255,255,0.18)]" 
                  : "text-white/45 hover:text-white/80"
              )}
            >
              {t('gifs')}
            </button>
          </div>

          {/* Save Button (Premium Emerald Glow) */}
          <button 
            type="button"
            onClick={handleConfirm}
            disabled={isLoading || !selectedPhoto}
            className="px-5 py-2 rounded-full bg-gradient-to-r from-emerald-500 to-teal-500 hover:from-emerald-400 hover:to-teal-400 text-black font-extrabold text-[11px] active:scale-95 transition-all duration-300 flex items-center justify-center gap-1.5 border border-emerald-400/30 shadow-[0_0_15px_rgba(16,185,129,0.22)] hover:shadow-[0_0_20px_rgba(16,185,129,0.35)] disabled:opacity-30 disabled:pointer-events-none"
          >
            {isLoading ? (
              <Loader2 className="h-3.5 w-3.5 animate-spin text-black" />
            ) : (
              t('save')
            )}
          </button>
        </div>

        {permission === 'denied' ? (
          <div className="flex-1 flex flex-col items-center justify-center p-6 text-center text-white bg-zinc-900">
            <p className="mb-4 text-white/70 text-sm">{t('givePermissionDesc')}</p>
            <button 
              type="button"
              onClick={requestPermission} 
              className="bg-emerald-500 hover:bg-emerald-600 active:scale-95 text-black font-bold rounded-2xl h-11 px-8 transition-transform"
            >
              {t('allowPermission')}
            </button>
          </div>
        ) : (
          <div className="flex-1 flex flex-col h-[calc(100vh-56px)] overflow-hidden">
            {/* Top Half: Auto-Cropped Circle Preview (aspect-square for perfect 1:1, edge-to-edge) */}
            <div className="relative w-full aspect-square bg-zinc-900 shrink-0 border-b border-white/[0.04]">
              {selectedPhoto ? (
                mode === 'gif' || selectedPhoto.isVideo ? (
                   <div className="w-full h-full flex items-center justify-center p-6">
                     <div className={cn(
                       "relative overflow-hidden bg-black/40 border border-white/10 shadow-2xl flex items-center justify-center",
                       type === 'avatar' ? 'w-[75%] aspect-square rounded-full' : 'w-[90%] aspect-[3/1] rounded-2xl'
                     )}>
                       {selectedPhoto.isVideo ? (
                         <video 
                           src={selectedPhoto.url} 
                           className="w-full h-full object-cover" 
                           autoPlay loop muted playsInline
                         />
                       ) : (
                         <img 
                           src={selectedPhoto.url} 
                           alt="GIF Preview"
                           className="w-full h-full object-cover" 
                         />
                       )}
                     </div>
                   </div>
                ) : (
                  <Cropper
                    image={selectedPhoto.url}
                    crop={crop}
                    zoom={zoom}
                    aspect={type === 'avatar' ? 1 : 3}
                    cropShape={type === 'avatar' ? 'round' : 'rect'}
                    showGrid={false}
                    onCropChange={setCrop}
                    onCropComplete={onCropCompleteHandler}
                    onZoomChange={setZoom}
                    objectFit="cover"
                    classes={{
                      containerClassName: 'bg-zinc-900',
                      cropAreaClassName: type === 'avatar' 
                        ? 'border-2 border-white/60 shadow-[0_0_0_9999em_rgba(9,9,11,0.7)] rounded-full' 
                        : 'border-2 border-white/60 shadow-[0_0_0_9999em_rgba(9,9,11,0.75)]'
                    }}
                    zoomWithScroll={true}
                  />
                )
              ) : (
                <div className="absolute inset-0 flex flex-col items-center justify-center text-white/30 text-sm gap-2">
                  <ImageIcon className="w-8 h-8 opacity-40 animate-pulse" />
                  <span>{mode === 'gif' ? t('selectGif') : t('selectPhoto')}</span>
                </div>
              )}

              {/* Hint text overlay */}
              {mode === 'gallery' && selectedPhoto && (
                <div className="absolute bottom-4 left-0 right-0 text-center pointer-events-none z-10">
                  <span className="bg-black/65 backdrop-blur-md border border-white/5 text-white/95 text-[10px] px-3 py-1.5 rounded-full font-medium tracking-wide shadow-lg">
                    {t('cropHint')}
                  </span>
                </div>
              )}
            </div>

            {/* Bottom Half: 3-Column Gallery / GIF Grid (scrollable) */}
            <div className="flex-1 bg-zinc-950 flex flex-col relative overflow-hidden">
              {mode === 'gallery' ? (
                <div className="flex-1 flex flex-col relative overflow-hidden h-full">
                  {/* The Photo Grid Scrollable area */}
                  <div className="flex-1 overflow-y-auto no-scrollbar pb-24">
                    <div className="grid grid-cols-3 gap-[2px] p-0.5">
                      {/* Fetched & Uploaded Photos */}
                      {displayPhotos.length > 0 && displayPhotos.map((photo) => (
                        <button
                          key={photo.id} 
                          type="button"
                          onClick={() => {
                            setSelectedPhoto(photo);
                            setCrop({ x: 0, y: 0 });
                            setZoom(1);
                          }}
                          className="relative aspect-square cursor-pointer overflow-hidden bg-white/[0.03] active:scale-95 transition-all group"
                        >
                          <img 
                            src={photo.url} 
                            alt="" 
                            className="w-full h-full object-cover group-hover:scale-105 transition-transform" 
                            loading="lazy" 
                          />
                          {selectedPhoto?.id === photo.id && (
                            <div className="absolute inset-0 bg-white/15 border-[3px] border-emerald-500 transition-all shadow-inner" />
                          )}
                        </button>
                      ))}
                    </div>
                  </div>

                  {/* Floating Action Button (FAB) at bottom-left corner with 'eva:file-add-fill' Icon */}
                  <button
                    type="button"
                    onClick={() => fileInputRef.current?.click()}
                    className="absolute bottom-6 left-6 w-14 h-14 rounded-full bg-zinc-900/90 backdrop-blur-md flex items-center justify-center border border-white/10 shadow-[0_6px_24px_rgba(0,0,0,0.65)] active:scale-95 transition-all z-20 group hover:bg-zinc-850"
                  >
                    <Icon icon="eva:file-add-fill" className="w-7 h-7 text-white" />
                    <input 
                      type="file" 
                      ref={fileInputRef} 
                      className="hidden" 
                      accept="image/*,video/*" 
                      onChange={handleFallbackUpload} 
                    />
                  </button>
                </div>
              ) : (
                <div className="flex-1 flex flex-col relative overflow-hidden h-full">
                  {/* Search Input bar (Sticky top in scroll view) */}
                  <div className="p-3 shrink-0 relative flex items-center bg-zinc-950 z-10">
                    <Search className="w-4 h-4 text-white/30 absolute left-6" />
                    <input 
                      type="text" 
                      placeholder={t('searchGifs')}
                      value={gifSearchQuery}
                      onChange={(e) => setGifSearchQuery(e.target.value)}
                      className="w-full bg-white/[0.06] text-white border border-white/[0.06] rounded-xl h-10 pl-10 pr-4 text-sm focus:ring-1 focus:ring-emerald-500 outline-none placeholder:text-white/30"
                    />
