                        ))
                      )}
                    </div>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
};

import { useState } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Plus, Trash2, Link as LinkIcon, Globe, Send, Instagram, Youtube, Facebook, Twitter, Github } from 'lucide-react';
import { cn } from '@/lib/utils';

export interface SocialLink {
  type: string;
  url: string;
  label?: string;
}

interface SocialLinksEditorProps {
  links: SocialLink[];
  onChange: (links: SocialLink[]) => void;
  maxLinks?: number;
}

const SOCIAL_TYPES = [
  { value: 'telegram', label: 'Telegram', icon: Send, color: 'bg-[#0088cc]' },
  { value: 'instagram', label: 'Instagram', icon: Instagram, color: 'bg-gradient-to-r from-[#833ab4] via-[#fd1d1d] to-[#fcb045]' },
  { value: 'youtube', label: 'YouTube', icon: Youtube, color: 'bg-[#FF0000]' },
  { value: 'facebook', label: 'Facebook', icon: Facebook, color: 'bg-[#1877F2]' },
  { value: 'twitter', label: 'Twitter/X', icon: Twitter, color: 'bg-foreground' },
  { value: 'github', label: 'GitHub', icon: Github, color: 'bg-foreground' },
  { value: 'website', label: 'Vebsayt', icon: Globe, color: 'bg-primary' },
  { value: 'other', label: 'Boshqa', icon: LinkIcon, color: 'bg-muted-foreground' },
];

export const getSocialIcon = (type: string) => {
  const socialType = SOCIAL_TYPES.find(s => s.value === type);
  return socialType?.icon || LinkIcon;
};

export const getSocialColor = (type: string) => {
  const socialType = SOCIAL_TYPES.find(s => s.value === type);
  return socialType?.color || 'bg-muted-foreground';
};

export const SocialLinksEditor = ({ links, onChange, maxLinks = 3 }: SocialLinksEditorProps) => {
  const addLink = () => {
    if (links.length >= maxLinks) return;
    onChange([...links, { type: 'website', url: '', label: '' }]);
  };

  const updateLink = (index: number, field: keyof SocialLink, value: string) => {
    const newLinks = [...links];
    newLinks[index] = { ...newLinks[index], [field]: value };
    onChange(newLinks);
  };

  const removeLink = (index: number) => {
    onChange(links.filter((_, i) => i !== index));
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <Label>Ijtimoiy havolalar</Label>
        <span className="text-xs text-muted-foreground">{links.length}/{maxLinks}</span>
      </div>

      {links.map((link, index) => (
        <div key={index} className="space-y-2 p-3 bg-muted/50 rounded-lg">
          <div className="flex gap-2">
            <Select
              value={link.type}
              onValueChange={(value) => updateLink(index, 'type', value)}
            >
              <SelectTrigger className="w-[140px]">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {SOCIAL_TYPES.map((type) => {
                  const Icon = type.icon;
                  return (
                    <SelectItem key={type.value} value={type.value}>
                      <div className="flex items-center gap-2">
                        <Icon className="h-4 w-4" />
                        {type.label}
                      </div>
                    </SelectItem>
                  );
                })}
              </SelectContent>
            </Select>
            
            <Button
              type="button"
              variant="ghost"
              size="icon"
              onClick={() => removeLink(index)}
              className="text-destructive hover:bg-destructive/10"
            >
              <Trash2 className="h-4 w-4" />
            </Button>
          </div>
          
          <Input
            placeholder="https://..."
            value={link.url}
            onChange={(e) => updateLink(index, 'url', e.target.value)}
          />
          
          <Input
            placeholder="Ko'rsatiladigan matn (ixtiyoriy)"
            value={link.label || ''}
            onChange={(e) => updateLink(index, 'label', e.target.value)}
            className="text-sm"
          />
        </div>
      ))}

      {links.length < maxLinks && (
        <Button
          type="button"
          variant="outline"
          onClick={addLink}
          className="w-full"
        >
          <Plus className="h-4 w-4 mr-2" />
          Havola qo'shish
        </Button>
      )}
    </div>
  );
};

import { useState, useEffect, useRef, useCallback } from 'react';
import { Loader2, Search } from 'lucide-react';
import { Input } from '@/components/ui/input';
import { Icon } from '@iconify/react';

export interface Short {
  id: string;
  title: string;
  thumbnail: string;
  channelTitle: string;
}

interface YouTubeShortsProps {
  onShortClick?: (shorts: Short[], index: number) => void;
  onSearchClick?: () => void;
  onSearchSubmit?: (query: string) => void;
  onShortsChange?: (shorts: Short[]) => void;
}

const SEEN_KEY = 'yt_shorts_seen_ids';
const SEEN_MAX = 500;

function getSeenIds(): Set<string> {
  try {
    const raw = localStorage.getItem(SEEN_KEY);
    if (!raw) return new Set();
    return new Set(JSON.parse(raw));
  } catch { return new Set(); }
}

function markSeen(ids: string[]) {
  try {
    const seen = getSeenIds();
    ids.forEach(id => seen.add(id));
    // Keep only last SEEN_MAX
    const arr = [...seen];
    if (arr.length > SEEN_MAX) arr.splice(0, arr.length - SEEN_MAX);
    localStorage.setItem(SEEN_KEY, JSON.stringify(arr));
  } catch {
    // Ignore error
  }
}

function clearSeenCache() {
  try { localStorage.removeItem(SEEN_KEY); } catch {
    // Ignore error
  }
}

// Rotating search queries for variety
const SEARCH_QUERIES = [
  'uzbekistan shorts trending',
  'uzbek viral shorts',
  'toshkent shorts trending',
  'samarkand shorts',
  'bukhara shorts',
  'uzbek prikol shorts',
  'uzbekistan news shorts',
  'toshkent shorts',
  'uzbekistan trending 2025 shorts',
  'uzbekistan funny shorts',
  'shorts comedy viral',
  'shorts music dance trending',
  'trending reels shorts new',
  'funny moments shorts viral',
  'shorts challenge trending',
];

function getRandomQuery(): string {
  return SEARCH_QUERIES[Math.floor(Math.random() * SEARCH_QUERIES.length)];
}

export function YouTubeShortsSection({ onShortClick, onSearchClick, onSearchSubmit, onShortsChange }: YouTubeShortsProps) {
  const [shorts, setShorts] = useState<Short[]>([]);
  const [nextToken, setNextToken] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isLoadingMore, setIsLoadingMore] = useState(false);
  const [hasMore, setHasMore] = useState(true);
  const [searchText, setSearchText] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);
  const loaderRef = useRef<HTMLDivElement>(null);
  const fetchingRef = useRef(false);
  const currentQueryRef = useRef(getRandomQuery());
  const queryIndexRef = useRef(0);
  const exhaustedQueriesRef = useRef(false);
  const startQueryIndexRef = useRef<number | null>(null);
  const rotatedAtLeastOnceRef = useRef(false);
  const retriesRef = useRef(0);

  const MUSIC_KEYWORDS = ['official video', 'music video', 'lyrics', 'lyric video', 'audio',
    'official audio', 'karaoke', 'remix', 'full album', 'playlist', 'mv', 'song', 'album',
    'concert', 'live performance', 'cover song', 'acoustic version', 'instrumental'];
  const MUSIC_CHANNEL_PATTERNS = [' - topic', 'vevo', 'records', 'music'];

  const isLikelyMusic = useCallback((s: Short) => {
    const t = (s.title || '').toLowerCase();
    const c = (s.channelTitle || '').toLowerCase();
    if (MUSIC_CHANNEL_PATTERNS.some(p => c.includes(p))) return true;
    if (MUSIC_KEYWORDS.some(k => t.includes(k))) return true;
    return false;
  }, []);

  const BLOCKED_KEYWORDS = ['india', 'indian', 'hindi', 'bollywood', 'punjabi', 'tamil', 'telugu', 'malayalam', 'bengali', 'gujarati', 'marathi'];

  const isBlocked = useCallback((s: Short) => {

    const t = (s.title || '').toLowerCase();

    const c = (s.channelTitle || '').toLowerCase();

    return BLOCKED_KEYWORDS.some((k) => t.includes(k) || c.includes(k));

  }, []);

  const fetchShorts = useCallback(async (pageToken?: string) => {
    if (fetchingRef.current) return;
    if (!hasMore && !pageToken) return;
    fetchingRef.current = true;

    const isFirstLoad = !pageToken;
    if (isFirstLoad) {
      setIsLoading(true);
      // If we have nothing yet, start at a random query. Otherwise keep current query when loading more.
      if (shorts.length === 0) {
        queryIndexRef.current = Math.floor(Math.random() * SEARCH_QUERIES.length);
        currentQueryRef.current = SEARCH_QUERIES[queryIndexRef.current] || getRandomQuery();
        startQueryIndexRef.current = queryIndexRef.current;
        rotatedAtLeastOnceRef.current = false;
      }
      exhaustedQueriesRef.current = false;
      setHasMore(true);
      retriesRef.current = 0;
    } else {
      setIsLoadingMore(true);
    }

    try {
      const projectId = import.meta.env.VITE_SUPABASE_PROJECT_ID;
      const anonKey = import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY;
      const params = new URLSearchParams({
        q: currentQueryRef.current,
        maxResults: '5',
        regionCode: 'UZ',
        relevanceLanguage: 'uz'
      });
      if (pageToken) params.set('pageToken', pageToken);

      const res = await fetch(
        `https://${projectId}.supabase.co/functions/v1/fetch-shorts?${params}`,
        { headers: { apikey: anonKey } }
      );
      if (!res.ok) throw new Error('Failed to fetch');
      const data = await res.json();
      const isCustomQuery = !SEARCH_QUERIES.includes(currentQueryRef.current);
      const newShorts: Short[] = (data?.shorts || [])
        .filter((s: Short) => isCustomQuery || (!isLikelyMusic(s) && !isBlocked(s)));
      const newToken: string | null = data?.nextPageToken || null;

      // Filter out already-seen shorts
      const seen = getSeenIds();
      // Don't filter out seen shorts if it's an explicit custom user query (we want to show all match results)
      const freshShorts = isCustomQuery ? newShorts : newShorts.filter(s => !seen.has(s.id));

      setShorts((prev) => {
        const combined = isFirstLoad ? freshShorts : [...prev, ...freshShorts];
        const seenSet = new Set<string>();
        const unique = combined.filter((s) => {
          if (seenSet.has(s.id)) return false;
          seenSet.add(s.id);
          return true;
        });
        return unique;
      });
      setNextToken(newToken);

      const rotateQueryAndContinue = () => {
        // Cycle through SEARCH_QUERIES and keep loading until all exhausted.
        const prevIndex = queryIndexRef.current;
        queryIndexRef.current = (queryIndexRef.current + 1) % SEARCH_QUERIES.length;
        const nextQuery = SEARCH_QUERIES[queryIndexRef.current] || getRandomQuery();
        currentQueryRef.current = nextQuery;

        rotatedAtLeastOnceRef.current = true;

        const start = startQueryIndexRef.current;
        if (start !== null && rotatedAtLeastOnceRef.current && queryIndexRef.current === start) {
          exhaustedQueriesRef.current = true;
        }

        if (exhaustedQueriesRef.current) {
          setHasMore(false);
          setNextToken(null);
          return;
        }

        retriesRef.current = 0;
        fetchingRef.current = false;
        fetchShorts();
      };

      // If we got too few fresh results and have a token, auto-fetch more
      if (freshShorts.length < 5 && newToken && retriesRef.current < 3) {
        retriesRef.current++;
        fetchingRef.current = false;
        fetchShorts(newToken);
        return;
      }

      // If token ended (or filtering removed most items), switch query and continue instead of stopping.
      if (freshShorts.length < 5 && !newToken) {
        if (isCustomQuery) {
          setHasMore(false);
          setNextToken(null);
          return;
        }
        rotateQueryAndContinue();
        return;
      }

      if (!newToken) {
        // no more pages for this query; move to next query on next loadMore
        // (but don't immediately rotate if we already got enough results)
        setHasMore(!isCustomQuery);
      }
    } catch (err) {
      console.error('Failed to fetch shorts:', err);
    } finally {
      setIsLoading(false);
      setIsLoadingMore(false);
      fetchingRef.current = false;
    }
  }, [hasMore, isBlocked, isLikelyMusic, shorts.length]);

  useEffect(() => {
    // onSearchClick triggered by UI
  }, [onSearchClick]);

  useEffect(() => {
    // notify parent about the latest list for caching
    // (used for UnifiedFullScreenViewer tab switching)
    // eslint-disable-next-line @typescript-eslint/no-unused-expressions
    (undefined);
  }, []);

  useEffect(() => {
    fetchShorts();
  }, [fetchShorts]);

  useEffect(() => {
    onShortsChange?.(shorts);
  }, [shorts, onShortsChange]);

  useEffect(() => {
    // keep parent in sync
    // (prop is optional)
  }, [onShortClick]);

  useEffect(() => {
    const handler = () => {
      clearSeenCache();
      setShorts([]);
      setNextToken(null);
      setHasMore(true);
      exhaustedQueriesRef.current = false;
      startQueryIndexRef.current = null;
      rotatedAtLeastOnceRef.current = false;
      fetchingRef.current = false;
      fetchShorts();
    };
    window.addEventListener('refresh-shorts', handler);
    return () => window.removeEventListener('refresh-shorts', handler);
  }, [fetchShorts]);

  // IntersectionObserver for infinite scroll
  useEffect(() => {
    const el = loaderRef.current;
    if (!el) return;
    const observer = new IntersectionObserver(
      (entries) => {
        if (!entries[0]?.isIntersecting) return;
        if (isLoadingMore || fetchingRef.current) return;

        if (nextToken) {
          fetchShorts(nextToken);
          return;
        }

        if (hasMore) {
          // token ended for the current query -> fetch will rotate query internally if needed
          fetchShorts();
        }
      },
      { threshold: 0.1 }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, [nextToken, isLoadingMore, fetchShorts, hasMore]);

  const scroll = useCallback((direction: 'left' | 'right') => {
    if (!scrollRef.current) return;
    scrollRef.current.scrollBy({
      left: direction === 'left' ? -240 : 240,
      behavior: 'smooth'
    });
  }, []);

  // Mark shorts as seen when user clicks to view them
  const handleShortClick = useCallback((allShorts: Short[], index: number) => {
    // Mark clicked + nearby as seen
    const toMark = allShorts.slice(Math.max(0, index - 2), index + 5).map(s => s.id);
    markSeen(toMark);
    try {
      const lastId = allShorts[index]?.id;
      if (lastId) localStorage.setItem('yt_shorts_last_id', lastId);
    } catch {
      // Ignore localStorage error
    }
    onShortClick?.(allShorts, index);
  }, [onShortClick]);

  if (isLoading) {
    return (
      <div className="px-3 pt-1 pb-2">
        <div className="flex items-center gap-1.5 mb-2">
          <div className="w-4 h-4 rounded bg-muted/50 animate-pulse" />
          <div className="w-16 h-3 rounded bg-muted/50 animate-pulse" />
        </div>
        <div className="flex gap-2 overflow-hidden">
          {[...Array(4)].map((_, i) =>
            <div key={i} className="w-[110px] h-[196px] rounded-2xl bg-muted/30 animate-pulse shrink-0" />
          )}
        </div>
      </div>
    );
  }

  if (shorts.length === 0) return null;

  return (
    <div className="pt-1 pb-0">
      {/* Header */}
      <div className="items-center mb-1.5 px-[12px] flex flex-row py-[3px] gap-2">
        <div className="flex items-center gap-1.5 flex-shrink-0">
          <Icon icon="logos:youtube-icon" className="w-4 h-4" />
          <span className="font-semibold text-xs text-foreground">Shorts</span>
        </div>
        <div className="flex-1">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-muted-foreground" />
            <Input
              placeholder="YouTube video va Shorts qidirish..."
              value={searchText}
              onChange={(e) => setSearchText(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter') {
                  const q = searchText.trim();
                  if (!q) return;
                  // Directly trigger YouTube search inline
                  currentQueryRef.current = q;
                  setShorts([]);
                  setNextToken(null);
                  setHasMore(true);
                  fetchingRef.current = false;
                  exhaustedQueriesRef.current = false;
                  startQueryIndexRef.current = null;
                  rotatedAtLeastOnceRef.current = false;
                  retriesRef.current = 0;
                  fetchShorts();
                }
              }}
              className="h-7 rounded-full pl-8 pr-3 bg-background/30 border-white/10 backdrop-blur-xl text-xs focus-visible:ring-1 focus-visible:ring-primary/40"
            />
          </div>
        </div>
      </div>

      {/* Carousel */}
      <style>{`.shorts-carousel::-webkit-scrollbar{display:none}`}</style>
      <div
        ref={scrollRef}
        className="shorts-carousel flex gap-2 overflow-x-auto px-3 snap-x snap-mandatory shadow-md"
        style={{ scrollbarWidth: 'none', msOverflowStyle: 'none', WebkitOverflowScrolling: 'touch' }}>
        {shorts.map((short, index) =>
          <div
            key={`${short.id}-${index}`}
            className="relative w-[110px] h-[196px] rounded-2xl overflow-hidden shrink-0 snap-start cursor-pointer group"
            onClick={() => handleShortClick(shorts, index)}>
            <img
              src={short.thumbnail}
              alt={short.title}
              className="absolute inset-0 w-full h-full object-cover"
              loading="lazy"
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent pointer-events-none" />
            <div className="absolute top-2 right-2 opacity-90 z-10">
               <Icon icon="logos:youtube-icon" className="w-5 h-5 drop-shadow-md" />
            </div>
            <div className="absolute bottom-0 left-0 right-0 p-1.5 z-10">
              <p className="text-[10px] font-medium leading-tight line-clamp-2 drop-shadow-lg bg-inherit text-gray-300">
                {short.title}
              </p>
              <p className="text-[9px] text-primary-foreground/60 mt-0.5 drop-shadow-lg">
                {short.channelTitle}
              </p>
            </div>
          </div>
        )}

        {/* Loader sentinel */}
        <div ref={loaderRef} className="flex items-center justify-center shrink-0 w-[60px]">
          {isLoadingMore ?
            <Loader2 className="w-5 h-5 text-muted-foreground animate-spin" /> :
            (nextToken || hasMore) ?
              <div className="w-5 h-5 rounded-full border-2 border-muted-foreground/30" /> :
              <p className="text-[9px] text-muted-foreground whitespace-nowrap">Hammasi Γ£ô</p>
          }
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect, useCallback, useRef } from 'react';
import { createPortal } from 'react-dom';
import { useNavigate } from 'react-router-dom';
import { X, ChevronLeft, ChevronRight, Heart, Send, Eye, MoreVertical, Pause, Play, Volume2, VolumeX, Plus } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog';
import { Sheet, SheetContent, SheetHeader, SheetTitle } from '@/components/ui/sheet';
import { ScrollArea } from '@/components/ui/scroll-area';
import { StoryGroup, Story, useStories } from '@/hooks/useStories';
import { useAuth } from '@/contexts/AuthContext';
import { useConversations } from '@/hooks/useConversations';
import { StarUsername } from '@/components/user/StarUsername';
import { supabase } from '@/integrations/supabase/client';
import { formatDistanceToNow } from 'date-fns';
import { cn } from '@/lib/utils';
import { toast } from 'sonner';
import { MusicOverlay } from '@/components/music/MusicOverlay';
import { isActiveAudio, playExclusiveAudio, stopActiveAudio } from '@/lib/audioController';

interface StoryViewerProps {
  storyGroups: StoryGroup[];
  initialGroupIndex: number;
  initialStoryIndex?: number;
  persistKey?: string;
  onClose: () => void;
  onDeleted?: () => void;
}

export const StoryViewer = ({
  storyGroups,
  initialGroupIndex,
  initialStoryIndex = 0,
  persistKey,
  onClose,
  onDeleted,
}: StoryViewerProps) => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const { recordView, toggleLike, getStoryViewers, getStoryLikers } = useStories();
  const { getOrCreateConversation } = useConversations();
  
  const [currentGroupIndex, setCurrentGroupIndex] = useState(initialGroupIndex);
  const [currentStoryIndex, setCurrentStoryIndex] = useState(initialStoryIndex);
  const [isPaused, setIsPaused] = useState(false);
  const [isMuted, setIsMuted] = useState(true);
  const [progress, setProgress] = useState(0);
  const [reply, setReply] = useState('');
  const [showViewers, setShowViewers] = useState(false);
  const [viewers, setViewers] = useState<any[]>([]);
  const [likers, setLikers] = useState<any[]>([]);
  const [insightsTab, setInsightsTab] = useState<'views' | 'likes'>('views');
  const [isLiked, setIsLiked] = useState(false);
  const [likeAnimKey, setLikeAnimKey] = useState(0);
  const [showLikeAnim, setShowLikeAnim] = useState(false);
  const [showDeleteDialog, setShowDeleteDialog] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [showCaption, setShowCaption] = useState(false);
  const [isMusicPlaying, setIsMusicPlaying] = useState(false);
  
  const videoRef = useRef<HTMLVideoElement>(null);
  const audioRef = useRef<HTMLAudioElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const mutedMediaRef = useRef(new Map<HTMLMediaElement, { muted: boolean; volume: number }>());
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const progressRef = useRef<number>(0);
  const lastPersistRef = useRef<number>(0);

  const currentGroup = storyGroups[currentGroupIndex];
  const currentStory = currentGroup?.stories[currentStoryIndex];
  const isOwnStory = currentStory?.user_id === user?.id;
  const storyDuration = currentStory?.media_type === 'video' ? 15000 : 5000;

  const audioKey = currentStory?.id ? `story:${currentStory.id}` : null;

  const getPersistKey = useCallback(() => {
    if (!persistKey) return null;
    const viewerId = user?.id || 'anon';
    return `story_viewer_state_v1:${viewerId}:${persistKey}`;
  }, [persistKey, user?.id]);

  const persistState = useCallback(() => {
    const key = getPersistKey();
    if (!key) return;
    try {
      const now = Date.now();
      if (now - lastPersistRef.current < 300) return;
      lastPersistRef.current = now;

      const ct = currentStory?.media_type === 'video' ? (videoRef.current?.currentTime || 0) : 0;
      localStorage.setItem(
        key,
        JSON.stringify({
          groupIndex: currentGroupIndex,
          storyIndex: currentStoryIndex,
          paused: isPaused,
          muted: isMuted,
          videoTime: ct,
          savedAt: now,
        })
      );
    } catch (e) { /* ignore */ }
  }, [currentGroupIndex, currentStory?.media_type, currentStoryIndex, getPersistKey, isMuted, isPaused]);

  useEffect(() => {
    const key = getPersistKey();
    if (!key) return;
    try {
      const raw = localStorage.getItem(key);
      if (!raw) return;
      const parsed = JSON.parse(raw) as {
        groupIndex?: number;
        storyIndex?: number;
        paused?: boolean;
        muted?: boolean;
        videoTime?: number;
      };

      if (typeof parsed.groupIndex === 'number' && parsed.groupIndex >= 0 && parsed.groupIndex < storyGroups.length) {
        setCurrentGroupIndex(parsed.groupIndex);
      }

      const g = storyGroups[
        typeof parsed.groupIndex === 'number' && parsed.groupIndex >= 0 && parsed.groupIndex < storyGroups.length
          ? parsed.groupIndex
          : initialGroupIndex
      ];
      const maxStoryIdx = g?.stories?.length ? g.stories.length - 1 : 0;
      if (typeof parsed.storyIndex === 'number') {
        const clamped = Math.max(0, Math.min(maxStoryIdx, parsed.storyIndex));
        setCurrentStoryIndex(clamped);
      }

      if (typeof parsed.paused === 'boolean') setIsPaused(parsed.paused);
      if (typeof parsed.muted === 'boolean') setIsMuted(parsed.muted);
    } catch (e) { /* ignore */ }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const getLocalLikeKey = useCallback((storyId: string) => {
    const viewerId = user?.id || 'anon';
    return `story_like_v1:${viewerId}:${storyId}`;
  }, [user?.id]);

  const readLocalLike = useCallback((storyId: string) => {
    try {
      const raw = localStorage.getItem(getLocalLikeKey(storyId));
      if (!raw) return null;
      const parsed = JSON.parse(raw) as { liked?: boolean; expiresAt?: number };
      if (!parsed || typeof parsed.expiresAt !== 'number') return null;
      if (Date.now() > parsed.expiresAt) {
        localStorage.removeItem(getLocalLikeKey(storyId));
        return null;
      }
      return parsed;
    } catch {
      return null;
    }
  }, [getLocalLikeKey]);

  const writeLocalLike = useCallback((storyId: string, liked: boolean) => {
    try {
      const ttlMs = 36 * 60 * 60 * 1000;
      localStorage.setItem(
        getLocalLikeKey(storyId),
        JSON.stringify({ liked, expiresAt: Date.now() + ttlMs })
      );
    } catch (e) { /* ignore */ }
  }, [getLocalLikeKey]);

  const removeLocalLike = useCallback((storyId: string) => {
    try {
      localStorage.removeItem(getLocalLikeKey(storyId));
    } catch (e) { /* ignore */ }
  }, [getLocalLikeKey]);

  // Record view when story changes
  useEffect(() => {
    if (currentStory && !isOwnStory) {
      recordView(currentStory.id);
    }
    if (currentStory) {
      const local = readLocalLike(currentStory.id);
      if (local && typeof local.liked === 'boolean') setIsLiked(local.liked);
      else setIsLiked(currentStory.has_liked || false);
    } else {
      setIsLiked(false);
    }
  }, [currentStory, isOwnStory, readLocalLike, recordView]);

  // Auto-play music when story changes
  useEffect(() => {
    setIsMusicPlaying(false);
    if (audioRef.current) {
      try {
        audioRef.current.pause();
        audioRef.current.currentTime = 0;
      } catch (e) { /* ignore */ }
    }
    stopActiveAudio(audioKey || undefined);

    // Auto-play music if story has audio
    if (currentStory?.audio_url && audioRef.current && audioKey) {
      const el = audioRef.current;
      let cancelled = false;

      const doPlay = async () => {
        if (cancelled) return;
        try {
          const ok = await playExclusiveAudio(audioKey, el);
          if (!cancelled) setIsMusicPlaying(ok && !el.paused);
        } catch {
          if (!cancelled) setIsMusicPlaying(false);
        }
      };

      // Set up source and load
      el.src = currentStory.audio_url;
      el.loop = true;
      el.preload = 'auto';
      el.crossOrigin = 'anonymous';

      // Try to play once audio is ready
      const onReady = () => {
        el.removeEventListener('canplaythrough', onReady);
        doPlay();
      };
      el.addEventListener('canplaythrough', onReady);

      try { el.load(); } catch (e) { /* ignore */ }

      // Fallback: if canplaythrough doesn't fire within 1.5s, try anyway
      const fallback = setTimeout(() => {
        el.removeEventListener('canplaythrough', onReady);
        doPlay();
      }, 1500);

      return () => {
        cancelled = true;
        el.removeEventListener('canplaythrough', onReady);
        clearTimeout(fallback);
      };
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentGroupIndex, currentStoryIndex]);

  useEffect(() => {
    if (!audioKey) return;
    setIsMusicPlaying(isActiveAudio(audioKey));
  }, [audioKey]);

  useEffect(() => {
    if (!audioKey) return;
    if (!currentStory?.audio_url) return;
    if (!isPaused) return;
    if (!audioRef.current) return;
    try {
      audioRef.current.pause();
    } catch (e) { /* ignore */ }
    setIsMusicPlaying(false);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isPaused]);

  useEffect(() => {
    const el = audioRef.current;
    if (!el) return;

    const onError = () => {
      setIsMusicPlaying(false);
      toast.error('Musiqa yuklanmadi');
    };

    el.addEventListener('error', onError);
    return () => el.removeEventListener('error', onError);
  }, []);

  // Load viewers/likers for own story
  useEffect(() => {
    if (isOwnStory && currentStory) {
      loadViewersAndLikers();
    }
  }, [currentStory, isOwnStory]);

  const loadViewersAndLikers = async () => {
    if (!currentStory) return;
    const [viewersData, likersData] = await Promise.all([
      getStoryViewers(currentStory.id),
      getStoryLikers(currentStory.id),
    ]);
    setViewers(viewersData);
    setLikers(likersData);
  };

  // Progress timer
  useEffect(() => {
    if (!currentStory) return;

    if (timerRef.current) {
      clearInterval(timerRef.current);
      timerRef.current = null;
    }

    if (currentStory.media_type === 'video') {
      const el = videoRef.current;
      if (!el) return;

      const key = getPersistKey();
      if (key) {
        try {
          const raw = localStorage.getItem(key);
          if (raw) {
            const parsed = JSON.parse(raw) as { videoTime?: number; groupIndex?: number; storyIndex?: number };
            if (
              typeof parsed.videoTime === 'number' &&
              typeof parsed.groupIndex === 'number' &&
              typeof parsed.storyIndex === 'number' &&
              parsed.groupIndex === currentGroupIndex &&
              parsed.storyIndex === currentStoryIndex &&
              parsed.videoTime > 0
            ) {
              try {
                el.currentTime = parsed.videoTime;
              } catch (e) { /* ignore */ }
            }
          }
        } catch (e) { /* ignore */ }
      }

      const onTime = () => {
        const dur = el.duration || 0;
        if (!dur) return;
        const pct = Math.max(0, Math.min(100, (el.currentTime / dur) * 100));
        setProgress(pct);
        persistState();
      };

      const onEnded = () => {
        goToNextRef.current();
      };

      el.addEventListener('timeupdate', onTime);
      el.addEventListener('ended', onEnded);
      onTime();
      return () => {
        el.removeEventListener('timeupdate', onTime);
        el.removeEventListener('ended', onEnded);
      };
    }

    if (isPaused) return;

    progressRef.current = 0;
    setProgress(0);

    const interval = 50;
    timerRef.current = setInterval(() => {
      progressRef.current += interval;
      setProgress((progressRef.current / storyDuration) * 100);
      persistState();

      if (progressRef.current >= storyDuration) {
        goToNextRef.current();
      }
    }, interval);

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [currentGroupIndex, currentStory, currentStoryIndex, getPersistKey, isPaused, persistState, storyDuration]);

  useEffect(() => {
    if (!currentStory || currentStory.media_type !== 'video') return;
    const el = videoRef.current;
    if (!el) return;
    el.muted = isMuted;
    if (isPaused) {
      try {
        el.pause();
      } catch (e) { /* ignore */ }
      persistState();
      return;
    }
    void (async () => {
      try {
        await el.play();
      } catch (e) { /* ignore */ }
    })();
  }, [currentStory, isMuted, isPaused, persistState]);

  useEffect(() => {
    const container = containerRef.current;
    const media = Array.from(document.querySelectorAll('video, audio')) as HTMLMediaElement[];

    for (const el of media) {
      if (container && container.contains(el)) continue;
      if (!mutedMediaRef.current.has(el)) {
        mutedMediaRef.current.set(el, { muted: el.muted, volume: el.volume });
      }
      try {
        el.pause();
      } catch (e) { /* ignore */ }
      el.muted = true;
      el.volume = 0;
    }

    return () => {
      mutedMediaRef.current.forEach((prev, el) => {
        el.muted = prev.muted;
        el.volume = prev.volume;
      });
      mutedMediaRef.current.clear();
    };
  }, []);

  const goToNext = useCallback(() => {
    if (currentStoryIndex < currentGroup.stories.length - 1) {
      setCurrentStoryIndex(prev => prev + 1);
    } else if (currentGroupIndex < storyGroups.length - 1) {
      setCurrentGroupIndex(prev => prev + 1);
      setCurrentStoryIndex(0);
    } else {
      onClose();
    }
  }, [currentStoryIndex, currentGroup, currentGroupIndex, storyGroups.length, onClose]);

  const goToNextRef = useRef(goToNext);
  useEffect(() => { goToNextRef.current = goToNext; }, [goToNext]);

  const goToPrev = useCallback(() => {
    if (currentStoryIndex > 0) {
      setCurrentStoryIndex(prev => prev - 1);
    } else if (currentGroupIndex > 0) {
      setCurrentGroupIndex(prev => prev - 1);
      const prevGroup = storyGroups[currentGroupIndex - 1];
      setCurrentStoryIndex(prevGroup.stories.length - 1);
    }
  }, [currentStoryIndex, currentGroupIndex, storyGroups]);

  useEffect(() => {
    persistState();
  }, [currentGroupIndex, currentStoryIndex, isPaused, isMuted, persistState]);

  const handleTap = (e: React.MouseEvent) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const width = rect.width;

    if (x < width * 0.3) {
      goToPrev();
    } else if (x > width * 0.7) {
      goToNext();
    } else {
      setIsPaused(prev => !prev);
    }
  };

  const toggleMusic = useCallback(async () => {
    if (!currentStory?.audio_url) return;
    if (!audioKey) return;
    const el = audioRef.current;
    if (!el) return;

    if (isActiveAudio(audioKey) && !el.paused) {
      try {
        el.pause();
      } catch (e) { /* ignore */ }
      stopActiveAudio(audioKey);
      setIsMusicPlaying(false);
      return;
    }

    try {
      el.src = currentStory.audio_url;
      el.loop = true;
      el.preload = 'auto';
      el.crossOrigin = 'anonymous';
      try { el.load(); } catch (e) { /* ignore */ }
    } catch (e) { /* ignore */ }

    // If story is paused, unpause so the paused-effect doesn't immediately stop audio.
    setIsPaused(false);

    const ok = await playExclusiveAudio(audioKey, el);
    if (!ok) {
      toast.error('Musiqani ijro etib bo\'lmadi');
      setIsMusicPlaying(false);
      return;
    }
    setIsMusicPlaying(!el.paused);
  }, [audioKey, currentStory?.audio_url]);

  const handleLike = useCallback(async () => {
    if (!currentStory) return;

    const next = !isLiked;
    setIsLiked(next);

    if (next) {
      writeLocalLike(currentStory.id, true);
      setLikeAnimKey(k => k + 1);
      setShowLikeAnim(true);
      window.setTimeout(() => setShowLikeAnim(false), 650);
    } else {
      removeLocalLike(currentStory.id);
    }

    try {
      await toggleLike(currentStory.id, isLiked);
    } catch {
      setIsLiked(!next);
      if (!next) writeLocalLike(currentStory.id, true);
      else removeLocalLike(currentStory.id);
      toast.error('Xatolik yuz berdi');
    }
  }, [currentStory, isLiked, removeLocalLike, toggleLike, writeLocalLike]);

  const timeAgo = currentStory
    ? formatDistanceToNow(new Date(currentStory.created_at), { addSuffix: true })
    : '';

  const handleDeleteStory = useCallback(async () => {
    if (!currentStory) return;
    setIsDeleting(true);
    try {
      const { error } = await supabase
        .from('stories')
        .delete()
        .eq('id', currentStory.id);

      if (error) throw error;

      toast.success("Hikoya o'chirildi");
      onDeleted?.();
      onClose();
    } catch (err) {
      console.error('Error deleting story:', err);
      toast.error("Xatolik yuz berdi");
    } finally {
      setIsDeleting(false);
      setShowDeleteDialog(false);
    }
  }, [currentStory, onClose, onDeleted]);

  if (!currentGroup || !currentStory) {
    return null;
  }

  const author = currentStory.author || currentGroup.user;

  const content = (
    <div ref={containerRef} className="fullscreen-story-view flex flex-col">
      {/* Story content */}
      <div
        className="relative flex-1 w-full min-h-0 flex items-center justify-center touch-none"
        onClick={handleTap}
      >
        {showLikeAnim && (
          <div key={likeAnimKey} className="absolute inset-0 z-20 flex items-center justify-center pointer-events-none">
            <div className="relative">
              <div className="absolute inset-0 rounded-full bg-red-500/20 blur-xl animate-ping" />
              <div className="relative w-24 h-24 flex items-center justify-center">
                <Heart className="w-20 h-20 text-red-500 fill-red-500 drop-shadow-[0_8px_18px_rgba(239,68,68,0.35)] animate-[likePop_650ms_ease-out]" />
              </div>
            </div>
          </div>
        )}

        {currentStory.media_type === 'video' ? (
          <video
            ref={videoRef}
            src={currentStory.media_url}
            className="max-w-full max-h-full w-full h-full object-contain"
            autoPlay
            muted={isMuted}
            playsInline
            loop={false}
          />
        ) : (
          <img
            src={currentStory.media_url}
            alt="Story"
            className="max-w-full max-h-full w-full h-full object-contain"
          />
        )}

        {/* Live animated GIF overlays ΓÇö rendered as HTML images (Instagram-style, never baked in) */}
        {currentStory.media_type === 'image' && currentStory.media_metadata?.gifOverlays?.map(gif => (
          <img
            key={gif.id}
            src={gif.originalUrl || gif.url}
            alt="gif sticker"
            className="absolute pointer-events-none select-none"
            style={{
              left: `${gif.x}%`,
              top: `${gif.y}%`,
              transform: `translate(-50%, -50%) scale(${gif.scale}) rotate(${gif.rotation}deg)`,
              width: '28%',
              maxWidth: '160px',
              zIndex: 11,
            }}
          />
        ))}

        {/* Overlay gradient */}
        <div className="absolute inset-0 bg-gradient-to-b from-black/50 via-transparent to-black/50 pointer-events-none" />

        {/* Progress bars ΓÇö safe-area ichida */}
        <div className="absolute top-0 left-0 right-0 flex gap-1 pt-[max(8px,env(safe-area-inset-top))] px-2">
          {currentGroup.stories.map((_, index) => (
            <div
              key={index}
              className="flex-1 h-0.5 bg-white/30 rounded-full overflow-hidden"
            >
              <div
                className="h-full bg-white transition-all duration-100"
                style={{
                  width:
                    index < currentStoryIndex
                      ? '100%'
                      : index === currentStoryIndex
                      ? `${progress}%`
                      : '0%',
                }}
              />
            </div>
          ))}
        </div>

        {/* Header ΓÇö safe-area */}
        <div className="absolute top-[max(24px,calc(8px+env(safe-area-inset-top)))] left-0 right-0 px-4 flex items-center justify-between">
          <div 
            className="flex items-center gap-3 cursor-pointer hover:opacity-80 transition-opacity"
            onClick={() => {
              if (author.id) {
                onClose();
                navigate(`/user/${author.id}`);
              }
            }}
          >
            <div className="relative w-10 h-10 overflow-visible">
              <div className="w-10 h-10 rounded-full overflow-hidden border-2 border-white">
                {author.avatar_url ? (
                  <img
                    src={author.avatar_url}
                    alt={author.name || 'User'}
                    className="w-full h-full object-cover"
                  />
                ) : (
                  <div className="w-full h-full bg-muted flex items-center justify-center text-white font-medium">
                    {(author.name || author.username || 'U').charAt(0).toUpperCase()}
                  </div>
                )}
              </div>

              {isOwnStory && (
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    navigate('/create-story');
                  }}
                  className="absolute -bottom-1 -right-1 w-5 h-5 rounded-full bg-white/85 flex items-center justify-center border-2 border-white/60 shadow-md"
                >
                  <Plus className="h-3 w-3 text-black/80" />
                </button>
              )}
            </div>
            <div className="text-white">
              <p className="font-medium text-sm">{author.name || author.username || 'Foydalanuvchi'}</p>
              <p className="text-xs opacity-70">{timeAgo}</p>
            </div>
          </div>

          <div className="flex items-center gap-2">
            {currentStory.audio_url && (
              <div onClick={(e) => e.stopPropagation()} className="mr-1">
                <MusicOverlay
                  audioTitle={currentStory.audio_title}
                  audioArtist={currentStory.audio_artist}
                  isPlaying={isMusicPlaying}
                  onTogglePlay={toggleMusic}
                  popoverSide="bottom"
                />
              </div>
            )}
            {isOwnStory && (
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button
                    variant="ghost"
                    size="icon"
                    className="text-white hover:bg-white/20"
                    onClick={(e) => e.stopPropagation()}
                  >
                    <MoreVertical className="h-5 w-5" />
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end" className="w-44">
                  <DropdownMenuSeparator />
                  <DropdownMenuItem
                    className="text-destructive focus:text-destructive"
                    onClick={(e) => {
                      e.preventDefault();
                      e.stopPropagation();
                      setShowDeleteDialog(true);
                      setIsPaused(true);
                    }}
                  >
                    O'chirish
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            )}

            {currentStory.media_type === 'video' && (
              <Button
                variant="ghost"
                size="icon"
                className="text-white hover:bg-white/20"
                onClick={(e) => {
                  e.stopPropagation();
                  setIsMuted(!isMuted);
                }}
              >
                {isMuted ? <VolumeX className="h-5 w-5" /> : <Volume2 className="h-5 w-5" />}
              </Button>
            )}
            <Button
              variant="ghost"
              size="icon"
              className="text-white hover:bg-white/20"
              onClick={(e) => {
                e.stopPropagation();
                setIsPaused(!isPaused);
              }}
            >
              {isPaused ? <Play className="h-5 w-5" /> : <Pause className="h-5 w-5" />}
            </Button>
            <Button
              variant="ghost"
              size="icon"
              className="text-white hover:bg-white/20"
              onClick={(e) => {
                e.stopPropagation();
                onClose();
              }}
            >
              <X className="h-5 w-5" />
            </Button>
          </div>
        </div>

        <audio
          ref={audioRef}
          className="absolute left-0 top-0 h-px w-px opacity-0 pointer-events-none"
          onError={() => {
            setIsMusicPlaying(false);
            try {
              console.error('Story audio error', {
                storyId: currentStory?.id,
                audioUrl: currentStory?.audio_url,
                mediaError: audioRef.current ? (audioRef.current as any).error : undefined,
              });
            } catch (e) { /* ignore */ }
            toast.error('Musiqa yuklanmadi');
          }}
          onEnded={() => setIsMusicPlaying(false)}
        />

        {/* Caption */}
        {currentStory.caption && (
          <div className="absolute bottom-[max(80px,calc(64px+env(safe-area-inset-bottom)))] left-4 right-4">
            <button
              type="button"
              onClick={(e) => {
                e.stopPropagation();
                setShowCaption(true);
                setIsPaused(true);
              }}
              className="w-full"
            >
              <p className="text-white text-center text-sm bg-black/40 px-3 py-2 rounded-lg line-clamp-2">
                {currentStory.caption}
              </p>
            </button>
          </div>
        )}

        {/* Footer actions ΓÇö safe-area */}
        <div className="absolute bottom-[max(16px,env(safe-area-inset-bottom))] left-4 right-4">
          {isOwnStory ? (
            // Own story: show viewers
            <div className="flex items-center gap-2">
              <Button
                variant="ghost"
                className="text-white hover:bg-white/20 gap-2"
                onClick={(e) => {
                  e.stopPropagation();
                  setInsightsTab('views');
                  setShowViewers(true);
                  setIsPaused(true);
                }}
              >
                <Eye className="h-5 w-5" />
                <span>{viewers.length} ko'rish</span>
              </Button>

              <Button
                variant="ghost"
                className="text-white hover:bg-white/20 gap-2"
                onClick={(e) => {
                  e.stopPropagation();
                  setInsightsTab('likes');
                  setShowViewers(true);
                  setIsPaused(true);
                }}
              >
                <Heart className="h-5 w-5" />
                <span>{likers.length} yoqtirish</span>
              </Button>
            </div>
          ) : (
            // Other's story: reply & like
            <div className="flex items-center gap-2">
              <Input
                placeholder={`${author.username || 'Foydalanuvchi'}ga javob...`}
                value={reply}
                onChange={(e) => setReply(e.target.value)}
                className="flex-1 bg-white/10 border-white/20 text-white placeholder:text-white/50"
                onClick={(e) => {
                  e.stopPropagation();
                  setIsPaused(true);
                }}
              />
              <Button
                variant="ghost"
                size="icon"
                className={cn(
                  'text-white hover:bg-white/20 active:scale-95 transition-transform',
                  'h-12 w-12 rounded-full bg-white/10 border border-white/15 backdrop-blur-md',
                  isLiked && 'text-red-500 bg-white/15 border-white/25'
                )}
                onClick={(e) => {
                  e.stopPropagation();
                  handleLike();
                }}
              >
                <Heart className={cn('h-7 w-7', isLiked && 'fill-current')} />
              </Button>
              <Button
                variant="ghost"
                size="icon"
                className={cn(
                  'text-white hover:bg-white/20 active:scale-95 transition-transform',
                  'h-12 w-12 rounded-full bg-gradient-to-br from-white/18 to-white/8 border border-white/15 backdrop-blur-md',
                  'disabled:opacity-40 disabled:active:scale-100'
                )}
                disabled={!reply.trim()}
                onClick={async (e) => {
                  e.stopPropagation();
                  if (!reply.trim() || !currentStory) return;
                  try {
                    const convId = await getOrCreateConversation(currentStory.user_id);
                    if (!convId || !user?.id) return;
                    const storyReplyText = `≡ƒô╖ Story'ga javob:\n${reply.trim()}`;
                    await supabase.from('messages').insert({
                      conversation_id: convId,
                      sender_id: user.id,
                      content: storyReplyText,
                      status: 'sent',
                    });
                    toast.success("Javob yuborildi");
                    setReply('');
                  } catch (err) {
                    console.error('Story reply error:', err);
                    toast.error("Xatolik yuz berdi");
                  }
                }}
              >
                <Send className="h-5 w-5" />
              </Button>
            </div>
          )}
        </div>

        {/* Navigation buttons (desktop) */}
        {currentGroupIndex > 0 && (
          <Button
            variant="ghost"
            size="icon"
            className="absolute left-2 top-1/2 -translate-y-1/2 text-white hover:bg-white/20 hidden md:flex"
            onClick={(e) => {
              e.stopPropagation();
              goToPrev();
            }}
          >
            <ChevronLeft className="h-8 w-8" />
          </Button>
        )}
        {currentGroupIndex < storyGroups.length - 1 && (
          <Button
            variant="ghost"
            size="icon"
            className="absolute right-2 top-1/2 -translate-y-1/2 text-white hover:bg-white/20 hidden md:flex"
            onClick={(e) => {
              e.stopPropagation();
              goToNext();
            }}
          >
            <ChevronRight className="h-8 w-8" />
          </Button>
        )}
      </div>

      {/* Viewers sheet */}
      <Sheet open={showViewers} onOpenChange={(open) => {
        setShowViewers(open);
        if (!open) setIsPaused(false);
      }}>
        <SheetContent side="bottom" className="h-[70vh] px-0">
          <div className="px-4">
            <SheetHeader>
              <SheetTitle>
                {insightsTab === 'views'
                  ? `Ko'rganlar (${viewers.length})`
                  : `Yoqtirganlar (${likers.length})`}
              </SheetTitle>
            </SheetHeader>

            <div className="mt-3 flex items-center gap-2">
              <button
                type="button"
                onClick={() => setInsightsTab('views')}
                className={cn(
                  'px-3 py-2 rounded-xl text-sm font-medium border transition-colors',
                  insightsTab === 'views'
                    ? 'bg-foreground text-background border-foreground'
                    : 'bg-background/50 text-foreground border-border hover:bg-muted'
                )}
              >
                Ko'rganlar
              </button>
              <button
                type="button"
                onClick={() => setInsightsTab('likes')}
                className={cn(
                  'px-3 py-2 rounded-xl text-sm font-medium border transition-colors',
                  insightsTab === 'likes'
                    ? 'bg-foreground text-background border-foreground'
                    : 'bg-background/50 text-foreground border-border hover:bg-muted'
                )}
              >
                Yoqtirganlar
              </button>
            </div>
          </div>

          <ScrollArea className="h-[calc(70vh-140px)] mt-4 px-4">
            {insightsTab === 'views' ? (
              viewers.length === 0 ? (
                <p className="text-center text-muted-foreground py-10">
                  Hali hech kim ko'rmagan
                </p>
              ) : (
                <div className="grid grid-cols-2 gap-3 pb-6">
                  {viewers.map((viewer) => (
                    <div
                      key={viewer.viewer_id}
                      className="flex items-center gap-3 p-3 rounded-2xl border border-border/60 bg-background/60 shadow-sm hover:shadow-md transition-shadow cursor-pointer active:scale-95"
                      onClick={() => {
                        if (viewer.viewer_id) {
                          setShowViewers(false);
                          onClose();
                          navigate(`/user/${viewer.viewer_id}`);
                        }
                      }}
                    >
                      <div className="w-11 h-11 rounded-2xl overflow-hidden bg-muted shrink-0">
                        {viewer.profile?.avatar_url ? (
                          <img
                            src={viewer.profile.avatar_url}
                            alt={viewer.profile.name || 'User'}
                            className="w-full h-full object-cover"
                          />
                        ) : (
                          <div className="w-full h-full flex items-center justify-center text-muted-foreground font-medium">
                            {(viewer.profile?.name || 'U').charAt(0).toUpperCase()}
                          </div>
                        )}
                      </div>
                      <div className="min-w-0 flex-1">
                        <p className="font-medium text-sm truncate">
                          {viewer.profile?.name || viewer.profile?.username || 'Foydalanuvchi'}
                        </p>
                        <div className="truncate">
                          <StarUsername username={viewer.profile?.username || 'user'} />
                        </div>
                      </div>
                      {likers.some(l => l.user_id === viewer.viewer_id) && (
                        <Heart className="h-4 w-4 text-red-500 fill-current" />
                      )}
                    </div>
                  ))}
                </div>
              )
            ) : (
              likers.length === 0 ? (
                <p className="text-center text-muted-foreground py-10">
                  Hali hech kim yoqtirmagan
                </p>
              ) : (
                <div className="grid grid-cols-2 gap-3 pb-6">
                  {likers.map((like) => (
                    <div
                      key={like.user_id}
                      className="flex items-center gap-3 p-3 rounded-2xl border border-border/60 bg-background/60 shadow-sm hover:shadow-md transition-shadow cursor-pointer active:scale-95"
                      onClick={() => {
                        if (like.user_id) {
                          setShowViewers(false);
                          onClose();
                          navigate(`/user/${like.user_id}`);
                        }
                      }}
                    >
                      <div className="w-11 h-11 rounded-2xl overflow-hidden bg-muted shrink-0">
                        {like.profile?.avatar_url ? (
                          <img
                            src={like.profile.avatar_url}
                            alt={like.profile.name || 'User'}
                            className="w-full h-full object-cover"
                          />
                        ) : (
                          <div className="w-full h-full flex items-center justify-center text-muted-foreground font-medium">
                            {(like.profile?.name || 'U').charAt(0).toUpperCase()}
                          </div>
                        )}
                      </div>
                      <div className="min-w-0 flex-1">
                        <p className="font-medium text-sm truncate">
                          {like.profile?.name || like.profile?.username || 'Foydalanuvchi'}
                        </p>
                        <div className="truncate">
                          <StarUsername username={like.profile?.username || 'user'} />
                        </div>
                      </div>
                      <Heart className="h-4 w-4 text-red-500 fill-current" />
                    </div>
                  ))}
                </div>
              )
            )}
          </ScrollArea>
        </SheetContent>
      </Sheet>

      <Sheet
        open={showCaption}
        onOpenChange={(open) => {
          setShowCaption(open);
          if (!open) setIsPaused(false);
        }}
      >
        <SheetContent side="bottom" className="h-[50vh] px-0">
          <div className="px-4">
            <SheetHeader>
              <SheetTitle>Izoh</SheetTitle>
            </SheetHeader>
          </div>
          <ScrollArea className="h-[calc(50vh-56px)] px-4">
            <div className="py-3 text-sm whitespace-pre-wrap break-words">
              {currentStory?.caption}
            </div>
          </ScrollArea>
        </SheetContent>
      </Sheet>

      <AlertDialog open={showDeleteDialog} onOpenChange={setShowDeleteDialog}>
        <AlertDialogContent onClick={(e) => e.stopPropagation()}>
          <AlertDialogHeader>
            <AlertDialogTitle>Hikoyani o'chirish</AlertDialogTitle>
            <AlertDialogDescription>
              Bu amalni bekor qilib bo'lmaydi. Hikoya butunlay o'chiriladi.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel onClick={() => setIsPaused(false)}>Bekor qilish</AlertDialogCancel>
            <AlertDialogAction
              onClick={handleDeleteStory}
              disabled={isDeleting}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              {isDeleting ? "O'chirilmoqda..." : "O'chirish"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );

  if (typeof document === 'undefined') return null;
  return createPortal(content, document.body);
};

const styleId = 'story-like-pop-style';
if (typeof document !== 'undefined' && !document.getElementById(styleId)) {
  const s = document.createElement('style');
  s.id = styleId;
  s.innerHTML = `@keyframes likePop{0%{transform:scale(.65);opacity:0}35%{transform:scale(1.12);opacity:1}100%{transform:scale(1);opacity:.95}}`;
  document.head.appendChild(s);
}

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const badgeVariants = cva(
  "inline-flex items-center rounded-full border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2",
  {
    variants: {
      variant: {
        default: "border-transparent bg-primary text-primary-foreground hover:bg-primary/80",
        secondary: "border-transparent bg-secondary text-secondary-foreground hover:bg-secondary/80",
        destructive: "border-transparent bg-destructive text-destructive-foreground hover:bg-destructive/80",
        outline: "text-foreground",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
);

export interface BadgeProps extends React.HTMLAttributes<HTMLDivElement>, VariantProps<typeof badgeVariants> {}

function Badge({ className, variant, ...props }: BadgeProps) {
  return <div className={cn(badgeVariants({ variant }), className)} {...props} />;
}

export { Badge, badgeVariants };

import * as React from "react";
import { Slot } from "@radix-ui/react-slot";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90",
        destructive: "bg-destructive text-destructive-foreground hover:bg-destructive/90",
        outline: "border border-input bg-background hover:bg-accent hover:text-accent-foreground",
        secondary: "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost: "hover:bg-accent hover:text-accent-foreground",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-10 px-4 py-2",
        sm: "h-9 rounded-md px-3",
        lg: "h-11 rounded-md px-8",
        icon: "h-10 w-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean;
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button";
    return <Comp className={cn(buttonVariants({ variant, size, className }))} ref={ref} {...props} />;
  },
);
Button.displayName = "Button";

export { Button, buttonVariants };

import * as React from "react";
import * as LabelPrimitive from "@radix-ui/react-label";
import { Slot } from "@radix-ui/react-slot";
import { Controller, ControllerProps, FieldPath, FieldValues, FormProvider, useFormContext } from "react-hook-form";

import { cn } from "@/lib/utils";
import { Label } from "@/components/ui/label";

const Form = FormProvider;

type FormFieldContextValue<
  TFieldValues extends FieldValues = FieldValues,
  TName extends FieldPath<TFieldValues> = FieldPath<TFieldValues>,
> = {
  name: TName;
};

const FormFieldContext = React.createContext<FormFieldContextValue>({} as FormFieldContextValue);

const FormField = <
  TFieldValues extends FieldValues = FieldValues,
  TName extends FieldPath<TFieldValues> = FieldPath<TFieldValues>,
>({
  ...props
}: ControllerProps<TFieldValues, TName>) => {
  return (
    <FormFieldContext.Provider value={{ name: props.name }}>
      <Controller {...props} />
    </FormFieldContext.Provider>
  );
};

const useFormField = () => {
  const fieldContext = React.useContext(FormFieldContext);
  const itemContext = React.useContext(FormItemContext);
  const { getFieldState, formState } = useFormContext();

  const fieldState = getFieldState(fieldContext.name, formState);

  if (!fieldContext) {
    throw new Error("useFormField should be used within <FormField>");
  }

  const { id } = itemContext;

  return {
    id,
    name: fieldContext.name,
    formItemId: `${id}-form-item`,
    formDescriptionId: `${id}-form-item-description`,
    formMessageId: `${id}-form-item-message`,
    ...fieldState,
  };
};

type FormItemContextValue = {
  id: string;
};

const FormItemContext = React.createContext<FormItemContextValue>({} as FormItemContextValue);

const FormItem = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => {
    const id = React.useId();

    return (
      <FormItemContext.Provider value={{ id }}>
        <div ref={ref} className={cn("space-y-2", className)} {...props} />
      </FormItemContext.Provider>
    );
  },
);
FormItem.displayName = "FormItem";

const FormLabel = React.forwardRef<
  React.ElementRef<typeof LabelPrimitive.Root>,
  React.ComponentPropsWithoutRef<typeof LabelPrimitive.Root>
>(({ className, ...props }, ref) => {
  const { error, formItemId } = useFormField();

  return <Label ref={ref} className={cn(error && "text-destructive", className)} htmlFor={formItemId} {...props} />;
});
FormLabel.displayName = "FormLabel";

const FormControl = React.forwardRef<React.ElementRef<typeof Slot>, React.ComponentPropsWithoutRef<typeof Slot>>(
  ({ ...props }, ref) => {
    const { error, formItemId, formDescriptionId, formMessageId } = useFormField();

    return (
      <Slot
        ref={ref}
        id={formItemId}
        aria-describedby={!error ? `${formDescriptionId}` : `${formDescriptionId} ${formMessageId}`}
        aria-invalid={!!error}
        {...props}
      />
    );
  },
);
FormControl.displayName = "FormControl";

const FormDescription = React.forwardRef<HTMLParagraphElement, React.HTMLAttributes<HTMLParagraphElement>>(
  ({ className, ...props }, ref) => {
    const { formDescriptionId } = useFormField();

    return <p ref={ref} id={formDescriptionId} className={cn("text-sm text-muted-foreground", className)} {...props} />;
  },
);
FormDescription.displayName = "FormDescription";

const FormMessage = React.forwardRef<HTMLParagraphElement, React.HTMLAttributes<HTMLParagraphElement>>(
  ({ className, children, ...props }, ref) => {
    const { error, formMessageId } = useFormField();
    const body = error ? String(error?.message) : children;

    if (!body) {
      return null;
    }

    return (
      <p ref={ref} id={formMessageId} className={cn("text-sm font-medium text-destructive", className)} {...props}>
        {body}
      </p>
    );
  },
);
FormMessage.displayName = "FormMessage";

export { useFormField, Form, FormItem, FormLabel, FormControl, FormDescription, FormMessage, FormField };

