import React, { createContext, useContext, useEffect, useState } from 'react';
import { supabase } from '@/integrations/supabase/client';
import type { User as SupabaseUser, Session } from '@supabase/supabase-js';
import { generateBaseUsername, ensureUniqueUsername } from '@/utils/usernameUtils';
import { signOutFromGoogleNative } from '@/lib/googleSignIn';

interface Profile {
  id: string;
  name: string | null;
  username: string | null;
  bio: string | null;
  avatar_url: string | null;
  theme_mode?: string | null;
  bg_theme?: string | null;
  gender: string | null;
  hide_highlights?: boolean | null;
  hide_collections?: boolean | null;
  is_private?: boolean | null;
  hide_online_status?: boolean | null;
  hide_mentions?: boolean | null;
  hide_saved_posts?: boolean | null;
  subscription_tier?: 'free' | 'pro' | string;
  created_at: string;
  updated_at: string;
}

interface AuthContextType {
  user: SupabaseUser | null;
  profile: Profile | null;
  session: Session | null;
  isLoading: boolean;
  isAuthenticated: boolean;
  logout: () => Promise<void>;
  refreshProfile: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<SupabaseUser | null>(null);
  const [profile, setProfile] = useState<Profile | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  const fetchProfile = async (userId: string) => {
    try {
       
      const sb: any = supabase;
      const { data, error } = await sb
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .maybeSingle();

      if (error) {
        console.error('Error fetching profile:', error);
        return null;
      }

      // If profile row is missing OR incomplete, self-heal from OAuth metadata
      if (!data || !data.username || !data.name || data.name === 'Foydalanuvchi' || !data.avatar_url) {
        // Generate a username for users who don't have one (e.g., Google login)
        // Also sync their name from OAuth metadata if missing
        const { data: userData } = await supabase.auth.getUser();
        const user = userData?.user;
        const currentUserEmail = user?.email;
        const currentFullName = user?.user_metadata?.full_name || user?.user_metadata?.name;
        const currentAvatarUrl =
          (user?.user_metadata as { avatar_url?: string; picture?: string } | undefined)?.avatar_url ||
          (user?.user_metadata as { avatar_url?: string; picture?: string } | undefined)?.picture;
        
        const updates: Partial<Profile> = {};

        if ((!data || !data.username) && currentUserEmail) {
          const baseUsername = generateBaseUsername(currentUserEmail);
          const finalUsername = await ensureUniqueUsername(supabase, baseUsername, userId);
          updates.username = finalUsername;
        }

        if ((!data || !data.name || data.name === 'Foydalanuvchi') && currentFullName) {
          updates.name = currentFullName;
        }

        if ((!data || !data.avatar_url) && currentAvatarUrl) {
          updates.avatar_url = currentAvatarUrl;
        }
        
        if (Object.keys(updates).length > 0) {
          console.log('Fixing profile data for user:', userId, updates);
          const { data: updatedData, error: updateError } = await sb
            .from('profiles')
            .upsert({ id: userId, ...updates }, { onConflict: 'id' })
            .select()
            .single();
            
          if (updateError) {
            console.error('Error auto-updating profile:', updateError);
          } else {
            console.log('Successfully auto-updated profile for user:', userId, updatedData);
            return updatedData as Profile;
          }
        }
      }

      return data as Profile | null;
    } catch (error) {
      console.error('Error fetching profile:', error);
      return null;
    }
  };

  const refreshProfile = async () => {
    if (user) {
      const profileData = await fetchProfile(user.id);
      setProfile(profileData);
    }
  };

  // Update last_seen periodically
  useEffect(() => {
    if (!user) return;
    
    const updateLastSeen = () => {
       
      const sb: any = supabase;
      sb.from('profiles').update({ last_seen: new Date().toISOString() }).eq('id', user.id).then();
    };
    
    updateLastSeen(); // on mount
    const interval = setInterval(updateLastSeen, 60000); // every 60s
    
    return () => clearInterval(interval);
  }, [user]);

  useEffect(() => {
    let isMounted = true;

    // Set up auth state listener FIRST
    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      async (event, session) => {
        if (!isMounted) return;

        console.log('Auth state changed:', event, session?.user?.email);
        
        setSession(session);
        setUser(session?.user ?? null);

        if (session?.user) {
          setTimeout(async () => {
            if (isMounted) {
              const profileData = await fetchProfile(session.user.id);
              if (isMounted) {
                setProfile(profileData);
              }
            }
          }, 0);
        } else {
          setProfile(null);
        }
        
        setIsLoading(false);
      }
    );

    // Then check for existing session
    const initializeAuth = async () => {
      try {
        const hashParams = new URLSearchParams(window.location.hash.substring(1));
        const accessToken = hashParams.get('access_token');
        
        if (accessToken) {
          console.log('OAuth callback detected, waiting for auth state change...');
          return;
        }

        const { data: { session } } = await supabase.auth.getSession();
        
        if (!isMounted) return;
        
        if (session) {
          setSession(session);
          setUser(session.user);
          const profileData = await fetchProfile(session.user.id);
          if (isMounted) {
            setProfile(profileData);
          }
        }
      } catch (error) {
        console.error('Error initializing auth:', error);
      } finally {
        if (isMounted) {
          setIsLoading(false);
        }
      }
    };

    initializeAuth();

    return () => {
      isMounted = false;
      subscription.unsubscribe();
    };
  }, []);

  const logout = async () => {
    await signOutFromGoogleNative();
    await supabase.auth.signOut();
    setUser(null);
    setProfile(null);
    setSession(null);
  };

  return (
    <AuthContext.Provider 
      value={{ 
        user, 
        profile, 
        session,
        isLoading, 
        isAuthenticated: !!user,
        logout,
        refreshProfile
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import React, { createContext, useContext, useEffect, useMemo, useState } from 'react';
import { useLocalStorage } from '@/hooks/useLocalStorage';

export type ThemeMode = 'light' | 'dark' | 'system';
export type BackgroundTheme = 'none' | 'aurora' | 'sunset' | 'ocean';

interface ThemeContextType {
  mode: ThemeMode;
  setMode: (mode: ThemeMode) => void;
  bgTheme: BackgroundTheme;
  setBgTheme: (bg: BackgroundTheme) => void;
  setOverride: (override: { mode?: ThemeMode; bgTheme?: BackgroundTheme } | null) => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

/** Update theme-color meta tag and Capacitor StatusBar (if available) */
const applyStatusBar = async (isDark: boolean) => {
  // 1. PWA meta tag
  const color = isDark ? '#000000' : '#ffffff';
  let meta = document.querySelector<HTMLMetaElement>('meta[name="theme-color"]');
  if (!meta) {
    meta = document.createElement('meta');
    meta.name = 'theme-color';
    document.head.appendChild(meta);
  }
  meta.content = color;

  // 2. Capacitor native StatusBar (Android / iOS)
  try {
    const { StatusBar, Style } = await import('@capacitor/status-bar');

    // Set icon style (white or black icons)
    await StatusBar.setStyle({ style: isDark ? Style.Dark : Style.Light });

    // CRITICAL: Make status bar transparent and overlay the webview
    // This allows the app background to stretch to the very top
    await StatusBar.setOverlaysWebView({ overlay: true });

    // On some Android versions, we might still need to set color to transparent explicitly
    // Note: Use a very light alpha if pure transparent is ignored by the OS
    try {
      await StatusBar.setBackgroundColor({ color: '#00000000' }); // Hex with 00 alpha
    } catch {
      // BackgroundColor might fail if overlay is active on some platforms, ignore
    }
  } catch {
    // Web or plugin not available ΓÇö ignore silently
  }
};

export const ThemeProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [mode, setMode] = useLocalStorage<ThemeMode>('theme-mode', 'dark');
  const [bgTheme, setBgTheme] = useLocalStorage<BackgroundTheme>('bg-theme', 'none');
  const [override, setOverride] = useState<{ mode?: ThemeMode; bgTheme?: BackgroundTheme } | null>(null);

  const effectiveMode = override?.mode ?? mode;
  const effectiveBgTheme = override?.bgTheme ?? bgTheme;

  useEffect(() => {
    const root = document.documentElement;

    const applyTheme = (isDark: boolean) => {
      if (isDark) {
        root.classList.add('dark');
      } else {
        root.classList.remove('dark');
      }
      void applyStatusBar(isDark);
    };

    if (effectiveMode === 'system') {
      const mq = window.matchMedia('(prefers-color-scheme: dark)');
      applyTheme(mq.matches);
      const handler = (e: MediaQueryListEvent) => applyTheme(e.matches);
      mq.addEventListener('change', handler);
      return () => mq.removeEventListener('change', handler);
    } else {
      applyTheme(effectiveMode === 'dark');
    }
  }, [effectiveMode]);

  return (
    <ThemeContext.Provider
      value={useMemo(
        () => ({
          mode: effectiveMode,
          setMode,
          bgTheme: effectiveBgTheme,
          setBgTheme,
          setOverride,
        }),
        [effectiveBgTheme, effectiveMode, setBgTheme, setMode]
      )}
    >
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) throw new Error('useTheme must be used within ThemeProvider');
  return context;
};

import { useState, useEffect, useCallback, useRef } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';

interface Position {
  x: number;
  y: number;
}

interface Connection {
  from: Position;
  to: Position;
  type: 'parent' | 'child' | 'spouse';
  path?: string; // AI-generated SVG path
  fromMemberId?: string;
  toMemberId?: string;
}

interface MemberPosition {
  id: string;
  x: number;
  y: number;
  width: number;
  height: number;
  relationType: string;
}

interface HeartPosition {
  id: string;
  x: number;
  y: number;
  width: number;
  height: number;
}

// Fallback path generation when AI is not available
const generateFallbackPath = (from: Position, to: Position, type: 'parent' | 'child' | 'spouse'): string => {
  const dx = to.x - from.x;
  const dy = to.y - from.y;
  
  if (type === 'spouse') {
    const midY = from.y;
    return `M ${from.x} ${from.y} Q ${from.x + dx / 2} ${midY - 10} ${to.x} ${to.y}`;
  }
  
  if (type === 'parent') {
    const controlY = from.y - Math.abs(dy) * 0.5;
    return `M ${from.x} ${from.y} C ${from.x} ${controlY}, ${to.x} ${to.y + Math.abs(dy) * 0.3}, ${to.x} ${to.y}`;
  }
  
  const controlY = from.y + Math.abs(dy) * 0.5;
  return `M ${from.x} ${from.y} C ${from.x} ${controlY}, ${to.x} ${to.y - Math.abs(dy) * 0.3}, ${to.x} ${to.y}`;
};

export const useAIConnectorLines = (
  containerRef: React.RefObject<HTMLDivElement>,
  memberElements: Map<string, HTMLElement | null>,
  members: any[],
  heartElements: Map<string, HTMLElement | null>,
  useAI: boolean = true
) => {
  const [connections, setConnections] = useState<Connection[]>([]);
  const [isCalculating, setIsCalculating] = useState(false);
  const { toast } = useToast();
  const lastCalculationRef = useRef<string>('');
  const debounceTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Calculate positions from DOM elements
  const calculatePositions = useCallback(() => {
    if (!containerRef.current) return null;
    
    const containerRect = containerRef.current.getBoundingClientRect();
    
    const memberPositions: MemberPosition[] = [];
    const heartPositions: HeartPosition[] = [];

    memberElements.forEach((el, id) => {
      if (el) {
        const rect = el.getBoundingClientRect();
        const member = members.find(m => m.id === id);
        memberPositions.push({
          id,
          x: rect.left - containerRect.left + rect.width / 2,
          y: rect.top - containerRect.top + rect.height / 2,
          width: rect.width,
          height: rect.height,
          relationType: member?.relation_type || 'unknown',
        });
      }
    });

    heartElements.forEach((el, id) => {
      if (el) {
        const rect = el.getBoundingClientRect();
        heartPositions.push({
          id,
          x: rect.left - containerRect.left + rect.width / 2,
          y: rect.top - containerRect.top + rect.height / 2,
          width: rect.width,
          height: rect.height,
        });
      }
    });

    return {
      members: memberPositions,
      hearts: heartPositions,
      containerWidth: containerRect.width,
      containerHeight: containerRect.height,
    };
  }, [containerRef, memberElements, members, heartElements]);

  // Calculate connections using AI
  const calculateWithAI = useCallback(async () => {
    const positions = calculatePositions();
    if (!positions || positions.members.length === 0) return;

    // Create hash to avoid duplicate calculations
    const positionHash = JSON.stringify(positions);
    if (positionHash === lastCalculationRef.current) return;
    
    setIsCalculating(true);
    
    try {
      const { data, error } = await supabase.functions.invoke('calculate-family-lines', {
        body: positions,
      });

      if (error) throw error;

      if (data?.connections) {
        const aiConnections: Connection[] = data.connections.map((conn: any) => {
          // Find positions for from/to
          const fromMember = positions.members.find(m => m.id === conn.fromId);
          const toHeart = positions.hearts.find(h => h.id === conn.toId);
          const toMember = positions.members.find(m => m.id === conn.toId);
          const fromHeart = positions.hearts.find(h => h.id === conn.fromId);

          return {
            from: {
              x: fromMember?.x || fromHeart?.x || 0,
              y: fromMember?.y - (fromMember?.height || 0) / 2 || fromHeart?.y + (fromHeart?.height || 0) / 2 || 0,
            },
            to: {
              x: toMember?.x || toHeart?.x || 0,
              y: toMember?.y - (toMember?.height || 0) / 2 || toHeart?.y + (toHeart?.height || 0) / 2 || 0,
            },
            type: conn.type,
            path: conn.path,
            fromMemberId: conn.fromId,
            toMemberId: conn.toId,
          };
        });

        setConnections(aiConnections);
        lastCalculationRef.current = positionHash;
      }
    } catch (error: any) {
      console.error('AI calculation error:', error);
      // Fallback to standard calculation
      calculateFallback();
    } finally {
      setIsCalculating(false);
    }
  }, [calculatePositions]);

  // Fallback calculation without AI
  const calculateFallback = useCallback(() => {
    if (!containerRef.current) return;
    
    const containerRect = containerRef.current.getBoundingClientRect();
    const newConnections: Connection[] = [];

    // Calculate parent-to-member connections
    members.forEach((member) => {
      const memberEl = memberElements.get(member.id);
      if (!memberEl) return;

      const memberRect = memberEl.getBoundingClientRect();
      const memberTop = {
        x: memberRect.left - containerRect.left + memberRect.width / 2,
        y: memberRect.top - containerRect.top,
      };

      // Check for parents-of-X heart element
      const parentsHeartEl = heartElements.get(`parents-of-${member.id}`);
      if (parentsHeartEl) {
        const heartRect = parentsHeartEl.getBoundingClientRect();
        const from = memberTop;
        const to = {
          x: heartRect.left - containerRect.left + heartRect.width / 2,
          y: heartRect.top - containerRect.top + heartRect.height,
        };
        
        newConnections.push({
          from,
          to,
          type: 'parent',
          path: generateFallbackPath(from, to, 'parent'),
          fromMemberId: member.id,
          toMemberId: 'parents',
        });
      } else {
        // Find fathers of this member
        const fathers = members.filter(m => 
          m.relation_type === `father_of_${member.id}` || 
          m.relation_type === `father_2_of_${member.id}`
        );

        fathers.forEach((father) => {
          const fatherEl = memberElements.get(father.id);
          if (fatherEl) {
            const fatherRect = fatherEl.getBoundingClientRect();
            const from = memberTop;
            const to = {
              x: fatherRect.left - containerRect.left + fatherRect.width / 2,
              y: fatherRect.top - containerRect.top + fatherRect.height,
            };
            
            newConnections.push({
              from,
              to,
              type: 'parent',
              path: generateFallbackPath(from, to, 'parent'),
              fromMemberId: member.id,
              toMemberId: father.id,
            });
          }
        });

        // Find mothers of this member
        const mothers = members.filter(m => 
          m.relation_type === `mother_of_${member.id}` || 
          m.relation_type === `mother_2_of_${member.id}`
        );

        mothers.forEach((mother) => {
          const motherEl = memberElements.get(mother.id);
          if (motherEl) {
            const motherRect = motherEl.getBoundingClientRect();
            const from = memberTop;
            const to = {
              x: motherRect.left - containerRect.left + motherRect.width / 2,
              y: motherRect.top - containerRect.top + motherRect.height,
            };
            
            newConnections.push({
              from,
              to,
              type: 'parent',
              path: generateFallbackPath(from, to, 'parent'),
              fromMemberId: member.id,
              toMemberId: mother.id,
            });
          }
        });
      }
    });

    // Calculate child connections (from heart to child)
    heartElements.forEach((heartEl, heartKey) => {
      if (!heartEl || heartKey.startsWith('parent-') || heartKey.startsWith('parents-of-')) return;

      const heartRect = heartEl.getBoundingClientRect();
      const heartCenter = {
        x: heartRect.left - containerRect.left + heartRect.width / 2,
        y: heartRect.top - containerRect.top + heartRect.height,
      };

      const parentMemberId = heartKey;
      const childMembers = members.filter(m => 
        m.relation_type.startsWith(`child_of_${parentMemberId}`)
      );

      childMembers.forEach((child) => {
        const childEl = memberElements.get(child.id);
        if (childEl) {
          const childRect = childEl.getBoundingClientRect();
          const from = heartCenter;
          const to = {
            x: childRect.left - containerRect.left + childRect.width / 2,
            y: childRect.top - containerRect.top,
          };
          
          newConnections.push({
            from,
            to,
            type: 'child',
            path: generateFallbackPath(from, to, 'child'),
            fromMemberId: parentMemberId,
            toMemberId: child.id,
          });
        }
      });
    });

    setConnections(newConnections);
  }, [containerRef, memberElements, members, heartElements]);

  // Main calculation function with debounce
  const calculate = useCallback(() => {
    if (debounceTimerRef.current) {
      clearTimeout(debounceTimerRef.current);
    }

    debounceTimerRef.current = setTimeout(() => {
      if (useAI) {
        calculateWithAI();
      } else {
        calculateFallback();
      }
    }, 200);
  }, [useAI, calculateWithAI, calculateFallback]);

  // Effect to trigger calculation
  useEffect(() => {
    const timer = setTimeout(calculate, 150);
    
    window.addEventListener('resize', calculate);
    
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', calculate);
      if (debounceTimerRef.current) {
        clearTimeout(debounceTimerRef.current);
      }
    };
  }, [calculate, members]);

  return { connections, isCalculating, recalculate: calculate };
};

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

export interface UserStoryStatus {
  userId: string;
  hasStory: boolean;
  hasUnviewed: boolean;
}

export const useFamilyStories = (userIds: string[]) => {
  const { user } = useAuth();
  const [storyStatuses, setStoryStatuses] = useState<Map<string, UserStoryStatus>>(new Map());
  const [isLoading, setIsLoading] = useState(false);

  const fetchStoryStatuses = useCallback(async () => {
    if (!user?.id || userIds.length === 0) return;

    setIsLoading(true);
    try {
      // Get active stories for these users
      const { data: stories, error } = await supabase
        .from('stories')
        .select('id, user_id')
        .in('user_id', userIds)
        .gt('expires_at', new Date().toISOString());

      if (error) throw error;

      if (!stories || stories.length === 0) {
        setStoryStatuses(new Map());
        return;
      }

      // Get viewed stories by current user
      const { data: views } = await supabase
        .from('story_views')
        .select('story_id')
        .eq('viewer_id', user.id)
        .in('story_id', stories.map(s => s.id));

      const viewedIds = new Set(views?.map(v => v.story_id) || []);

      // Build status map
      const statusMap = new Map<string, UserStoryStatus>();
      userIds.forEach(userId => {
        const userStories = stories.filter(s => s.user_id === userId);
        const hasStory = userStories.length > 0;
        const hasUnviewed = userStories.some(s => !viewedIds.has(s.id));
        statusMap.set(userId, { userId, hasStory, hasUnviewed });
      });

      setStoryStatuses(statusMap);
    } catch (error) {
      console.error('Error fetching story statuses:', error);
    } finally {
      setIsLoading(false);
    }
  }, [user?.id, userIds.join(',')]);

  useEffect(() => {
    fetchStoryStatuses();
  }, [fetchStoryStatuses]);

  const getStoryStatus = useCallback((userId: string): UserStoryStatus => {
    return storyStatuses.get(userId) || { userId, hasStory: false, hasUnviewed: false };
  }, [storyStatuses]);

  return {
    storyStatuses,
    getStoryStatus,
    isLoading,
    refetch: fetchStoryStatuses,
  };
};

import { useState, useCallback, useEffect, useRef } from 'react';
import { FamilyMember, AddMemberData, MergedProfileInfo } from '@/types/family';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { parseFamilyTreeData } from '@/utils/treeParser';
import { useQuery, useQueryClient } from '@tanstack/react-query';

// Unique client ID to prevent real-time feedback loops
const CLIENT_ID = crypto.randomUUID();
const generateId = () => crypto.randomUUID();

export const useLocalFamilyTree = () => {
  const { user, profile } = useAuth();
  const [members, setMembers] = useState<Record<string, FamilyMember>>({});
  const [rootId, setRootId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [networkId, setNetworkId] = useState<string | null>(null);
  const [isSharedNetwork, setIsSharedNetwork] = useState(false);
  
  // Prevent updates while dragging
  const isDraggingRef = useRef(false);
  const pendingUpdatesRef = useRef<Map<string, { x: number; y: number }>>(new Map());

  // Get or create family network for current user
  const getOrCreateNetworkId = useCallback(async (): Promise<string | null> => {
    if (!user?.id) return null;
    
    // Check if user already has a network
    const { data: userProfile } = await supabase
      .from('profiles')
      .select('family_network_id')
      .eq('id', user.id)
      .single();
    
    if (userProfile?.family_network_id) {
      return userProfile.family_network_id;
    }
    
    // Create new network
    const { data: newNetwork, error } = await supabase
      .from('family_networks')
      .insert({})
      .select('id')
      .single();
    
    if (error || !newNetwork) {
      console.error('Error creating network:', error);
      return null;
    }
    
    // Update user profile with network ID
    await supabase
      .from('profiles')
      .update({ family_network_id: newNetwork.id })
      .eq('id', user.id);
    
    return newNetwork.id;
  }, [user?.id]);

  const queryClient = useQueryClient();

  const { data: treeData, isLoading: isQueryLoading, refetch: refetchTree } = useQuery({
    queryKey: ['familyTree', user?.id],
    queryFn: async () => {
      if (!user?.id) throw new Error('Not logged in');
      
      const userNetworkId = await getOrCreateNetworkId();
      if (!userNetworkId) throw new Error('No network ID');

      const { data: networkUsers } = await supabase
        .from('profiles')
        .select('id')
        .eq('family_network_id', userNetworkId);
      
      const userIds = networkUsers?.map(u => u.id) || [user.id];
      const isShared = (networkUsers?.length || 1) > 1;

      const [membersRes, positionsRes] = await Promise.all([
        supabase.from('family_tree_members').select('*').in('owner_id', userIds),
        supabase.from('node_positions').select('*').eq('network_id', userNetworkId)
      ]);

      if (membersRes.error) throw membersRes.error;
      if (positionsRes.error) throw positionsRes.error;

      const dbMembers = membersRes.data || [];
      const dbPositions = positionsRes.data || [];

      const { membersMap, rootId: newRootId, newPositions } = parseFamilyTreeData(
        dbMembers,
        dbPositions,
        user.id
      );

      // Save any auto-corrected positions silently in background
      if (newPositions.length > 0) {
        const BATCH_SIZE = 50;
        await Promise.all(
          Array.from({ length: Math.ceil(newPositions.length / BATCH_SIZE) }).map((_, i) => {
            const batch = newPositions.slice(i * BATCH_SIZE, (i + 1) * BATCH_SIZE).map((pos) => ({
              member_id: pos.member_id,
              owner_id: user.id,
              x: pos.x,
              y: pos.y,
              updated_by: CLIENT_ID,
              network_id: userNetworkId,
            }));
            return supabase.from('node_positions').upsert(batch, { onConflict: 'member_id,owner_id' });
          })
        ).catch(err => console.error("Auto-correction save failed:", err));
      }

      return { membersMap, newRootId, userNetworkId, isShared };
    },
    enabled: !!user?.id,
    staleTime: 0, // Always check for updates on remount (navigation)
    gcTime: 10 * 60 * 1000,   // 10 minutes garbage collection
  });

  // Sync data to local editor state when query finishes
  useEffect(() => {
    if (isQueryLoading) {
      if (Object.keys(members).length === 0) setIsLoading(true);
    } else {
      setIsLoading(false);
      setIsRefreshing(false);
    }

    if (treeData && !isDraggingRef.current) {
      setMembers(treeData.membersMap);
      setRootId(treeData.newRootId);
      setNetworkId(treeData.userNetworkId);
      setIsSharedNetwork(treeData.isShared);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [treeData, isQueryLoading]);

  // Handle case when not logged in
  useEffect(() => {
    if (!user?.id) {
      setIsLoading(false);
    }
  }, [user?.id]);

  // Keep loadData wrapper for external calls
  const loadData = useCallback(async (isInitial = true) => {
    if (isInitial) setIsLoading(true);
    else setIsRefreshing(true);
    await refetchTree();
  }, [refetchTree]);

  // Listen for manual reload requests
  useEffect(() => {
    const handleReload = () => loadData(false);
    window.addEventListener('family-tree-reload', handleReload);
    return () => window.removeEventListener('family-tree-reload', handleReload);
  }, [loadData]);
 
  // Real-time subscriptions
  useEffect(() => {
    if (!user?.id || !networkId) return;

    const channel = supabase
      .channel('family_tree_sync')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'family_tree_members' },
        (payload) => {
          // Reload on any member change in network (will filter by network in loadData)
          loadData(false);
        }
      )
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'node_positions', filter: `owner_id=eq.${user.id}` },
        (payload) => {
          if (isDraggingRef.current) {
            const p = payload.new as { member_id: string; x: number; y: number; updated_by: string };
            if (p) pendingUpdatesRef.current.set(p.member_id, { x: p.x, y: p.y });
            return;
          }
          
          if (payload.eventType === 'INSERT' || payload.eventType === 'UPDATE') {
            const p = payload.new as { member_id: string; x: number; y: number; updated_by: string };
            if (p.updated_by === CLIENT_ID) return;
            
            setMembers((prev) => {
              if (!prev[p.member_id]) return prev;
              return {
                ...prev,
                [p.member_id]: { ...prev[p.member_id], position: { x: p.x, y: p.y } },
              };
            });
          }
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [user?.id, networkId, loadData]);

  // Update position
  const updatePosition = useCallback(async (memberId: string, position: { x: number; y: number }) => {
    if (!user?.id) return;
    
    isDraggingRef.current = false;

    pendingUpdatesRef.current.forEach((pos, id) => {
      if (id !== memberId) {
        setMembers((prev) => {
          if (!prev[id]) return prev;
          return { ...prev, [id]: { ...prev[id], position: pos } };
        });
      }
    });
    pendingUpdatesRef.current.clear();

    setMembers((prev) => {
      if (!prev[memberId]) return prev;
      return { ...prev, [memberId]: { ...prev[memberId], position } };
    });

    await supabase
      .from('node_positions')
      .upsert({
        member_id: memberId,
        owner_id: user.id,
        network_id: networkId,
        x: position.x,
        y: position.y,
        updated_by: CLIENT_ID,
        updated_at: new Date().toISOString(),
      }, { onConflict: 'member_id,owner_id' });
      
    // Invalidate query to ensure cache stays synced with local state
    queryClient.invalidateQueries({ queryKey: ['familyTree', user.id] });
  }, [user?.id, networkId, queryClient]);

  // Add initial couple
  const addInitialCouple = useCallback(async () => {
    if (!user?.id) return { husbandId: '', wifeId: '' };

    const husbandId = generateId();
    const wifeId = generateId();

    try {
      await supabase.from('family_tree_members').insert([
        {
          id: husbandId,
          owner_id: user.id,
          member_name: '',
          gender: 'male',
          relation_type: 'self',
          is_placeholder: true,
          avatar_url: null,
          birth_year: null,
          death_year: null,
        },
        {
          id: wifeId,
          owner_id: user.id,
          member_name: '',
          gender: 'female',
          relation_type: `spouse_of_${husbandId}`,
          is_placeholder: true,
          avatar_url: null,
          birth_year: null,
          death_year: null,
        },
      ]);

      await supabase.from('node_positions').insert([
        { member_id: husbandId, owner_id: user.id, network_id: networkId!, x: 0, y: 0, updated_by: CLIENT_ID },
        { member_id: wifeId, owner_id: user.id, network_id: networkId!, x: 180, y: 0, updated_by: CLIENT_ID },
      ]);

      setMembers({
        [husbandId]: {
          id: husbandId,
          name: '',
          gender: 'male',
          spouseId: wifeId,
          position: { x: 0, y: 0 },
          childrenIds: [],
          birthYear: undefined,
          deathYear: undefined,
          photoUrl: undefined,
        },
        [wifeId]: {
          id: wifeId,
          name: '',
          gender: 'female',
          spouseId: husbandId,
          position: { x: 180, y: 0 },
          childrenIds: [],
          birthYear: undefined,
          deathYear: undefined,
          photoUrl: undefined,
        },
      });
      setRootId(husbandId);

      return { husbandId, wifeId };
    } catch (error) {
      console.error('Error creating initial couple:', error);
      return { husbandId: '', wifeId: '' };
    }
  }, [user?.id]);

  // Update member info
  const updateMember = useCallback(async (id: string, updates: Partial<FamilyMember>) => {
    if (!user?.id) return;

    // Get current member to find linkedUserId
    const currentMember = members[id];
    const linkedUserId = currentMember?.linkedUserId;

    setMembers((prev) => {
      if (!prev[id]) return prev;
      return { ...prev, [id]: { ...prev[id], ...updates } };
    });

    const dbUpdates: Record<string, unknown> = {};
    if (updates.name !== undefined) dbUpdates.member_name = updates.name;
    if (updates.photoUrl !== undefined) dbUpdates.avatar_url = updates.photoUrl || null;
    if (updates.gender !== undefined) dbUpdates.gender = updates.gender;
    if (updates.birthYear !== undefined) dbUpdates.birth_year = updates.birthYear ?? null;
    if (updates.deathYear !== undefined) dbUpdates.death_year = updates.deathYear ?? null;
    if (updates.coverUrl !== undefined) dbUpdates.cover_url = updates.coverUrl || null;

    if (Object.keys(dbUpdates).length > 0) {
      if (linkedUserId) {
        // Sync across ALL trees that have this linked user
        await supabase
          .from('family_tree_members')
          .update(dbUpdates)
          .eq('linked_user_id', linkedUserId);

        // If this IS our own linked profile, also update the main profiles table
        if (linkedUserId === user.id) {
          const profileUpdates: Record<string, unknown> = {};
          if (updates.name !== undefined) profileUpdates.name = updates.name;
          if (updates.photoUrl !== undefined) profileUpdates.avatar_url = updates.photoUrl || null;
          if (updates.coverUrl !== undefined) profileUpdates.cover_url = updates.coverUrl || null;

          if (Object.keys(profileUpdates).length > 0) {
            await supabase.from('profiles').update(profileUpdates).eq('id', user.id);
          }
        }
      } else {
        // Regular non-linked member: update only the specific row
        await supabase
          .from('family_tree_members')
          .update(dbUpdates)
          .eq('id', id)
          .or(`owner_id.eq.${user.id},linked_user_id.eq.${user.id}`);
      }
    }
  }, [user?.id, members]);

  // Remove member
  const removeMember = useCallback(async (id: string) => {
    if (!user?.id) return;

    setMembers((prev) => {
      const member = prev[id];
      if (!member) return prev;

      const next = { ...prev };
      delete next[id];

      if (member.spouseId && next[member.spouseId]) {
        next[member.spouseId] = { ...next[member.spouseId], spouseId: undefined };
      }
      member.parentIds?.forEach((pid) => {
        if (next[pid]) {
          next[pid] = { ...next[pid], childrenIds: next[pid].childrenIds?.filter((c) => c !== id) };
        }
      });
      member.childrenIds?.forEach((cid) => {
        if (next[cid]) {
          next[cid] = { ...next[cid], parentIds: next[cid].parentIds?.filter((p) => p !== id) };
        }
      });

      return next;
    });

    await supabase.from('family_tree_members').delete().eq('id', id).eq('owner_id', user.id);
  }, [user?.id]);

  // Add parents
  const addParents = useCallback(async (childId: string, fatherData: AddMemberData, motherData: AddMemberData) => {
    if (!user?.id) return { fatherId: '', motherId: '' };

    const child = members[childId];
    const childPos = child?.position || { x: 0, y: 0 };
    const fatherId = generateId();
    const motherId = generateId();

    const fatherPos = { x: childPos.x - 90, y: childPos.y - 200 };
    const motherPos = { x: childPos.x + 90, y: childPos.y - 200 };

    try {
      await supabase.from('family_tree_members').insert([
        {
          id: fatherId,
          owner_id: user.id,
          member_name: fatherData.name || '',
          gender: 'male',
          relation_type: `father_of_${childId}`,
          is_placeholder: true,
          avatar_url: fatherData.photoUrl || null,
          birth_year: fatherData.birthYear ?? null,
          death_year: fatherData.deathYear ?? null,
        },
        {
          id: motherId,
          owner_id: user.id,
          member_name: motherData.name || '',
          gender: 'female',
          relation_type: `mother_of_${childId}`,
          is_placeholder: true,
          avatar_url: motherData.photoUrl || null,
          birth_year: motherData.birthYear ?? null,
          death_year: motherData.deathYear ?? null,
        },
      ]);

      await supabase.from('node_positions').insert([
        { member_id: fatherId, owner_id: user.id, network_id: networkId!, x: fatherPos.x, y: fatherPos.y, updated_by: CLIENT_ID },
        { member_id: motherId, owner_id: user.id, network_id: networkId!, x: motherPos.x, y: motherPos.y, updated_by: CLIENT_ID },
      ]);

      setMembers((prev) => ({
        ...prev,
        [fatherId]: {
          id: fatherId,
          name: fatherData.name || '',
          gender: 'male',
          spouseId: motherId,
          position: fatherPos,
          childrenIds: [childId],
          photoUrl: fatherData.photoUrl,
          birthYear: fatherData.birthYear,
          deathYear: fatherData.deathYear,
        },
        [motherId]: {
          id: motherId,
          name: motherData.name || '',
          gender: 'female',
          spouseId: fatherId,
          position: motherPos,
          childrenIds: [childId],
          photoUrl: motherData.photoUrl,
          birthYear: motherData.birthYear,
          deathYear: motherData.deathYear,
        },
        [childId]: { ...prev[childId], parentIds: [fatherId, motherId] },
      }));

      return { fatherId, motherId };
    } catch (error) {
      console.error('Error adding parents:', error);
      return { fatherId: '', motherId: '' };
    }
  }, [user?.id, members]);

  // Add spouse
  const addSpouse = useCallback(async (memberId: string, spouseData: AddMemberData) => {
    const member = members[memberId];
    if (!member || !user?.id) return null;

    const spouseId = generateId();
    const memberPos = member.position || { x: 0, y: 0 };
    const spousePos = { x: memberPos.x + (member.gender === 'male' ? 180 : -180), y: memberPos.y };

    try {
      await supabase.from('family_tree_members').insert({
        id: spouseId,
        owner_id: user.id,
        member_name: spouseData.name || '',
        gender: spouseData.gender,
        relation_type: `spouse_of_${memberId}`,
        is_placeholder: true,
        avatar_url: spouseData.photoUrl || null,
        birth_year: spouseData.birthYear ?? null,
        death_year: spouseData.deathYear ?? null,
      });

      await supabase.from('node_positions').insert({
        member_id: spouseId,
        owner_id: user.id,
        network_id: networkId!,
        x: spousePos.x,
        y: spousePos.y,
        updated_by: CLIENT_ID,
      });

      setMembers((prev) => ({
        ...prev,
        [memberId]: { ...prev[memberId], spouseId },
        [spouseId]: {
          id: spouseId,
          name: spouseData.name || '',
          gender: spouseData.gender,
          spouseId: memberId,
          position: spousePos,
          childrenIds: [],
          photoUrl: spouseData.photoUrl,
          birthYear: spouseData.birthYear,
          deathYear: spouseData.deathYear,
        },
      }));

      return spouseId;
    } catch (error) {
      console.error('Error adding spouse:', error);
      return null;
    }
  }, [user?.id, members]);

  // Add child
  const addChild = useCallback(async (parentId: string, childData: AddMemberData) => {
    const parent = members[parentId];
    if (!parent || !user?.id) return null;

    const childId = generateId();
    const parentPos = parent.position || { x: 0, y: 0 };
    const spousePos = parent.spouseId ? members[parent.spouseId]?.position : null;
    
    const centerX = spousePos ? (parentPos.x + spousePos.x) / 2 : parentPos.x;
    const siblingCount = parent.childrenIds?.length || 0;
    const childPos = { x: centerX + (siblingCount * 150), y: parentPos.y + 200 };

    const parentIds = parent.spouseId ? [parentId, parent.spouseId] : [parentId];

    try {
      await supabase.from('family_tree_members').insert({
        id: childId,
        owner_id: user.id,
        member_name: childData.name || '',
        gender: childData.gender,
        relation_type: `child_of_${parentId}_${siblingCount + 1}`,
        is_placeholder: true,
        avatar_url: childData.photoUrl || null,
        birth_year: childData.birthYear ?? null,
        death_year: childData.deathYear ?? null,
      });

      await supabase.from('node_positions').insert({
        member_id: childId,
        owner_id: user.id,
        network_id: networkId!,
        x: childPos.x,
        y: childPos.y,
        updated_by: CLIENT_ID,
      });

      setMembers((prev) => {
        const updates: Record<string, FamilyMember> = {
          [childId]: {
            id: childId,
            name: childData.name || '',
            gender: childData.gender,
            parentIds,
            position: childPos,
            childrenIds: [],
            photoUrl: childData.photoUrl,
            birthYear: childData.birthYear,
            deathYear: childData.deathYear,
          },
        };
        
        parentIds.forEach((pid) => {
          if (prev[pid]) {
            updates[pid] = { ...prev[pid], childrenIds: [...(prev[pid].childrenIds || []), childId] };
          }
        });

        return { ...prev, ...updates };
      });

      return childId;
    } catch (error) {
      console.error('Error adding child:', error);
      return null;
    }
  }, [user?.id, members]);

  // Create self node - with DB-level duplicate check
  const creatingSelfRef = useRef(false);
  const createSelfNode = useCallback(async (gender: 'male' | 'female') => {
    if (!user?.id) return null;

    // Prevent concurrent calls (double-click / race condition)
    if (creatingSelfRef.current) return null;
    creatingSelfRef.current = true;

    try {
      // Check local state
      const existingMembers = Object.values(members);
      const selfExists = existingMembers.some(m => m.linkedUserId === user.id);
      if (selfExists) return null;

      // DB-level check: does a self node already exist for this user?
      const { data: existing } = await supabase
        .from('family_tree_members')
        .select('id')
        .eq('owner_id', user.id)
        .eq('linked_user_id', user.id)
        .limit(1);

      if (existing && existing.length > 0) {
        // Already exists in DB, just reload
        await loadData();
        return existing[0].id;
      }

      const { data: profileData } = await supabase
        .from('profiles')
        .select('name, username, avatar_url')
        .eq('id', user.id)
        .single();

      const selfId = generateId();
      const memberName = profileData?.name || profileData?.username || "Men";

      await supabase.from('family_tree_members').insert({
        id: selfId,
        owner_id: user.id,
        member_name: memberName,
        gender: gender,
        relation_type: 'self',
        is_placeholder: false,
        linked_user_id: user.id,
        avatar_url: profileData?.avatar_url,
        birth_year: null,
        death_year: null,
      });

      await supabase.from('node_positions').insert({
        member_id: selfId,
        owner_id: user.id,
        network_id: networkId!,
        x: 0,
        y: 0,
        updated_by: CLIENT_ID,
      });

      setMembers((prev) => ({
        ...prev,
        [selfId]: {
          id: selfId,
          name: memberName,
          gender: gender,
          photoUrl: profileData?.avatar_url || undefined,
          birthYear: undefined,
          deathYear: undefined,
          position: { x: 0, y: 0 },
          childrenIds: [],
          linkedUserId: user.id,
        },
      }));

      setRootId(selfId);
      return selfId;
    } catch (error) {
      console.error('Error creating self node:', error);
      return null;
    } finally {
      creatingSelfRef.current = false;
    }
  }, [user?.id, members, loadData]);

  // Reorder merged profiles
  const reorderMergedProfiles = useCallback(async (newOrderIds: string[]) => {
    if (!user?.id || newOrderIds.length < 2) return;
    
    // newOrderIds[0] is the new primary. The rest should merge into it.
    const newPrimaryId = newOrderIds[0];
    const newMergedIds = newOrderIds.slice(1);

    try {
      // 1. Un-merge the new primary if it was merged into something else (make it the master)
      await supabase
        .from('family_tree_members')
        .update({ merged_into: null })
        .eq('id', newPrimaryId);

      // 2. Point all others to the new primary
      if (newMergedIds.length > 0) {
        await supabase
          .from('family_tree_members')
          .update({ merged_into: newPrimaryId })
          .in('id', newMergedIds);
      }
      
      // Reload the tree
      await loadData(false);
    } catch (error) {
      console.error('Error reordering merged profiles:', error);
    }
  }, [user?.id, loadData]);

  // Detach (fork) network - creates an independent copy of the shared tree
  const detachNetwork = useCallback(async (): Promise<boolean> => {
    if (!user?.id || !networkId) return false;

    try {
      // 1. Get all users in current network
      const { data: networkUsers } = await supabase
        .from('profiles')
        .select('id')
        .eq('family_network_id', networkId);

      const otherUserIds = (networkUsers || [])
        .map(u => u.id)
        .filter(id => id !== user.id);

      if (otherUserIds.length === 0) return false; // Nothing to detach from

      // 2. Load ALL members from other users in the network
      const { data: otherMembers } = await supabase
        .from('family_tree_members')
        .select('*')
        .in('owner_id', otherUserIds);

      if (!otherMembers || otherMembers.length === 0) {
        // Just leave network ΓÇö create new one
        const { data: newNet } = await supabase
          .from('family_networks')
          .insert({})
          .select('id')
          .single();
        if (newNet) {
          await supabase.from('profiles').update({ family_network_id: newNet.id }).eq('id', user.id);
        }
        await loadData(false);
        return true;
      }

      // 3. Build ID remapping: old other-user member ID -> new cloned ID
      const idMap = new Map<string, string>();
      for (const m of otherMembers) {
        idMap.set(m.id, generateId());
      }

      // Helper to remap an ID in a relation_type string
      const remapRelationType = (relType: string): string => {
        let result = relType;
        idMap.forEach((newId, oldId) => {
          result = result.split(oldId).join(newId);
        });
        return result;
      };

      // 4. Clone records for other users with new IDs, remapped relations, current owner
      const clonedInserts = otherMembers.map(m => ({
        id: idMap.get(m.id as string)!,
        owner_id: user.id,
        member_name: (m.member_name as string) || '',
        gender: (m.gender as string) || 'male',
        avatar_url: (m.avatar_url as string) || null,
        is_placeholder: (m.is_placeholder as boolean) || false,
        merged_into: m.merged_into ? (idMap.get(m.merged_into as string) ?? null) : null,
        relation_type: remapRelationType((m.relation_type as string) || ''),
        linked_user_id: (m.linked_user_id as string) || null,
      }));

      // 5. Current user's own members also need their relation_type remapped (where they reference other members)
      const { data: myMembers } = await supabase
        .from('family_tree_members')
        .select('*')
        .eq('owner_id', user.id);

      const myMemberUpdates = (myMembers || []).map(m => ({
        id: m.id as string,
        relation_type: remapRelationType((m.relation_type as string) || ''),
        merged_into: m.merged_into ? (idMap.get(m.merged_into as string) ?? (m.merged_into as string)) : null,
      }));

      // MUTUAL CLONING for remaining network members:
      // We pick the first other user to own the clones of myMembers in the old network
      const targetOtherId = otherUserIds[0];
      
      const myIdMap = new Map<string, string>();
      for (const m of (myMembers || [])) {
        myIdMap.set(m.id as string, generateId());
      }
      
      const remapMyRelationType = (relType: string): string => {
        let result = relType;
        myIdMap.forEach((newId, oldId) => {
          result = result.split(oldId).join(newId);
        });
        return result;
      };

      const clonedMyMembers = (myMembers || []).map(m => ({
        id: myIdMap.get(m.id as string)!,
        owner_id: targetOtherId,
        member_name: (m.member_name as string) || '',
        gender: (m.gender as string) || 'male',
        avatar_url: (m.avatar_url as string) || null,
        is_placeholder: (m.is_placeholder as boolean) || false,
        merged_into: m.merged_into ? (myIdMap.get(m.merged_into as string) ?? (m.merged_into as string)) : null,
        relation_type: remapMyRelationType((m.relation_type as string) || ''),
        linked_user_id: (m.linked_user_id as string) || null,
      }));
      
      const otherMemberUpdates = otherMembers.map(m => ({
        id: m.id as string,
        relation_type: remapMyRelationType((m.relation_type as string) || ''),
        merged_into: m.merged_into ? (myIdMap.get(m.merged_into as string) ?? (m.merged_into as string)) : null,
      }));

      // 6. Create a new network for the current user
      const { data: newNetwork } = await supabase
        .from('family_networks')
        .insert({})
        .select('id')
        .single();

      if (!newNetwork) throw new Error('Failed to create new network');

      // 7. Insert cloned members + update relations + update profile network
      await Promise.all([
        supabase.from('family_tree_members').insert(clonedInserts),
        supabase.from('family_tree_members').insert(clonedMyMembers),
        ...myMemberUpdates.map(u =>
          supabase.from('family_tree_members')
            .update({ relation_type: u.relation_type, merged_into: u.merged_into })
            .eq('id', u.id)
        ),
        ...otherMemberUpdates.map(u =>
          supabase.from('family_tree_members')
            .update({ relation_type: u.relation_type, merged_into: u.merged_into })
            .eq('id', u.id)
        ),
        supabase.from('profiles').update({ family_network_id: newNetwork.id }).eq('id', user.id),
      ]);

      await loadData(false);
      return true;
    } catch (error) {
      console.error('Error detaching network:', error);
      return false;
    }
  }, [user?.id, networkId, loadData]);

  // Derived counts
  const totalCount = Object.keys(members).length;
  const activeCount = Object.values(members).filter((m) => !!m.linkedUserId).length;

  return {
    members,
    rootId,
    totalCount,
    activeCount,
    isLoading,
    isRefreshing,
    networkId,
    isSharedNetwork,
    addInitialCouple,
    updateMember,
    updatePosition,
    addParents,
    addSpouse,
    addChild,
    removeMember,
    createSelfNode,
    reorderMergedProfiles,
    detachNetwork,
    reload: loadData,
  };
};

import { useState, useCallback, useMemo } from 'react';
import { FamilyMember } from '@/types/family';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';
import { 
  MergeCandidate, 
  ChildProfile, 
  ChildMergeSuggestion, 
  CoupleGroup, 
  calculateSimilarity,
  computeMatchScore,
  birthYearScore,
} from './useTreeMerging';
import { MergeDialogData } from './useFamilyInvitations';

export interface MergeSuggestion {
  sourceId: string;
  targetId: string;
  sourceName: string;
  targetName: string;
  reason: string;
  gender: 'male' | 'female';
}

export interface MergedProfile {
  primaryId: string;
  mergedIds: string[];
  mergedNames: string[];
}

export const useMergeMode = (members: Record<string, FamilyMember>) => {
  const { user } = useAuth();
  const [isActive, setIsActive] = useState(false);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [mergedProfiles, setMergedProfiles] = useState<Map<string, MergedProfile>>(new Map());
  const [isProcessing, setIsProcessing] = useState(false);

  const startMergeMode = useCallback((memberId: string) => {
    setIsActive(true);
    setSelectedIds([memberId]);
  }, []);

  const toggleSelection = useCallback((memberId: string) => {
    if (!isActive) return;
    
    const member = members[memberId];
    const firstMember = members[selectedIds[0]];
    
    if (firstMember && member && firstMember.gender !== member.gender) {
      toast.error("Faqat bir xil jinsdagi profillarni birlashtirish mumkin");
      return;
    }
    
    setSelectedIds(prev => {
      if (prev.includes(memberId)) {
        if (prev[0] === memberId) {
          cancelMerge();
          return [];
        }
        return prev.filter(id => id !== memberId);
      }
      return [...prev, memberId];
    });
  }, [isActive, members, selectedIds]);

  const cancelMerge = useCallback(() => {
    setIsActive(false);
    setSelectedIds([]);
  }, []);

  /**
   * Tanlangan profillardan MergeDialogData yaratish
   */
  const computeMergeData = useCallback((): MergeDialogData | null => {
    if (selectedIds.length < 2) return null;
    
    const primaryId = selectedIds[0];
    const primary = members[primaryId];
    if (!primary) return null;
    
    const parentMerges: MergeCandidate[] = [];
    const coupleGroups: CoupleGroup[] = [];
    
    for (const otherId of selectedIds.slice(1)) {
      const other = members[otherId];
      if (!other) continue;
      
      // Asosiy birlashtirish: tanlangan profillar
      parentMerges.push({
        sourceId: primaryId,
        targetId: otherId,
        sourceName: primary.name,
        targetName: other.name,
        sourcePhotoUrl: primary.photoUrl,
        targetPhotoUrl: other.photoUrl,
        relationship: 'parent',
      });
      
      // Ota-onalarni birlashtirish tavsiyasi
      const primaryParentIds = primary.parentIds || [];
      const otherParentIds = other.parentIds || [];
      
      const coupleParentMerges: MergeCandidate[] = [];
      const matchedPrimary = new Set<string>();
      const matchedOther = new Set<string>();
      
      for (const ppId of primaryParentIds) {
        const pp = members[ppId];
        if (!pp) continue;
        for (const opId of otherParentIds) {
          const op = members[opId];
          if (!op) continue;
          if (pp.gender === op.gender && ppId !== opId && !matchedPrimary.has(ppId) && !matchedOther.has(opId)) {
            const merge: MergeCandidate = {
              sourceId: ppId,
              targetId: opId,
              sourceName: pp.name,
              targetName: op.name,
              sourcePhotoUrl: pp.photoUrl,
              targetPhotoUrl: op.photoUrl,
              relationship: 'parent',
            };
            parentMerges.push(merge);
            coupleParentMerges.push(merge);
            matchedPrimary.add(ppId);
            matchedOther.add(opId);
          }
        }
      }
      
      // Farzandlarni topish (birthYear 30% ball uchun)
      const getChildren = (memberId: string): ChildProfile[] => {
        const m = members[memberId];
        if (!m) return [];
        const childIds = new Set(m.childrenIds || []);
        if (m.spouseId && members[m.spouseId]) {
          (members[m.spouseId].childrenIds || []).forEach(id => childIds.add(id));
        }
        return [...childIds]
          .filter(id => members[id])
          .map(id => ({
            id,
            name: members[id].name,
            photoUrl: members[id].photoUrl,
            gender: members[id].gender,
            birthYear: members[id].birthYear,
          }));
      };

      const sourceChildren = getChildren(primaryId);
      const targetChildren = getChildren(otherId);

      // Tavsiyalar: ball boΓÇÿyicha eng yaxshi juftliklar birinchi (keraklisi keraklisi bilan)
      const allPairs: { source: ChildProfile; target: ChildProfile; score: number }[] = [];
      const MERGE_THRESHOLD = 1;

      for (const sc of sourceChildren) {
        for (const t of targetChildren) {
          if (t.gender !== sc.gender) continue;
          const nameSim = calculateSimilarity(sc.name, t.name);
          const birthSim = birthYearScore(sc.birthYear, t.birthYear);
          const score = computeMatchScore(nameSim, birthSim, 100, 0);
          if (score >= MERGE_THRESHOLD) {
            allPairs.push({ source: sc, target: t, score });
          }
        }
      }
      allPairs.sort((a, b) => b.score - a.score);

      const childSuggestions: ChildMergeSuggestion[] = [];
      const usedSourceIds = new Set<string>();
      const usedTargetIds = new Set<string>();
      for (const { source, target, score } of allPairs) {
        if (usedSourceIds.has(source.id) || usedTargetIds.has(target.id)) continue;
        childSuggestions.push({ sourceChild: source, targetChild: target, similarity: score });
        usedSourceIds.add(source.id);
        usedTargetIds.add(target.id);
      }
      
      if (sourceChildren.length > 0 || targetChildren.length > 0) {
        coupleGroups.push({
          label: `${primary.name} va ${other.name}`,
          parentMerges: coupleParentMerges,
          sourceChildren,
          targetChildren,
          childSuggestions,
        });
      }
    }
    
    return {
      senderName: primary.name,
      receiverName: selectedIds.slice(1).map(id => members[id]?.name || '').join(', '),
      parentMerges,
      coupleGroups,
      childSuggestions: coupleGroups.flatMap(g => g.childSuggestions),
      allSourceChildren: coupleGroups.flatMap(g => g.sourceChildren),
      allTargetChildren: coupleGroups.flatMap(g => g.targetChildren),
    };
  }, [selectedIds, members]);

  // Direct merge execution (backward compat)
  const executeMerge = useCallback(async () => {
    if (selectedIds.length < 2 || !user?.id) return;
    
    setIsProcessing(true);
    
    try {
      const primaryId = selectedIds[0];
      const primary = members[primaryId];
      if (!primary) throw new Error('Primary member not found');
      
      const mergedIds = selectedIds.slice(1);
      const mergedNames = mergedIds.map(id => members[id]?.name || 'Noma\'lum');
      
      for (const mergedId of mergedIds) {
        const merged = members[mergedId];
        if (!merged) continue;
        
        await supabase
          .from('family_tree_members')
          .update({ 
            merged_into: primaryId,
            updated_at: new Date().toISOString()
          })
          .eq('id', mergedId);
        
        if (merged.linkedUserId && !primary.linkedUserId) {
          await supabase
            .from('family_tree_members')
            .update({ 
              linked_user_id: merged.linkedUserId,
              is_placeholder: false 
            })
            .eq('id', primaryId);
        }
      }
      
      setMergedProfiles(prev => {
        const next = new Map(prev);
        const existing = next.get(primaryId);
        next.set(primaryId, {
          primaryId,
          mergedIds: existing ? [...existing.mergedIds, ...mergedIds] : mergedIds,
          mergedNames: existing ? [...existing.mergedNames, ...mergedNames] : mergedNames,
        });
        return next;
      });
      
      toast.success(`${mergedIds.length} ta profil birlashtirildi`);
      cancelMerge();
      
      window.dispatchEvent(new CustomEvent('family-tree-reload'));
      
    } catch (error) {
      console.error('Error executing merge:', error);
      toast.error('Birlashtirishda xatolik');
    } finally {
      setIsProcessing(false);
    }
  }, [selectedIds, members, user?.id, cancelMerge]);

  const suggestions = useMemo((): MergeSuggestion[] => {
    if (selectedIds.length < 2) return [];
    // Keeping for backward compat but suggestions now go through computeMergeData
    return [];
  }, [selectedIds]);

  const applySuggestion = useCallback((suggestion: MergeSuggestion) => {
    setSelectedIds(prev => {
      const newIds = [...prev];
      if (!newIds.includes(suggestion.sourceId)) newIds.push(suggestion.sourceId);
      if (!newIds.includes(suggestion.targetId)) newIds.push(suggestion.targetId);
      return newIds;
    });
  }, []);

  return {
    isActive,
    selectedIds,
    mergedProfiles,
    suggestions,
    isProcessing,
    startMergeMode,
    toggleSelection,
    cancelMerge,
    executeMerge,
    computeMergeData,
    applySuggestion,
  };
};

import { useState, useEffect, useCallback, useRef } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { getCache, setCache } from '@/lib/localCache';

export interface Message {
  id: string;
  conversation_id: string;
  sender_id: string;
  content: string;
  status: 'sent' | 'delivered' | 'seen';
  created_at: string;
  updated_at: string;
  media_url?: string | null;
  media_type?: 'image' | 'video' | 'audio' | null;
}

const cacheKey = (convId: string) => `messages_cache_${convId}`;

const PAGE_SIZE = 30;

type Cursor = {
  oldestCreatedAt: string | null;
  hasMore: boolean;
};

const memoryCache = new Map<string, Message[]>();
const memoryCursorCache = new Map<string, Cursor>();

export const useMessages = (conversationId: string | null) => {
  const { user } = useAuth();
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isLoadingMore, setIsLoadingMore] = useState(false);
  const [hasMore, setHasMore] = useState(false);
  const [oldestCreatedAt, setOldestCreatedAt] = useState<string | null>(null);
  const [otherUserTyping, setOtherUserTyping] = useState(false);
  const typingTimeoutRef = useRef<ReturnType<typeof setTimeout>>();

  // Load from cache first (memory -> localStorage)
  useEffect(() => {
    if (!conversationId) return;

    const mem = memoryCache.get(conversationId);
    if (mem && mem.length > 0) {
      setMessages(mem);
      const cur = memoryCursorCache.get(conversationId);
      if (cur) {
        setOldestCreatedAt(cur.oldestCreatedAt);
        setHasMore(cur.hasMore);
      }
      setIsLoading(false);
      return;
    }

    const cached = getCache<Message[]>(cacheKey(conversationId));
    if (cached && cached.length > 0) {
      setMessages(cached);
      memoryCache.set(conversationId, cached);
      setIsLoading(false);

      const oldest = cached[0]?.created_at ?? null;
      const cursor = { oldestCreatedAt: oldest, hasMore: cached.length >= PAGE_SIZE };
      setOldestCreatedAt(cursor.oldestCreatedAt);
      setHasMore(cursor.hasMore);
      memoryCursorCache.set(conversationId, cursor);
    }
  }, [conversationId]);

  const updateCursor = useCallback((convId: string, nextMessages: Message[]) => {
    const oldest = nextMessages[0]?.created_at ?? null;
    const cursor: Cursor = {
      oldestCreatedAt: oldest,
      hasMore: nextMessages.length >= PAGE_SIZE
    };
    setOldestCreatedAt(cursor.oldestCreatedAt);
    setHasMore(cursor.hasMore);
    memoryCursorCache.set(convId, cursor);
  }, []);

  const fetchMessages = useCallback(async () => {
    if (!conversationId) return;

    if (messages.length === 0) {
      setIsLoading(true);
    }

    try {
      // Fetch only last PAGE_SIZE messages initially
      const { data, error } = await supabase
        .from('messages')
        .select('*')
        .eq('conversation_id', conversationId)
        .order('created_at', { ascending: false })
        .limit(PAGE_SIZE);

      if (error) throw error;
      const msgs = ((data || []) as Message[]).slice().reverse();
      setMessages(msgs);
      setCache(cacheKey(conversationId), msgs);
      memoryCache.set(conversationId, msgs);
      updateCursor(conversationId, msgs);

      // Mark messages as seen
      if (user?.id && data && data.length > 0) {
        await supabase
          .from('messages')
          .update({ status: 'seen' })
          .eq('conversation_id', conversationId)
          .neq('sender_id', user.id)
          .neq('status', 'seen');
      }
    } catch (error) {
      console.error('Error fetching messages:', error);
    } finally {
      setIsLoading(false);
    }
  }, [conversationId, messages.length, updateCursor, user?.id]);

  const loadOlder = useCallback(async () => {
    if (!conversationId) return;
    if (!oldestCreatedAt) return;
    if (!hasMore) return;
    if (isLoadingMore) return;

    setIsLoadingMore(true);
    try {
      const { data, error } = await supabase
        .from('messages')
        .select('*')
        .eq('conversation_id', conversationId)
        .lt('created_at', oldestCreatedAt)
        .order('created_at', { ascending: false })
        .limit(PAGE_SIZE);

      if (error) throw error;
      const older = ((data || []) as Message[]).slice().reverse();
      if (older.length === 0) {
        setHasMore(false);
        memoryCursorCache.set(conversationId, { oldestCreatedAt, hasMore: false });
        return;
      }

      setMessages((prev) => {
        const merged = [...older, ...prev];
        setCache(cacheKey(conversationId), merged);
        memoryCache.set(conversationId, merged);
        updateCursor(conversationId, merged);
        return merged;
      });
    } catch (error) {
      console.error('Error loading older messages:', error);
    } finally {
      setIsLoadingMore(false);
    }
  }, [conversationId, hasMore, isLoadingMore, oldestCreatedAt, updateCursor]);

  useEffect(() => {
    fetchMessages();
  }, [fetchMessages]);

  // Real-time subscription for messages
  useEffect(() => {
    if (!conversationId) return;

    const channel = supabase
      .channel(`messages-${conversationId}`)
      .on(
        'postgres_changes',
        {
          event: 'INSERT',
          schema: 'public',
          table: 'messages',
          filter: `conversation_id=eq.${conversationId}`
        },
        (payload) => {
          const newMessage = payload.new as Message;
          setMessages(prev => {
            const updated = [...prev, newMessage];
            setCache(cacheKey(conversationId), updated);
            memoryCache.set(conversationId, updated);
            updateCursor(conversationId, updated);
            return updated;
          });
          
          // Mark as seen if from other user
          if (user?.id && newMessage.sender_id !== user.id) {
            supabase
              .from('messages')
              .update({ status: 'seen' })
              .eq('id', newMessage.id)
              .then();
          }
        }
      )
      .on(
        'postgres_changes',
        {
          event: 'UPDATE',
          schema: 'public',
          table: 'messages',
          filter: `conversation_id=eq.${conversationId}`
        },
        (payload) => {
          const updatedMessage = payload.new as Message;
          setMessages(prev => {
            const updated = prev.map(m => m.id === updatedMessage.id ? updatedMessage : m);
            setCache(cacheKey(conversationId), updated);
            memoryCache.set(conversationId, updated);
            return updated;
          });
        }
      )
      .on(
        'postgres_changes',
        {
          event: 'DELETE',
          schema: 'public',
          table: 'messages',
          filter: `conversation_id=eq.${conversationId}`
        },
        (payload) => {
          const deletedId = (payload.old as any).id;
          setMessages(prev => {
            const updated = prev.filter(m => m.id !== deletedId);
            setCache(cacheKey(conversationId), updated);
            memoryCache.set(conversationId, updated);
            updateCursor(conversationId, updated);
            return updated;
          });
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [conversationId, user?.id]);

  // Typing indicator subscription
  useEffect(() => {
    if (!conversationId || !user?.id) return;

    const channel = supabase
      .channel(`typing-${conversationId}`)
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'typing_indicators',
          filter: `conversation_id=eq.${conversationId}`
        },
        (payload) => {
          if (payload.new && (payload.new as any).user_id !== user.id) {
            setOtherUserTyping((payload.new as any).is_typing);
          }
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [conversationId, user?.id]);

  const sendMessage = async (content: string, mediaUrl?: string, mediaType?: string) => {
    if (!conversationId || !user?.id) return null;
    
    if (!content.trim() && !mediaUrl) return null;

    try {
      const messageData: any = {
        conversation_id: conversationId,
        sender_id: user.id,
        content: content.trim() || (mediaType === 'audio' ? '≡ƒÄñ Ovozli xabar' : '≡ƒôÄ Media'),
        status: 'sent'
      };

      if (mediaUrl) {
        messageData.media_url = mediaUrl;
        messageData.media_type = mediaType;
      }

      const { data, error } = await supabase
        .from('messages')
        .insert(messageData)
        .select()
        .single();

      if (error) throw error;
      return data as Message;
    } catch (error) {
      console.error('Error sending message:', error);
      return null;
    }
  };

  const setTyping = useCallback(async (isTyping: boolean) => {
    if (!conversationId || !user?.id) return;

    if (typingTimeoutRef.current) {
      clearTimeout(typingTimeoutRef.current);
    }

    try {
      await supabase
        .from('typing_indicators')
        .upsert({
          conversation_id: conversationId,
          user_id: user.id,
          is_typing: isTyping,
          updated_at: new Date().toISOString()
        }, {
          onConflict: 'conversation_id,user_id'
        });

      if (isTyping) {
        typingTimeoutRef.current = setTimeout(() => {
          setTyping(false);
        }, 3000);
      }
    } catch (error) {
      console.error('Error setting typing:', error);
    }
  }, [conversationId, user?.id]);

  return {
    messages,
    isLoading,
    isLoadingMore,
    hasMore,
    otherUserTyping,
    sendMessage,
    setTyping,
    loadOlder,
    refetch: fetchMessages
  };
};

import { useState, useCallback, useRef, useMemo } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { Post } from '@/types';

const PAGE_SIZE = 10;

interface CacheData {
  posts: Post[];
  fetchedAt: number;
  hasMore: boolean;
}

// Global cache - persists across component mounts
const globalCacheByKey: Record<string, CacheData | undefined> = {};
const CACHE_TTL = 5 * 60 * 1000; // 5 minutes

type PostVisibility = 'public' | 'friends_only' | 'private' | 'profile';

async function fetchPostsPage(from: number, pageSize: number, visibilities: PostVisibility[]): Promise<Post[]> {
  const { data: postsData, error } = await supabase
    .from('posts')
    .select('*')
    .in('visibility', visibilities)
    .order('created_at', { ascending: false })
    .range(from, from + pageSize - 1);

  if (error) throw error;

  let postsWithAuthors: Post[] = [];

  if (postsData && postsData.length > 0) {
    const userIds = [...new Set(postsData.map(p => p.user_id))];
    const { data: profiles } = await supabase
      .from('profiles')
      .select('*')
      .in('id', userIds);

    postsWithAuthors = postsData.map(post => {
      const profile = profiles?.find(p => p.id === post.user_id);
      return {
        ...post,
        media_urls: post.media_urls || [],
        author: profile ? {
          id: post.user_id,
          full_name: profile.name || 'Foydalanuvchi',
          username: profile.username || 'user',
          bio: profile.bio || '',
          avatar_url: profile.avatar_url || '',
          cover_url: '',
          instagram: '',
          telegram: '',
          followers_count: 0,
          following_count: 0,
          relatives_count: 0,
          created_at: post.created_at,
        } : undefined
      };
    });
  }

  return postsWithAuthors;
}

interface UsePostsCacheOptions {
  visibilities?: PostVisibility[];
}

export const usePostsCache = (options?: UsePostsCacheOptions) => {
  const normalizedVisibilities = useMemo(() => {
    const base = (options?.visibilities && options.visibilities.length > 0)
      ? options.visibilities
      : (['public', 'profile', 'friends_only'] as PostVisibility[]);
    return base.slice().sort();
  }, [options?.visibilities?.join('|')]);

  const cacheKey = useMemo(() => normalizedVisibilities.join('|'), [normalizedVisibilities]);
  const globalCache = globalCacheByKey[cacheKey];

  const [posts, setPosts] = useState<Post[]>(globalCache?.posts || []);
  const [isLoading, setIsLoading] = useState(!globalCache);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [isLoadingMore, setIsLoadingMore] = useState(false);
  const [hasMore, setHasMore] = useState(globalCache?.hasMore ?? true);
  const isFetchingRef = useRef(false);

  const isCacheValid = useCallback(() => {
    const cache = globalCacheByKey[cacheKey];
    if (!cache) return false;
    const now = Date.now();
    return (now - cache.fetchedAt) < CACHE_TTL;
  }, [cacheKey]);

  const fetchPosts = useCallback(async (forceRefresh = false) => {
    if (isFetchingRef.current) return;

    const cache = globalCacheByKey[cacheKey];

    if (cache && !forceRefresh) {
      // SWR: show stale instantly
      setPosts(cache.posts);
      setHasMore(cache.hasMore);
      setIsLoading(false);

      // If cache is still fully valid, don't even fetch in background
      if (isCacheValid()) return;
    } else if (forceRefresh) {
      setIsRefreshing(true);
    } else {
      setIsLoading(true);
    }

    isFetchingRef.current = true;

    try {
      console.log('Fetching posts with visibilities:', normalizedVisibilities);
      const postsWithAuthors = await fetchPostsPage(0, PAGE_SIZE, normalizedVisibilities);
      console.log('Fetched posts count:', postsWithAuthors.length);

      const hasMoreData = postsWithAuthors.length >= PAGE_SIZE;

      globalCacheByKey[cacheKey] = {
        posts: postsWithAuthors,
        fetchedAt: Date.now(),
        hasMore: hasMoreData,
      };

      setPosts(postsWithAuthors);
      setHasMore(hasMoreData);
    } catch (error) {
      console.error('Error fetching posts in cache hook:', error);
    } finally {
      setIsLoading(false);
      setIsRefreshing(false);
      isFetchingRef.current = false;
    }
  }, [cacheKey, isCacheValid, normalizedVisibilities]);

  const loadMore = useCallback(async () => {
    if (isFetchingRef.current || !hasMore || posts.length === 0) return;

    isFetchingRef.current = true;
    setIsLoadingMore(true);

    try {
      const nextPosts = await fetchPostsPage(posts.length, PAGE_SIZE, normalizedVisibilities);
      const hasMoreData = nextPosts.length >= PAGE_SIZE;

      const updatedPosts = [...posts, ...nextPosts];

      const cache = globalCacheByKey[cacheKey];
      if (cache) {
        cache.posts = updatedPosts;
        cache.hasMore = hasMoreData;
        cache.fetchedAt = Date.now();
      }

      setPosts(updatedPosts);
      setHasMore(hasMoreData);
    } catch (error) {
      console.error('Error loading more posts:', error);
    } finally {
      setIsLoadingMore(false);
      isFetchingRef.current = false;
    }
  }, [cacheKey, hasMore, posts, normalizedVisibilities]);

  // Add new post to cache (optimistic)
  const addPostToCache = useCallback((newPost: Post) => {
    const updatedPosts = [newPost, ...posts];
    setPosts(updatedPosts);
    const cache = globalCacheByKey[cacheKey];
    if (cache) {
      cache.posts = updatedPosts;
    }
  }, [cacheKey, posts]);

  // Remove post from cache
  const removePostFromCache = useCallback((postId: string) => {
    const updatedPosts = posts.filter(p => p.id !== postId);
    setPosts(updatedPosts);
    const cache = globalCacheByKey[cacheKey];
    if (cache) {
      cache.posts = updatedPosts;
    }
  }, [cacheKey, posts]);

  // Update post in cache (for like counts, etc.)
  const updatePostInCache = useCallback((postId: string, updates: Partial<Post>) => {
    const updatedPosts = posts.map(p => 
      p.id === postId ? { ...p, ...updates } : p
    );
    setPosts(updatedPosts);
    const cache = globalCacheByKey[cacheKey];
    if (cache) {
      cache.posts = updatedPosts;
    }
  }, [cacheKey, posts]);

  // Clear cache
  const clearCache = useCallback(() => {
    delete globalCacheByKey[cacheKey];
    setPosts([]);
    setHasMore(true);
  }, [cacheKey]);

  const forceRefresh = useCallback(async () => {
    delete globalCacheByKey[cacheKey];
    await fetchPosts(true);
  }, [cacheKey, fetchPosts]);

  return {
    posts,
    isLoading,
    isRefreshing,
    isLoadingMore,
    hasMore,
    fetchPosts,
    forceRefresh,
    loadMore,
    addPostToCache,
    removePostFromCache,
    updatePostInCache,
    clearCache,
    isCacheValid
  };
};

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

interface UnfollowRecord {
  id: string;
  unfollowed_user_id: string;
  created_at: string;
  profile?: { id: string; name: string | null; username: string | null; avatar_url: string | null };
}

export type UnfollowHistoryMode = 'incoming';

interface UseUnfollowHistoryOptions {
  mode?: UnfollowHistoryMode;
  enabled?: boolean;
  userId?: string;
}

export const useUnfollowHistory = (options?: UseUnfollowHistoryOptions) => {
  const { user } = useAuth();
  const [history, setHistory] = useState<UnfollowRecord[]>([]);

  const RETENTION_DAYS = 30;

  const getCutoffIso = useCallback(() => {
    const d = new Date();
    d.setDate(d.getDate() - RETENTION_DAYS);
    return d.toISOString();
  }, []);

  const fetchHistory = useCallback(async () => {
    const ownerId = options?.userId || user?.id;
    if (!ownerId) return;
    if (options?.enabled === false) return;
    const cutoffIso = getCutoffIso();

    // Cleanup old records only for the current user's own history (RLS allows delete when auth.uid() = user_id).
    if (user?.id && ownerId === user.id) {
      await supabase.from('unfollow_history').delete().eq('user_id', ownerId).lt('created_at', cutoffIso);
    }

    const { data } = await supabase
      .from('unfollow_history')
      .select('*')
      .eq('user_id', ownerId)
      .gte('created_at', cutoffIso)
      .order('created_at', { ascending: false })
      .limit(50);
    
    if (data && data.length > 0) {
      const userIds = data.map(d => d.unfollowed_user_id);
      const { data: profiles } = await supabase
        .from('profiles')
        .select('id, name, username, avatar_url')
        .in('id', userIds);
      
      const profileMap = new Map((profiles || []).map(p => [p.id, p]));
      setHistory(data.map(d => ({ ...d, profile: profileMap.get(d.unfollowed_user_id) || undefined })));
    } else {
      setHistory([]);
    }
  }, [getCutoffIso, options?.enabled, options?.userId, user?.id]);

  useEffect(() => {
    if (options?.enabled === false) return;
    fetchHistory();
  }, [fetchHistory, options?.enabled]);

  const recordUnfollow = useCallback(async (unfollowedUserId: string) => {
    // Record "incoming" unfollow for the user who got unfollowed.
    // user_id = owner of history (unfollowedUserId)
    // unfollowed_user_id = actor who unfollowed (current user)
    if (!user?.id) return;

    // Insert is allowed by RLS policy (see migration) where actor is auth.uid() = unfollowed_user_id.
    await supabase.from('unfollow_history').insert({ user_id: unfollowedUserId, unfollowed_user_id: user.id });
  }, [getCutoffIso, user?.id]);

  return { history, recordUnfollow, refetch: fetchHistory };
};

import { useState, useEffect, useCallback, useRef } from 'react';
import DailyIframe, { DailyCall, DailyParticipant, DailyEventObject } from '@daily-co/daily-js';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';
import { clearLocalCallNotification } from '@/lib/pushNotifications';
import { ForegroundService } from '@capawesome-team/capacitor-android-foreground-service';
import { Capacitor } from '@capacitor/core';

interface Call {
  id: string;
  caller_id: string;
  receiver_id: string;
  room_url: string;
  room_name: string;
  status: string;
  created_at: string;
}

export const useVideoCall = (otherUserId: string | null) => {
  const { user } = useAuth();
  const [callObject, setCallObject] = useState<DailyCall | null>(null);
  const [isInCall, setIsInCall] = useState(false);
  const [wasInCall, setWasInCall] = useState(false);
  const [partnerLeft, setPartnerLeft] = useState(false);
  const [isCreatingRoom, setIsCreatingRoom] = useState(false);
  const [incomingCall, setIncomingCall] = useState<Call | null>(null);
  const [currentCall, setCurrentCall] = useState<Call | null>(null);
  const [cameraOn, setCameraOn] = useState(true);
  const [micOn, setMicOn] = useState(true);
  const [remoteParticipant, setRemoteParticipant] = useState<DailyParticipant | null>(null);
  const callHistorySavedRef = useRef(false);
  const callObjectRef = useRef<DailyCall | null>(null);
  const reconnectAttemptsRef = useRef(0);
  const maxReconnectAttempts = 3;

  const [lastRoomUrl, setLastRoomUrl] = useState<string | null>(null);

  // Keep ref in sync
  useEffect(() => {
    callObjectRef.current = callObject;
  }, [callObject]);

  // Subscribe to incoming calls
  useEffect(() => {
    if (!user?.id) return;

    const channel = supabase
      .channel('incoming-calls')
      .on(
        'postgres_changes',
        {
          event: 'INSERT',
          schema: 'public',
          table: 'calls',
          filter: `receiver_id=eq.${user.id}`,
        },
        (payload) => {
          const call = payload.new as Call;
          if (call.status === 'pending') {
            setIncomingCall(call);
          }
        }
      )
      .on(
        'postgres_changes',
        {
          event: 'UPDATE',
          schema: 'public',
          table: 'calls',
        },
        (payload) => {
          const call = payload.new as Call;
          
          if (call.status === 'ended') {
            if (currentCall?.id === call.id || incomingCall?.id === call.id) {
              // Don't call leaveCall() directly to avoid clearing everything if we want to show "Call Ended" UI
              // But for now, let's keep it simple
              if (callObjectRef.current) {
                callObjectRef.current.leave().catch(() => undefined);
              }
              setIsInCall(false);
              setRemoteParticipant(null);
              toast.info("Qo'ng'iroq tugadi");
            }
            if (incomingCall?.id === call.id) {
              clearLocalCallNotification(call.caller_id);
            }
            setIncomingCall(null);
          }
          
          if (call.status === 'active' && currentCall?.id === call.id) {
            setCurrentCall(call);
          }
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [user?.id, currentCall?.id, incomingCall?.id]);

  // Cleanup on unmount
  useEffect(() => {
    // Listen for foreground service button clicks (e.g. "Tugatish" button)
    const setupForegroundListener = async () => {
      if (Capacitor.getPlatform() !== 'android') return;
      try {
        await ForegroundService.removeAllListeners();
        await ForegroundService.addListener('buttonClicked', (event) => {
          const id = (event as unknown as { buttonId?: number; id?: number } | null)?.buttonId ??
            (event as unknown as { buttonId?: number; id?: number } | null)?.id;
          if (id === 1) {
            // "Tugatish" was clicked
            leaveCall();
          }
        });
      } catch (e) {
        // usually fails on web/iOS, ignore listener setup error
      }
    };
    
    setupForegroundListener();

    return () => {
      if (Capacitor.getPlatform() === 'android') {
        try { void ForegroundService.removeAllListeners(); } catch {
          // ignore
        }
      }
      // Ignore removal error
      const co = callObjectRef.current;
      if (co) {
        try {
          co.leave();
          co.destroy();
        } catch {
          // ignore leave/destroy error
        }
      }
    };
  }, []);

  const startCall = useCallback(async () => {
    if (!otherUserId || !user?.id || isCreatingRoom) return;

    setIsCreatingRoom(true);
    
    try {
      const { data, error } = await supabase.functions.invoke('create-daily-room', {
        body: { receiver_id: otherUserId },
      });

      if (error) throw error;
      
      setCurrentCall(data.call);
      setLastRoomUrl(data.room_url);
      callHistorySavedRef.current = false;
      
      await joinRoom(data.room_url);
      
    } catch (error) {
      console.error('Error starting call:', error);
      toast.error("Qo'ng'iroqni boshlashda xatolik");
    } finally {
      setIsCreatingRoom(false);
    }
  }, [otherUserId, user?.id, isCreatingRoom]);

  const answerCall = useCallback(async () => {
    if (!incomingCall) return;

    try {
      await supabase
        .from('calls')
        .update({ status: 'active' })
        .eq('id', incomingCall.id);

      setCurrentCall(incomingCall);
      setLastRoomUrl(incomingCall.room_url);
      callHistorySavedRef.current = false;
      await joinRoom(incomingCall.room_url);
      clearLocalCallNotification(incomingCall.caller_id);
      setIncomingCall(null);
      
    } catch (error) {
      console.error('Error answering call:', error);
      toast.error("Qo'ng'iroqqa javob berishda xatolik");
    }
  }, [incomingCall]);

  const rejoinCall = useCallback(async () => {
    if (!lastRoomUrl) return;
    await joinRoom(lastRoomUrl);
  }, [lastRoomUrl]);

  const declineCall = useCallback(async () => {
    if (!incomingCall) return;

    try {
      await supabase.functions.invoke('end-call', {
        body: { 
          call_id: incomingCall.id,
          room_name: incomingCall.room_name 
        },
      });
      
      clearLocalCallNotification(incomingCall.caller_id);
      setIncomingCall(null);
    } catch (error) {
      console.error('Error declining call:', error);
    }
  }, [incomingCall]);

  const joinRoom = async (roomUrl: string) => {
    try {
      // Destroy existing call object if any
      if (callObjectRef.current) {
        try {
          await callObjectRef.current.leave();
          callObjectRef.current.destroy();
        } catch {
          // ignore previous call cleanup
        }
        setCallObject(null);
        callObjectRef.current = null;
      }

      reconnectAttemptsRef.current = 0;

      const newCallObject = DailyIframe.createCallObject({
        audioSource: true,
        videoSource: true,
      });

      newCallObject.on('joined-meeting', async () => {
        setIsInCall(true);
        setWasInCall(true);
        setPartnerLeft(false);
        reconnectAttemptsRef.current = 0;

        // Start Foreground Service so call doesn't drop when app is backgrounded
        if (Capacitor.getPlatform() === 'android') {
          try {
            await ForegroundService.startForegroundService({
              id: 2,
              title: "Avlodona Video Qo'ng'iroq",
              body: "Suhbat davom etmoqda... Qaytish uchun bosing",
              smallIcon: 'ic_stat_icon_config_sample',
              buttons: [
                { title: 'Tugatish', id: 1 }
              ],
              silent: true,
            });
          } catch (e) {
            console.error('Failed to start foreground service:', e);
          }
        }
      });

      newCallObject.on('left-meeting', () => {
        setIsInCall(false);
        setRemoteParticipant(null);
        setPartnerLeft(false);

        if (Capacitor.getPlatform() === 'android') {
          try {
            void ForegroundService.stopForegroundService();
          } catch {
            // ignore
          }
        }
      });

      newCallObject.on('participant-joined', (event: DailyEventObject) => {
        if (event?.participant && !event.participant.local) {
          setRemoteParticipant(event.participant);
          setPartnerLeft(false);
        }
      });

      newCallObject.on('participant-updated', (event: DailyEventObject) => {
        if (event?.participant && !event.participant.local) {
          setRemoteParticipant(event.participant);
          setPartnerLeft(false);
        }
      });

      newCallObject.on('participant-left', (event: DailyEventObject) => {
        if (event?.participant && !event.participant.local) {
          setRemoteParticipant(null);
          setPartnerLeft(true);
          toast.info("Suhbatdosh chiqib ketdi");
        }
      });

      // Handle network quality and reconnection
      newCallObject.on('network-quality-change', (event: DailyEventObject) => {
        const quality = (event as unknown as { quality?: string } | null)?.quality;
        if (quality === 'very-low') {
          toast.warning("Internet aloqasi yomon", { duration: 2000 });
        }
      });

      newCallObject.on('network-connection', (event: DailyEventObject) => {
        const evt = (event as unknown as { event?: string } | null)?.event;
        if (evt === 'interrupted') {
          toast.warning("Internet uzildi, qayta ulanmoqda...", { duration: 3000 });
        }
        if (evt === 'connected') {
          if (reconnectAttemptsRef.current > 0) {
            toast.success("Qayta ulandi!", { duration: 2000 });
          }
          reconnectAttemptsRef.current = 0;
        }
      });

      newCallObject.on('error', (event: DailyEventObject) => {
        console.error('Daily error:', event);
        const errorType = String(
          (event as unknown as { errorMsg?: unknown; error?: { type?: unknown } } | null)?.errorMsg ??
            (event as unknown as { error?: { type?: unknown } } | null)?.error?.type ??
            ''
        );
        
        // Camera/mic permission errors
        if (errorType.includes('not-allowed') || errorType.includes('NotAllowed')) {
          toast.error("Kamera yoki mikrofonga ruxsat bering");
          return;
        }
        
        // Device not found
        if (errorType.includes('not-found') || errorType.includes('NotFound')) {
          toast.error("Kamera yoki mikrofon topilmadi");
          // Continue call with available devices
          try {
            newCallObject.setLocalVideo(false);
            setCameraOn(false);
          } catch {
            // ignore video toggle error
          }
          return;
        }

        // Network/connection errors - try reconnect
        if (reconnectAttemptsRef.current < maxReconnectAttempts) {
          reconnectAttemptsRef.current++;
          toast.error(`Xatolik yuz berdi, qayta urinish... (${reconnectAttemptsRef.current}/${maxReconnectAttempts})`);
          return;
        }

        toast.error("Video qo'ng'iroqda xatolik yuz berdi");
      });

      // Camera access error handling
      newCallObject.on('camera-error', (event: DailyEventObject) => {
        console.error('Camera error:', event);
        const errType = String((event as unknown as { error?: { type?: unknown } } | null)?.error?.type ?? '');
        if (errType === 'cam-in-use') {
          toast.error("Kamera boshqa ilova tomonidan ishlatilmoqda");
        } else if (errType === 'not-found') {
          toast.error("Kamera topilmadi");
        } else if (errType === 'permissions') {
          toast.error("Kameraga ruxsat berilmagan");
        } else {
          toast.error("Kamera xatosi");
        }
        setCameraOn(false);
      });

      setCallObject(newCallObject);
      callObjectRef.current = newCallObject;

      await newCallObject.join({ url: roomUrl });
      
    } catch (error: unknown) {
      console.error('Error joining room:', error);
      const msg = String((error as { message?: unknown } | null)?.message ?? '');
      
      // Specific error messages
      if (msg.includes('permission')) {
        toast.error("Kamera va mikrofonga ruxsat bering");
      } else if (msg.includes('network') || msg.includes('fetch')) {
        toast.error("Internet aloqasi yo'q");
      } else {
        toast.error("Xonaga qo'shilishda xatolik");
      }
    }
  };

  const leaveCall = useCallback(async () => {
    try {
      if (callObject) {
        try {
          await callObject.leave();
        } catch {
          // ignore leave
        }
        try {
          callObject.destroy();
        } catch {
          // ignore destroy
        }
        setCallObject(null);
        callObjectRef.current = null;
      }
      
      try {
        if (Capacitor.getPlatform() === 'android') {
          await ForegroundService.stopForegroundService();
        }
      } catch (e) {
        // Ignore service stop error
      }

      if (currentCall) {
        try {
          await supabase.functions.invoke('end-call', {
            body: { 
              call_id: currentCall.id,
              room_name: currentCall.room_name 
            },
          });
        } catch (err) {
          console.error('Error ending call on server:', err);
        }

        // Save call history ONLY ONCE
        if (!callHistorySavedRef.current && user?.id) {
          callHistorySavedRef.current = true;
          try {
            const otherUserToSaveId = currentCall.caller_id === user.id 
              ? currentCall.receiver_id 
              : currentCall.caller_id;
            
            const { data: existing } = await supabase
              .from('conversations')
              .select('id')
              .or(`and(participant1_id.eq.${user.id},participant2_id.eq.${otherUserToSaveId}),and(participant1_id.eq.${otherUserToSaveId},participant2_id.eq.${user.id})`)
              .maybeSingle();

            let convId = existing?.id;
            if (!convId) {
              const { data: newConv } = await supabase
                .from('conversations')
                .insert({ participant1_id: user.id, participant2_id: otherUserToSaveId })
                .select('id')
                .single();
              convId = newConv?.id;
            }

            if (convId) {
              const startTime = new Date(currentCall.created_at);
              const endTime = new Date();
              const durationSec = Math.round((endTime.getTime() - startTime.getTime()) / 1000);
              const mins = Math.floor(durationSec / 60);
              const secs = durationSec % 60;
              const durationText = mins > 0 ? `${mins} daqiqa ${secs} soniya` : `${secs} soniya`;

              await supabase.from('messages').insert({
                conversation_id: convId,
                sender_id: user.id,
                content: `≡ƒô╣ Video qo'ng'iroq ΓÇö ${durationText}`,
                status: 'sent',
              });
            }
          } catch (historyErr) {
            console.error('Error saving call history:', historyErr);
          }
        }
      }

      setIsInCall(false);
      // Don't clear currentCall or lastRoomUrl immediately so we can show Rejoin UI
      setRemoteParticipant(null);
      setPartnerLeft(false);
      setCameraOn(true);
      setMicOn(true);
      
    } catch (error) {
      console.error('Error leaving call:', error);
    }
  }, [callObject, currentCall, user?.id]);

  const endCallPermanently = useCallback(() => {
    leaveCall();
    setCurrentCall(null);
    setLastRoomUrl(null);
  }, [leaveCall]);

  const toggleCamera = useCallback(async () => {
    if (!callObject) return;
    try {
      const newState = !cameraOn;
      await callObject.setLocalVideo(newState);
      setCameraOn(newState);
    } catch (err) {
      console.error('Toggle camera error:', err);
      toast.error("Kamerani almashtirish imkonsiz");
    }
  }, [callObject, cameraOn]);

  const toggleMic = useCallback(async () => {
    if (!callObject) return;
    try {
      const newState = !micOn;
      await callObject.setLocalAudio(newState);
      setMicOn(newState);
    } catch (err) {
      console.error('Toggle mic error:', err);
      toast.error("Mikrofonni almashtirish imkonsiz");
    }
  }, [callObject, micOn]);

  return {
    isInCall,
    wasInCall,
    partnerLeft,
    isCreatingRoom,
    incomingCall,
    currentCall,
    cameraOn,
    micOn,
    callObject,
    remoteParticipant,
    lastRoomUrl,
    startCall,
    answerCall,
    rejoinCall,
    declineCall,
    leaveCall,
    endCallPermanently,
    toggleCamera,
    toggleMic,
  };
};
